{
  "name": "Nextwaves RFID Scanner",
  "description": "A Web Bluetooth testing and debugging tool for the Nextwaves Scanner V3 RFID reader."
}

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export enum ScanMode {
  INTERACTIVE = 'INTERACTIVE',
  BATCH = 'BATCH'
}

export interface Tag {
  epc: string;
  timestamp: number;
  rssi?: number;
  count: number;
}

export interface Settings {
  power: number;
  frequency: string;
  rfParams: string;
}

export interface BleError {
  message: string;
  timestamp: number;
}

export type LogEntry = {
  type: 'info' | 'error' | 'rx' | 'tx';
  message: string;
  timestamp: number;
};

// Internal types for component props
export interface ControlsProps {
  status: ConnectionStatus;
  scanMode: ScanMode;
  isScanning: boolean;
  settings: Settings;
  onConnect: () => void;
  onDisconnect: () => void;
  onToggleMode: (mode: ScanMode) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  onUpdateSettings: (key: keyof Settings, value: string | number) => void;
  onWriteEpc: (oldEpc: string, newEpc: string) => void;
  writeLoading: boolean;
  selectedEpc: string;
}

export interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export interface BatchResultsProps {
  fileContent: string;
  transferProgress: number; // 0-100, -1 if idle
  isTransferring: boolean;
}

import { ConnectionStatus } from '../types';

const SERVICE_UUID = 0x00ff;
const CHAR_CMD_UUID = 0xff01;
const CHAR_FILE_REQ_UUID = 0xff02;
const CHAR_FILE_DATA_UUID = 0xff03;

type TagCallback = (tag: { epc: string }) => void;
type LogCallback = (msg: string, type: 'info' | 'error' | 'rx' | 'tx') => void;
type FileDataCallback = (data: ArrayBuffer) => void;

class BLEService {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private service: BluetoothRemoteGATTService | null = null;
  private charCmd: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileReq: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileData: BluetoothRemoteGATTCharacteristic | null = null;

  private onTagReceived: TagCallback | null = null;
  private onLog: LogCallback | null = null;
  private onFileData: FileDataCallback | null = null;

  constructor() {}

  setCallbacks(
    onTag: TagCallback,
    onLog: LogCallback,
    onFileData: FileDataCallback
  ) {
    this.onTagReceived = onTag;
    this.onLog = onLog;
    this.onFileData = onFileData;
  }

  async connect(): Promise<void> {
    if (!navigator.bluetooth) {
      throw new Error('Web Bluetooth is not supported in this browser.');
    }

    this.log('Requesting device...', 'info');

    try {
      this.device = await navigator.bluetooth.requestDevice({
        filters: [{ namePrefix: 'Nextwaves_Scanner_V3' }],
        optionalServices: [SERVICE_UUID],
      });

      this.device.addEventListener('gattserverdisconnected', this.handleDisconnect.bind(this));

      this.log(`Connecting to ${this.device.name}...`, 'info');
      this.server = await this.device.gatt!.connect();

      this.log('Getting Service...', 'info');
      this.service = await this.server.getPrimaryService(SERVICE_UUID);

      this.log('Getting Characteristics...', 'info');
      this.charCmd = await this.service.getCharacteristic(CHAR_CMD_UUID);
      this.charFileReq = await this.service.getCharacteristic(CHAR_FILE_REQ_UUID);
      this.charFileData = await this.service.getCharacteristic(CHAR_FILE_DATA_UUID);

      // Setup Notifications for Commands/Tags
      this.log('Starting Notifications...', 'info');
      await this.charCmd.startNotifications();
      this.charCmd.addEventListener('characteristicvaluechanged', this.handleCmdNotification.bind(this));

      // Setup Notifications for File Data
      await this.charFileData.startNotifications();
      this.charFileData.addEventListener('characteristicvaluechanged', this.handleFileNotification.bind(this));

      this.log('Connected and ready.', 'info');
    } catch (error: any) {
      this.log(`Connection failed: ${error.message}`, 'error');
      throw error;
    }
  }

  disconnect() {
    if (this.device && this.device.gatt?.connected) {
      this.device.gatt.disconnect();
    }
  }

  handleDisconnect() {
    this.log('Device disconnected.', 'error');
    this.device = null;
    this.server = null;
    this.service = null;
    this.charCmd = null;
    this.charFileReq = null;
    this.charFileData = null;
    // Note: The App component should handle state updates via a separate mechanism or error re-throw if needed, 
    // but here we just log.
  }

  private handleCmdNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    const decoder = new TextDecoder('utf-8');
    const value = decoder.decode(target.value);

    // Attempt to parse JSON
    try {
        const data = JSON.parse(value);
        if (data.cmd === 'live_tag' && data.epc) {
            if (this.onTagReceived) this.onTagReceived(data);
        } else {
            this.log(`RX: ${value}`, 'rx');
        }
    } catch (e) {
        // Not JSON or partial data
        this.log(`RX (Raw): ${value}`, 'rx');
    }
  }

  private handleFileNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    // Pass raw buffer to the handler in App to reconstruct the file
    if (this.onFileData) {
        this.onFileData(target.value.buffer);
    }
  }

  async sendCommand(command: object): Promise<void> {
    if (!this.charCmd) throw new Error('Not connected');
    const str = JSON.stringify(command);
    const encoder = new TextEncoder();
    this.log(`TX: ${str}`, 'tx');
    await this.charCmd.writeValue(encoder.encode(str));
  }

  async requestFileTransfer(): Promise<void> {
    if (!this.charFileReq) throw new Error('Not connected');
    const str = 'send_file';
    const encoder = new TextEncoder();
    this.log(`TX (FileReq): ${str}`, 'tx');
    await this.charFileReq.writeValue(encoder.encode(str));
  }

  private log(msg: string, type: 'info' | 'error' | 'rx' | 'tx') {
    if (this.onLog) this.onLog(msg, type);
    else console.log(`[${type.toUpperCase()}] ${msg}`);
  }
}

export const bleService = new BLEService();

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded-md font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed';

  const variants = {
    primary: 'bg-blue-600 text-white hover:bg-blue-700 focus:ring-blue-500',
    secondary: 'bg-slate-700 text-slate-100 hover:bg-slate-600 focus:ring-slate-500',
    danger: 'bg-red-600 text-white hover:bg-red-700 focus:ring-red-500',
    success: 'bg-emerald-600 text-white hover:bg-emerald-700 focus:ring-emerald-500',
    outline: 'border border-slate-600 text-slate-300 hover:bg-slate-800 focus:ring-slate-500 bg-transparent'
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-4 py-2 text-sm',
    lg: 'px-6 py-3 text-base'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

export const Input: React.FC<InputProps> = ({ label, error, className = '', ...props }) => {
  return (
    <div className="w-full">
      {label && <label className="block text-xs font-medium text-slate-400 mb-1">{label}</label>}
      <input
        className={`w-full bg-slate-800 border ${error ? 'border-red-500' : 'border-slate-700'} rounded-md px-3 py-2 text-sm text-slate-200 placeholder-slate-500 focus:outline-none focus:ring-1 focus:ring-blue-500 focus:border-blue-500 transition-colors ${className}`}
        {...props}
      />
      {error && <p className="mt-1 text-xs text-red-500">{error}</p>}
    </div>
  );
};

import React, { useState } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, Zap, Activity, ScanLine, FileText, Send } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings,
  onWriteEpc,
  writeLoading,
  selectedEpc
}) => {
  const [newEpc, setNewEpc] = useState('');
  const [oldEpcInput, setOldEpcInput] = useState('');

  // Sync internal oldEpc with selected prop when it changes
  React.useEffect(() => {
    if (selectedEpc) setOldEpcInput(selectedEpc);
  }, [selectedEpc]);

  const handleWrite = () => {
    onWriteEpc(oldEpcInput, newEpc);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  return (
    <div className="flex flex-col h-full bg-slate-900 border-r border-slate-800 p-4 overflow-y-auto w-full md:w-80 shrink-0 gap-6">

      {/* Header / Connection */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-blue-400 mb-2">
          <Radio className="w-6 h-6" />
          <h1 className="font-bold text-lg text-slate-100">Nextwaves V3</h1>
        </div>

        {isConnected ? (
          <Button variant="danger" fullWidth onClick={onDisconnect} disabled={isScanning}>
            <Bluetooth className="w-4 h-4 mr-2" />
            Disconnect
          </Button>
        ) : (
          <Button variant="primary" fullWidth onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING}>
            <Bluetooth className="w-4 h-4 mr-2" />
            {status === ConnectionStatus.CONNECTING ? 'Connecting...' : 'Connect Scanner'}
          </Button>
        )}

        <div className="flex items-center justify-between text-xs px-1">
          <span className="text-slate-500">Status</span>
          <span className={`font-medium ${
            status === ConnectionStatus.CONNECTED ? 'text-emerald-400' : 
            status === ConnectionStatus.ERROR ? 'text-red-400' : 'text-slate-400'
          }`}>
            {status}
          </span>
        </div>
      </div>

      <div className="h-px bg-slate-800" />

      {/* Scan Controls */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <ScanLine className="w-4 h-4" />
          <h2>Scanning</h2>
        </div>

        <div className="bg-slate-800 p-1 rounded-lg flex text-xs">
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.INTERACTIVE ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
            disabled={isScanning}
          >
            Interactive
          </button>
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.BATCH ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.BATCH)}
            disabled={isScanning}
          >
            Batch
          </button>
        </div>

        {isScanning ? (
          <Button variant="danger" fullWidth onClick={onStopScan} disabled={!isConnected}>
            Stop Scan
          </Button>
        ) : (
          <Button variant="success" fullWidth onClick={onStartScan} disabled={!isConnected}>
            Start Scan
          </Button>
        )}
      </div>

      <div className="h-px bg-slate-800" />

      {/* Settings */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <SettingsIcon className="w-4 h-4" />
          <h2>Settings</h2>
        </div>

        <div>
          <label className="flex justify-between text-xs text-slate-400 mb-2">
            <span>Tx Power</span>
            <span>{settings.power} dBm</span>
          </label>
          <input 
            type="range" 
            min="0" 
            max="33" 
            value={settings.power}
            onChange={(e) => onUpdateSettings('power', parseInt(e.target.value))}
            disabled={!isConnected || isScanning}
            className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
          />
        </div>

        <div className="space-y-2">
            <label className="text-xs text-slate-400">Region</label>
            <select 
              className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-md p-2 focus:ring-1 focus:ring-blue-500 focus:outline-none"
              value={settings.frequency}
              onChange={(e) => onUpdateSettings('frequency', e.target.value)}
              disabled={!isConnected || isScanning}
            >
              <option value="US">US (902-928 MHz)</option>
              <option value="EU">EU (865-868 MHz)</option>
              <option value="CN">CN (920-925 MHz)</option>
              <option value="VN">VN (918-923 MHz)</option>
            </select>
        </div>

        <Input 
          label="RF Params (speed,qv,sess,targ)"
          value={settings.rfParams}
          onChange={(e) => onUpdateSettings('rfParams', e.target.value)}
          placeholder="e.g. 1,4,1,0"
          disabled={!isConnected || isScanning}
        />
      </div>

      <div className="h-px bg-slate-800" />

      {/* Write EPC */}
      <div className="space-y-4 pb-4">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <FileText className="w-4 h-4" />
          <h2>Write EPC</h2>
        </div>

        <div className="space-y-3">
          <Input 
            label="Current EPC" 
            placeholder="Select from log..." 
            value={oldEpcInput}
            onChange={(e) => setOldEpcInput(e.target.value)}
            disabled={!isConnected || isScanning}
          />
          <Input 
            label="New EPC (Hex)" 
            placeholder="e.g. E200..." 
            value={newEpc}
            onChange={(e) => setNewEpc(e.target.value)}
            disabled={!isConnected || isScanning}
          />
          <Button 
            variant="secondary" 
            fullWidth 
            size="sm"
            onClick={handleWrite}
            disabled={!isConnected || isScanning || writeLoading}
          >
            {writeLoading ? 'Writing...' : 'Write Tag'}
          </Button>
        </div>
      </div>

    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Tag, LogEntry } from '../types';
import { Trash2, Terminal } from 'lucide-react';

interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export const InteractiveLog: React.FC<InteractiveLogProps> = ({ tags, onClear, onSelectEpc, logs }) => {
  const logEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logs
  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  return (
    <div className="flex-1 flex flex-col h-full bg-slate-950 border-r border-slate-800 min-w-[300px]">

      {/* Top Panel: Live Tags */}
      <div className="flex-1 flex flex-col min-h-0">
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900/50">
          <div className="flex items-center gap-2">
            <span className="font-semibold text-slate-200">Live Tags</span>
            <span className="bg-blue-900/50 text-blue-400 text-xs px-2 py-0.5 rounded-full border border-blue-800">
              {tags.length}
            </span>
          </div>
          <button 
            onClick={onClear}
            className="text-slate-400 hover:text-red-400 transition-colors p-1"
            title="Clear List"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-1 custom-scrollbar">
          {tags.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 text-sm">
              <p>No tags scanned yet.</p>
              <p className="text-xs mt-1 opacity-70">Start a scan to see data.</p>
            </div>
          ) : (
            tags.map((tag, idx) => (
              <div 
                key={`${tag.epc}-${idx}`}
                onClick={() => onSelectEpc(tag.epc)}
                className="group flex items-center justify-between p-3 rounded-md bg-slate-900 border border-slate-800 hover:border-blue-500/50 cursor-pointer transition-all hover:bg-slate-800"
              >
                <div className="flex flex-col">
                  <span className="font-mono text-emerald-400 font-medium tracking-wide text-sm">{tag.epc}</span>
                  <span className="text-xs text-slate-500">
                    {new Date(tag.timestamp).toLocaleTimeString()}
                    {tag.rssi && <span className="ml-2">RSSI: {tag.rssi}</span>}
                  </span>
                </div>
                <div className="flex items-center gap-3">
                    <span className="text-xs font-mono bg-slate-800 text-slate-400 px-2 py-1 rounded">
                        x{tag.count}
                    </span>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Bottom Panel: System Logs */}
      <div className="h-1/3 border-t border-slate-800 flex flex-col bg-black">
        <div className="flex items-center gap-2 px-4 py-2 bg-slate-900 border-b border-slate-800 text-xs font-mono text-slate-400">
          <Terminal className="w-3 h-3" />
          <span>System Log</span>
        </div>
        <div className="flex-1 overflow-y-auto p-2 font-mono text-xs space-y-1">
          {logs.map((log, i) => (
            <div key={i} className="flex gap-2">
              <span className="text-slate-600 shrink-0 select-none">
                {new Date(log.timestamp).toLocaleTimeString([], {hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit'})}
              </span>
              <span className={`break-all ${
                log.type === 'error' ? 'text-red-400' :
                log.type === 'tx' ? 'text-cyan-600' :
                log.type === 'rx' ? 'text-emerald-600' :
                'text-slate-300'
              }`}>
                {log.type === 'tx' && '> '}
                {log.type === 'rx' && '< '}
                {log.message}
              </span>
            </div>
          ))}
          <div ref={logEndRef} />
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Download, FileDown, RefreshCw } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring 
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="w-full md:w-1/3 flex flex-col h-full bg-slate-950 p-4 gap-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <FileDown className="w-5 h-5 text-purple-400" />
          <h2>Batch Results</h2>
        </div>
        {fileContent && !isTransferring && (
          <button 
            onClick={handleDownload}
            className="flex items-center gap-1 text-xs text-blue-400 hover:text-blue-300 transition-colors"
          >
            <Download className="w-3 h-3" />
            Save .txt
          </button>
        )}
      </div>

      <div className="flex-1 bg-slate-900 rounded-lg border border-slate-800 overflow-hidden relative flex flex-col">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-10 p-8 text-center">
            <RefreshCw className="w-10 h-10 text-blue-500 animate-spin mb-4" />
            <h3 className="text-slate-200 font-medium">Transferring File...</h3>
            {transferProgress >= 0 && (
                <p className="text-slate-400 text-sm mt-2">{transferProgress}%</p>
            )}
            <p className="text-slate-500 text-xs mt-4">Please wait while data is retrieved from the scanner.</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-600 p-8 text-center">
            <p className="mb-2">No batch data available.</p>
            <p className="text-xs max-w-xs">Run a Batch Scan and stop it to automatically trigger file transfer.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar">
            <pre className="font-mono text-xs text-slate-300 whitespace-pre-wrap break-all leading-relaxed">
              {fileContent}
            </pre>
          </div>
        )}
      </div>

      <div className="text-xs text-slate-500 text-center">
        Batch data is transferred over characteristic 0xFF03
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry
} from './types';

function App() {
  // --- State ---
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0'
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [fileBuffer, setFileBuffer] = useState<number[]>([]); // Storing bytes

  // Write EPC State
  const [writeLoading, setWriteLoading] = useState(false);

  // --- Refs for Performance ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>();

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Callbacks ---

  const handleTag = useCallback((data: any) => {
    const now = Date.now();
    const newTag: Tag = {
      epc: data.epc,
      timestamp: now,
      rssi: data.rssi,
      count: 1
    };

    // Update Buffer
    const existing = tagBufferRef.current.get(newTag.epc);
    if (existing) {
        newTag.count = existing.count + 1;
    }
    tagBufferRef.current.set(newTag.epc, newTag);
  }, []);

  const handleFileData = useCallback((buffer: ArrayBuffer) => {
    const view = new DataView(buffer);
    const header = view.getUint16(0, true); // Assuming Little Endian

    // 0xFFFF = START
    if (header === 0xFFFF) {
        // Start of file
        setFileBuffer([]); 
        setIsTransferring(true);
        addLog('File Transfer Started...', 'info');
    } 
    // 0xFFFE = EOF
    else if (header === 0xFFFE) {
        setIsTransferring(false);
        addLog('File Transfer Complete.', 'success');

        // Reconstruct File
        // Since setFileBuffer is async, we rely on the callback approach or ref if this was complex.
        // However, React state updates in event handlers are batched. 
        // We need the current buffer to finalize. 
        // Better to use a Ref for file buffer to avoid closure stale state issues.
    } 
    // DATA Packets
    else {
        // Append data (skip first 2 bytes which is header)
        const dataBytes = new Uint8Array(buffer.slice(2));
        setFileBuffer(prev => {
            const next = [...prev, ...Array.from(dataBytes)];
            // Check if EOF was actually triggered in logic outside state? 
            // Actually, we need to handle the EOF state logic here carefully.
            return next;
        });
    }
  }, [addLog]);

  // Use a Ref for file building to ensure sync integrity during rapid packets
  const rawFileBytesRef = useRef<number[]>([]);

  const handleFileDataRef = useCallback((buffer: ArrayBuffer) => {
    const view = new DataView(buffer);
    const header = view.getUint16(0, true);

    if (header === 0xFFFF) {
        rawFileBytesRef.current = [];
        setIsTransferring(true);
        addLog('File transfer started', 'info');
    } else if (header === 0xFFFE) {
        setIsTransferring(false);
        addLog(`File transfer done. ${rawFileBytesRef.current.length} bytes received.`, 'info');

        // Convert to string
        const bytes = new Uint8Array(rawFileBytesRef.current);
        const decoder = new TextDecoder('utf-8');
        const text = decoder.decode(bytes);
        setFileContent(text);
    } else {
        const chunk = new Uint8Array(buffer.slice(2));
        for(let i=0; i<chunk.length; i++) {
            rawFileBytesRef.current.push(chunk[i]);
        }
    }
  }, [addLog]);

  // --- Effects ---

  // Initialize BLE listeners
  useEffect(() => {
    bleService.setCallbacks(
        handleTag,
        (msg, type) => addLog(msg, type),
        handleFileDataRef
    );
  }, [handleTag, addLog, handleFileDataRef]);

  // Render Loop for Tags (throttled to 200ms)
  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 200 && tagBufferRef.current.size > 0) {
        // Convert Map values to array, sort by timestamp desc, take top 500
        const allTags = Array.from(tagBufferRef.current.values());
        // Sort: newest first
        allTags.sort((a, b) => b.timestamp - a.timestamp);
        const displayTags = allTags.slice(0, 500);

        setTags(displayTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };

    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);


  // --- Actions ---

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);
    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'S' });
      } else {
        // Batch
        setFileContent(''); // Clear previous batch results
        await bleService.sendCommand({ cmd: 'SB' });
      }
      setIsScanning(true);
      addLog(`Started ${scanMode} Scan`, 'info');
    } catch (e: any) {
      addLog(`Scan Start Failed: ${e.message}`, 'error');
    }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'X' });
      } else {
        // Batch
        await bleService.sendCommand({ cmd: 'XB' });
        // Auto trigger file transfer
        setTimeout(async () => {
             addLog('Requesting File Transfer...', 'tx');
             await bleService.requestFileTransfer();
        }, 500);
      }
      setIsScanning(false);
      addLog('Stopped Scan', 'info');
    } catch (e: any) {
      addLog(`Scan Stop Failed: ${e.message}`, 'error');
    }
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number) => {
    // Optimistic update
    setSettings(prev => ({ ...prev, [key]: value }));

    if (status !== ConnectionStatus.CONNECTED) return;

    try {
        let cmd = {};
        if (key === 'power') cmd = { cmd: 'SP', val: value };
        if (key === 'frequency') cmd = { cmd: 'SF', val: value };
        if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };

        await bleService.sendCommand(cmd);
    } catch(e: any) {
        addLog(`Settings Update Failed: ${e.message}`, 'error');
    }
  };

  const handleWriteEpc = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc) {
        addLog('Old and New EPC required', 'error');
        return;
    }

    // Validation
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
        addLog('New EPC must be Hex characters only', 'error');
        return;
    }
    if (newEpc.length > 32) {
        addLog('New EPC length must be <= 32 chars', 'error');
        return;
    }
    if (newEpc.length % 4 !== 0) {
        addLog('New EPC length must be multiple of 4', 'error');
        return;
    }

    setWriteLoading(true);
    try {
        await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
        addLog(`Write Command Sent: ${oldEpc} -> ${newEpc}`, 'info');
    } catch (e: any) {
        addLog(`Write Failed: ${e.message}`, 'error');
    } finally {
        setWriteLoading(false);
    }
  };

  const handleClearLog = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  return (
    <div className="flex flex-col md:flex-row h-full w-full bg-slate-950 text-slate-200">

      {/* 1. Left Controls */}
      <Controls 
        status={status}
        scanMode={scanMode}
        isScanning={isScanning}
        settings={settings}
        onConnect={handleConnect}
        onDisconnect={handleDisconnect}
        onToggleMode={setScanMode}
        onStartScan={handleStartScan}
        onStopScan={handleStopScan}
        onUpdateSettings={handleUpdateSettings}
        onWriteEpc={handleWriteEpc}
        writeLoading={writeLoading}
        selectedEpc={selectedEpc}
      />

      {/* 2. Middle Interactive Log */}
      <InteractiveLog 
        tags={tags}
        onClear={handleClearLog}
        onSelectEpc={setSelectedEpc}
        logs={logs}
      />

      {/* 3. Right Batch Results */}
      <BatchResults 
        fileContent={fileContent}
        isTransferring={isTransferring}
        transferProgress={-1} // Can implement precise progress if total size is known from header
      />

    </div>
  );
}

