interface ExtendedControlsProps extends ControlsProps {
  onOpenWriteModal: () => void;
}

export const Controls: React.FC<ExtendedControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings,
  onOpenWriteModal
}) => {

  // Local state for settings to allow "Select then Apply" pattern
  const [localSettings, setLocalSettings] = useState<Settings>(settings);
  const [isDirty, setIsDirty] = useState(false);

  // Sync local state when props change (e.g. after 'Get Settings' returns)
  useEffect(() => {
    setLocalSettings(settings);
    setIsDirty(false); // Reset dirty flag when backend updates us
  }, [settings]);

  const handleSettingChange = (key: keyof Settings, value: string | number) => {
    setLocalSettings(prev => ({ ...prev, [key]: value }));
    setIsDirty(true);
  };

  const applySettings = () => {
    // Send all updates
    // In a real scenario, we might want to check what changed, 
    // but sending all ensures synchronization.
    onUpdateSettings('power', localSettings.power);
    onUpdateSettings('frequency', localSettings.frequency);
    onUpdateSettings('rfParams', localSettings.rfParams);
    setIsDirty(false);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  return (
    <div className="flex flex-col h-full bg-slate-900 p-4 overflow-y-auto w-full gap-6">

