import { ConnectionStatus } from '../types';

// --- Web Bluetooth Type Definitions ---
interface BluetoothDevice extends EventTarget {
  id: string;
  name?: string;
  gatt?: BluetoothRemoteGATTServer;
}

interface BluetoothRemoteGATTServer {
  device: BluetoothDevice;
  connected: boolean;
  connect(): Promise<BluetoothRemoteGATTServer>;
  disconnect(): void;
  getPrimaryService(service: string | number): Promise<BluetoothRemoteGATTService>;
}

interface BluetoothRemoteGATTService {
  getCharacteristic(characteristic: string | number): Promise<BluetoothRemoteGATTCharacteristic>;
}

interface BluetoothRemoteGATTCharacteristic extends EventTarget {
  value?: DataView;
  writeValue(value: BufferSource): Promise<void>;
  startNotifications(): Promise<BluetoothRemoteGATTCharacteristic>;
}
// --------------------------------------

const SERVICE_UUID = 0x00ff;
const CHAR_CMD_UUID = 0xff01;
const CHAR_FILE_REQ_UUID = 0xff02;
const CHAR_FILE_DATA_UUID = 0xff03;

// Callbacks
type DataCallback = (data: any) => void;
type LogCallback = (msg: string, type: 'info' | 'error' | 'rx' | 'tx') => void;
// New File Transfer Callback Signature
type FileTransferEvent = 'start' | 'progress' | 'complete' | 'error';
type FileTransferCallback = (event: FileTransferEvent, data?: any) => void;

class BLEService {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private service: BluetoothRemoteGATTService | null = null;
  private charCmd: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileReq: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileData: BluetoothRemoteGATTCharacteristic | null = null;

  private onDataReceived: DataCallback | null = null;
  private onLog: LogCallback | null = null;
  private onFileTransfer: FileTransferCallback | null = null;

  // File Transfer State
  private isFileTransferring = false;
  private fileBuffer: Uint8Array[] = [];
  private fileTotalSize = 0;
  private fileReceivedSize = 0;

  constructor() {}

  setCallbacks(
    onData: DataCallback,
    onLog: LogCallback,
    onFileTransfer: FileTransferCallback
  ) {
    this.onDataReceived = onData;
    this.onLog = onLog;
    this.onFileTransfer = onFileTransfer;
  }

  async connect(): Promise<void> {
    const nav = navigator as any;
    if (!nav.bluetooth) {
      throw new Error('Web Bluetooth is not supported in this browser.');
    }

    this.log('Requesting device...', 'info');

    try {
      this.device = await nav.bluetooth.requestDevice({
        filters: [{ namePrefix: 'Nextwaves_Scanner_V3' }],
        optionalServices: [SERVICE_UUID],
      });

      this.device!.addEventListener('gattserverdisconnected', this.handleDisconnect.bind(this));

      this.log(`Connecting to ${this.device!.name}...`, 'info');
      this.server = await this.device!.gatt!.connect();

      this.log('Getting Service...', 'info');
      this.service = await this.server.getPrimaryService(SERVICE_UUID);

      this.log('Getting Characteristics...', 'info');
      this.charCmd = await this.service.getCharacteristic(CHAR_CMD_UUID);
      this.charFileReq = await this.service.getCharacteristic(CHAR_FILE_REQ_UUID);
      this.charFileData = await this.service.getCharacteristic(CHAR_FILE_DATA_UUID);

      // Setup Notifications for Commands/Tags
      this.log('Starting Notifications...', 'info');
      await this.charCmd.startNotifications();
      this.charCmd.addEventListener('characteristicvaluechanged', this.handleCmdNotification.bind(this));

      // Setup Notifications for File Data
      await this.charFileData.startNotifications();
      this.charFileData.addEventListener('characteristicvaluechanged', this.handleFileNotification.bind(this));

      this.log('Connected and ready.', 'info');
    } catch (error: any) {
      this.log(`Connection failed: ${error.message}`, 'error');
      throw error;
    }
  }

  disconnect() {
    if (this.device && this.device.gatt?.connected) {
      this.device.gatt.disconnect();
    }
  }

  handleDisconnect() {
    this.log('Device disconnected.', 'error');
    this.resetFileState();
    this.device = null;
    this.server = null;
    this.service = null;
    this.charCmd = null;
    this.charFileReq = null;
    this.charFileData = null;
  }

  private resetFileState() {
    this.isFileTransferring = false;
    this.fileBuffer = [];
    this.fileTotalSize = 0;
    this.fileReceivedSize = 0;
  }

  private handleCmdNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    const decoder = new TextDecoder('utf-8');
    const value = decoder.decode(target.value);

    // Attempt to parse JSON
    try {
        const data = JSON.parse(value);

        // Pass all parsed JSON to the App to handle (Tags, Settings response, etc)
        if (this.onDataReceived) {
            this.onDataReceived(data);
        }

        // Optional: Log non-tag high-level commands as RX
        if (data.cmd !== 'live_tag') {
             this.log(`RX: ${value}`, 'rx');
        }

    } catch (e) {
        // Not JSON or partial data
        this.log(`RX (Raw): ${value}`, 'rx');
    }
  }

  private handleFileNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value || target.value.byteLength < 2) return;

    const view = new DataView(target.value.buffer);
    // CRITICAL: Protocol specifies Big-Endian for headers
    const header = view.getUint16(0, false); 

    if (header === 0xFFFF) {
        // --- START PACKET ---
        this.resetFileState();
        this.isFileTransferring = true;

        // Payload is JSON Metadata
        const payload = new Uint8Array(target.value.buffer.slice(2));
        const decoder = new TextDecoder('utf-8');
        try {
            const jsonStr = decoder.decode(payload);
            const metadata = JSON.parse(jsonStr);
            this.fileTotalSize = metadata.size || 0;

            if (this.onFileTransfer) {
                this.onFileTransfer('start', { total: this.fileTotalSize });
            }
        } catch (e) {
            this.log('Failed to parse START packet', 'error');
            this.isFileTransferring = false;
            if (this.onFileTransfer) this.onFileTransfer('error', 'Invalid START packet');
        }

    } else if (header === 0xFFFE) {
        // --- EOF PACKET ---
        if (!this.isFileTransferring) return;
        this.isFileTransferring = false;

        // Assembly
        const totalLen = this.fileBuffer.reduce((acc, chunk) => acc + chunk.length, 0);
        const fullFile = new Uint8Array(totalLen);
        let offset = 0;
        for (const chunk of this.fileBuffer) {
            fullFile.set(chunk, offset);
            offset += chunk.length;
        }

        // Decode
        const decoder = new TextDecoder('utf-8');
        const text = decoder.decode(fullFile);

        if (this.onFileTransfer) {
            this.onFileTransfer('complete', text);
        }

    } else {
        // --- DATA PACKET ---
        // Header is Sequence Number (0x0000...) - we ignore seq for now and just append
        if (!this.isFileTransferring) return;

        const chunk = new Uint8Array(target.value.buffer.slice(2));
        this.fileBuffer.push(chunk);
        this.fileReceivedSize += chunk.length;

        // Progress
        if (this.onFileTransfer && this.fileTotalSize > 0) {
            const percent = Math.min(100, Math.round((this.fileReceivedSize / this.fileTotalSize) * 100));
            this.onFileTransfer('progress', percent);
        }
    }
  }

  async sendCommand(command: object): Promise<void> {
    if (!this.charCmd) throw new Error('Not connected');
    const str = JSON.stringify(command);
    const encoder = new TextEncoder();
    this.log(`TX: ${str}`, 'tx');
    await this.charCmd.writeValue(encoder.encode(str));
  }

  // Get Settings Command
  async getSettings(): Promise<void> {
    // Sends { cmd: 'GS' } -> Get Settings
    await this.sendCommand({ cmd: 'GS' });
  }

  async requestFileTransfer(): Promise<void> {
    if (!this.charFileReq) throw new Error('Not connected');

    if (this.isFileTransferring) {
        this.log('File transfer already in progress', 'error');
        return;
    }

    const str = 'send_file';
    const encoder = new TextEncoder();
    this.log(`TX (FileReq): ${str}`, 'tx');
    await this.charFileReq.writeValue(encoder.encode(str));
  }

  private log(msg: string, type: 'info' | 'error' | 'rx' | 'tx') {
    if (this.onLog) this.onLog(msg, type);
    else console.log(`[${type.toUpperCase()}] ${msg}`);
  }
}

export const bleService = new BLEService();

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutDashboard, ScrollText, FileOutput, Radio, Bluetooth } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriteEpcModal } from './components/WriteEpcModal';
import { Button } from './components/ui/Button';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry
} from './types';

function App() {
  // --- State ---
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Modal State
  const [isWriteModalOpen, setIsWriteModalOpen] = useState(false);

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0'
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeLoading, setWriteLoading] = useState(false);

  // --- Refs for Performance ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Callbacks ---

  const handleDataReceived = useCallback((data: any) => {
    // 1. Handle Tag Data
    if (data.cmd === 'live_tag' && data.epc) {
        const now = Date.now();
        const newTag: Tag = {
          epc: data.epc,
          timestamp: now,
          rssi: data.rssi,
          count: 1
        };

        // Update Buffer
        const existing = tagBufferRef.current.get(newTag.epc);
        if (existing) {
            newTag.count = existing.count + 1;
        }
        tagBufferRef.current.set(newTag.epc, newTag);
        return;
    }

    // 2. Handle Settings Response (Get Settings)
    // Assuming structure: { cmd: 'GS', power: 30, frequency: 'US', ... }
    if (data.cmd === 'GS' || data.cmd === 'get_settings') {
        addLog('Settings Received from Device', 'rx');
        setSettings(prev => ({
            ...prev,
            power: data.power ?? prev.power,
            frequency: data.frequency ?? prev.frequency,
            rfParams: data.rfParams ?? prev.rfParams
        }));
        return;
    }
  }, [addLog]);

  // Handle File Transfer Events
  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') {
        setIsTransferring(true);
        setTransferProgress(0);
        setFileContent('');
        const sizeKB = (data?.total / 1024).toFixed(1);
        addLog(`File transfer started (${sizeKB} KB)...`, 'info');
    } else if (event === 'progress') {
        setTransferProgress(data); // data is percentage
    } else if (event === 'complete') {
        setIsTransferring(false);
        setTransferProgress(100);
        setFileContent(data); // data is file string
        addLog('File transfer completed successfully.', 'info');
    } else if (event === 'error') {
        setIsTransferring(false);
        setTransferProgress(-1);
        addLog(`File transfer error: ${data}`, 'error');
    }
  }, [addLog]);

  // --- Effects ---

  // Initialize BLE listeners
  useEffect(() => {
    bleService.setCallbacks(
        handleDataReceived,
        (msg, type) => addLog(msg, type),
        handleFileEvent
    );
  }, [handleDataReceived, addLog, handleFileEvent]);

  // Render Loop for Tags (throttled to 200ms)
  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 200 && tagBufferRef.current.size > 0) {
        // Convert Map values to array, sort by timestamp desc, take top 500
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        // Sort: newest first
        allTags.sort((a, b) => b.timestamp - a.timestamp);
        const displayTags = allTags.slice(0, 500);

        setTags(displayTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };

    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);


  // --- Actions ---

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);

      // Auto-fetch settings after connection
      setTimeout(async () => {
         addLog('Fetching current settings...', 'tx');
         try {
            await bleService.getSettings();
         } catch(e) {
            addLog('Failed to fetch settings', 'error');
         }
      }, 500);

    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'S' });
      } else {
        // Batch
        setFileContent(''); // Clear previous batch results
        await bleService.sendCommand({ cmd: 'SB' });
      }
      setIsScanning(true);
      addLog(`Started ${scanMode} Scan`, 'info');
    } catch (e: any) {
      addLog(`Scan Start Failed: ${e.message}`, 'error');
    }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'X' });
      } else {
        // Batch
        await bleService.sendCommand({ cmd: 'XB' });
        // Auto trigger file transfer
        setTimeout(async () => {
             addLog('Requesting File Transfer...', 'tx');
             await bleService.requestFileTransfer();
        }, 500);
      }
      setIsScanning(false);
      addLog('Stopped Scan', 'info');
    } catch (e: any) {
      addLog(`Scan Stop Failed: ${e.message}`, 'error');
    }
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number) => {
    // Optimistic update for App state, but UI in Controls will wait for confirm
    setSettings(prev => ({ ...prev, [key]: value }));

    if (status !== ConnectionStatus.CONNECTED) return;

    try {
        let cmd = {};
        if (key === 'power') cmd = { cmd: 'SP', val: value };
        if (key === 'frequency') cmd = { cmd: 'SF', val: value };
        if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };

        await bleService.sendCommand(cmd);
        addLog(`Settings Set: ${key} = ${value}`, 'info');
    } catch(e: any) {
        addLog(`Settings Update Failed: ${e.message}`, 'error');
    }
  };

  const handleWriteEpc = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc) {
        addLog('Old and New EPC required', 'error');
        return;
    }

    // Validation
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
        addLog('New EPC must be Hex characters only', 'error');
        return;
    }
    if (newEpc.length > 32) {
        addLog('New EPC length must be <= 32 chars', 'error');
        return;
    }
    if (newEpc.length % 4 !== 0) {
        addLog('New EPC length must be multiple of 4', 'error');
        return;
    }

    setWriteLoading(true);
    try {
        await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
        addLog(`Write Command Sent: ${oldEpc} -> ${newEpc}`, 'info');
        // Close modal on success if needed, or keep open for multiple writes
    } catch (e: any) {
        addLog(`Write Failed: ${e.message}`, 'error');
    } finally {
        setWriteLoading(false);
    }
  };

  const handleClearLog = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  return (
    // changed from h-screen h-[100dvh] to fixed inset-0 to reliably lock to viewport on Android
    <div className="fixed inset-0 flex flex-col bg-slate-950 text-slate-200 overflow-hidden">

      {/* Write EPC Modal */}
      <WriteEpcModal 
        isOpen={isWriteModalOpen}
        onClose={() => setIsWriteModalOpen(false)}
        onWrite={handleWriteEpc}
        isLoading={writeLoading}
        selectedEpc={selectedEpc}
      />

      {/* --- Global Mobile/Tablet Header (< lg) --- */}
      <div className="lg:hidden flex items-center justify-between p-3 bg-slate-900 border-b border-slate-800 shrink-0 z-20">
        <div className="flex items-center gap-2 text-blue-400">
          <Radio className="w-5 h-5" />
          <h1 className="font-bold text-base text-slate-100">Nextwaves V3</h1>
        </div>

        <div className="flex items-center gap-3">
          {/* Status Dot */}
          <div className={`w-2.5 h-2.5 rounded-full ${
            status === ConnectionStatus.CONNECTED ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 
            status === ConnectionStatus.ERROR ? 'bg-red-500' : 
            status === ConnectionStatus.CONNECTING ? 'bg-yellow-500 animate-pulse' : 'bg-slate-600'
          }`} title={status} />

          {isConnected ? (
             <Button variant="danger" size="sm" onClick={handleDisconnect} disabled={isScanning}>
               <Bluetooth className="w-3 h-3 mr-1" />
               Disconnect
             </Button>
          ) : (
             <Button variant="primary" size="sm" onClick={handleConnect} disabled={status === ConnectionStatus.CONNECTING}>
               <Bluetooth className="w-3 h-3 mr-1" />
               {status === ConnectionStatus.CONNECTING ? '...' : 'Connect'}
             </Button>
          )}
        </div>
      </div>

      {/* --- Main Content Area --- */}
      <div className="flex-1 flex flex-col lg:flex-row overflow-hidden relative">

        {/* 1. Controls Wrapper - Fixed 80 (320px) on Desktop */}
        <div className={`
          ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
          lg:flex flex-col h-full w-full lg:w-80 shrink-0 z-10 border-b lg:border-b-0 lg:border-r border-slate-800
        `}>
          <Controls 
            status={status}
            scanMode={scanMode}
            isScanning={isScanning}
            settings={settings}
            onConnect={handleConnect}
            onDisconnect={handleDisconnect}
            onToggleMode={setScanMode}
            onStartScan={handleStartScan}
            onStopScan={handleStopScan}
            onUpdateSettings={handleUpdateSettings}
            onWriteEpc={handleWriteEpc}
            writeLoading={writeLoading}
            selectedEpc={selectedEpc}
            onOpenWriteModal={() => setIsWriteModalOpen(true)}
          />
        </div>

        {/* 2. Middle Interactive Log Wrapper - Flexible */}
        <div className={`
          ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
          lg:flex flex-col flex-1 h-full min-w-0
        `}>
          <InteractiveLog 
            tags={tags}
            onClear={handleClearLog}
            onSelectEpc={setSelectedEpc}
            logs={logs}
          />
        </div>

        {/* 3. Right Batch Results Wrapper - Fixed 80 (320px) on Desktop */}
        <div className={`
          ${mobileTab === 'results' ? 'flex' : 'hidden'} 
          lg:flex flex-col h-full w-full lg:w-80 shrink-0 border-t lg:border-t-0 lg:border-l border-slate-800
        `}>
          <BatchResults 
            fileContent={fileContent}
            isTransferring={isTransferring}
            transferProgress={transferProgress} 
          />
        </div>

      </div>

      {/* --- Mobile Tab Navigation (< lg) --- */}
      <div className="lg:hidden flex items-center justify-around bg-slate-900 border-t border-slate-800 h-16 shrink-0 z-50 safe-area-pb">
        <button 
          onClick={() => setMobileTab('controls')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'controls' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <LayoutDashboard size={20} />
          <span className="text-[10px] font-medium">Controls</span>
        </button>

        <button 
          onClick={() => setMobileTab('logs')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'logs' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <div className="relative">
            <ScrollText size={20} />
            {tags.length > 0 && <span className="absolute -top-1 -right-1 w-2 h-2 bg-emerald-500 rounded-full" />}
          </div>
          <span className="text-[10px] font-medium">Logs</span>
        </button>

        <button 
          onClick={() => setMobileTab('results')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'results' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <FileOutput size={20} />
          <span className="text-[10px] font-medium">Batch</span>
        </button>
      </div>

    </div>
  );
}

export default App;

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export enum ScanMode {
  INTERACTIVE = 'INTERACTIVE',
  BATCH = 'BATCH'
}

export interface Tag {
  epc: string;
  timestamp: number;
  rssi?: number;
  count: number;
}

export interface Settings {
  power: number;
  frequency: string;
  rfParams: string; // "speed,qv,session,target"
  buzzer: boolean;
  deviceInfo: string;
}

export interface BleError {
  message: string;
  timestamp: number;
}

export type LogEntry = {
  type: 'info' | 'error' | 'rx' | 'tx';
  message: string;
  timestamp: number;
};

// Internal types for component props
export interface ControlsProps {
  status: ConnectionStatus;
  scanMode: ScanMode;
  isScanning: boolean;
  settings: Settings;
  onConnect: () => void;
  onDisconnect: () => void;
  onToggleMode: (mode: ScanMode) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  onUpdateSettings: (key: keyof Settings, value: string | number | boolean) => void;
  onWriteEpc: (oldEpc: string, newEpc: string) => void;
  writeLoading: boolean;
  selectedEpc: string;
  onOpenWriteModal: () => void;
}

export interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export interface BatchResultsProps {
  fileContent: string;
  transferProgress: number; // 0-100, -1 if idle
  isTransferring: boolean;
}

import { ConnectionStatus } from '../types';

// --- Web Bluetooth Type Definitions ---
interface BluetoothDevice extends EventTarget {
  id: string;
  name?: string;
  gatt?: BluetoothRemoteGATTServer;
}

interface BluetoothRemoteGATTServer {
  device: BluetoothDevice;
  connected: boolean;
  connect(): Promise<BluetoothRemoteGATTServer>;
  disconnect(): void;
  getPrimaryService(service: string | number): Promise<BluetoothRemoteGATTService>;
}

interface BluetoothRemoteGATTService {
  getCharacteristic(characteristic: string | number): Promise<BluetoothRemoteGATTCharacteristic>;
}

interface BluetoothRemoteGATTCharacteristic extends EventTarget {
  value?: DataView;
  writeValue(value: BufferSource): Promise<void>;
  startNotifications(): Promise<BluetoothRemoteGATTCharacteristic>;
}
// --------------------------------------

const SERVICE_UUID = 0x00ff;
const CHAR_CMD_UUID = 0xff01;
const CHAR_FILE_REQ_UUID = 0xff02;
const CHAR_FILE_DATA_UUID = 0xff03;

// Callbacks
type DataCallback = (data: any) => void;
type LogCallback = (msg: string, type: 'info' | 'error' | 'rx' | 'tx') => void;
type FileTransferEvent = 'start' | 'progress' | 'complete' | 'error';
type FileTransferCallback = (event: FileTransferEvent, data?: any) => void;

class BLEService {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private service: BluetoothRemoteGATTService | null = null;
  private charCmd: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileReq: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileData: BluetoothRemoteGATTCharacteristic | null = null;

  private onDataReceived: DataCallback | null = null;
  private onLog: LogCallback | null = null;
  private onFileTransfer: FileTransferCallback | null = null;

  // File Transfer State
  private isFileTransferring = false;
  private fileBuffer: Uint8Array[] = [];
  private fileTotalSize = 0;
  private fileReceivedSize = 0;

  constructor() {}

  setCallbacks(
    onData: DataCallback,
    onLog: LogCallback,
    onFileTransfer: FileTransferCallback
  ) {
    this.onDataReceived = onData;
    this.onLog = onLog;
    this.onFileTransfer = onFileTransfer;
  }

  async connect(): Promise<void> {
    const nav = navigator as any;
    if (!nav.bluetooth) {
      throw new Error('Web Bluetooth is not supported in this browser.');
    }

    this.log('Requesting device...', 'info');

    try {
      this.device = await nav.bluetooth.requestDevice({
        filters: [{ namePrefix: 'Nextwaves_Scanner_V3' }],
        optionalServices: [SERVICE_UUID],
      });

      this.device!.addEventListener('gattserverdisconnected', this.handleDisconnect.bind(this));

      this.log(`Connecting to ${this.device!.name}...`, 'info');
      this.server = await this.device!.gatt!.connect();

      this.log('Getting Service...', 'info');
      this.service = await this.server.getPrimaryService(SERVICE_UUID);

      this.log('Getting Characteristics...', 'info');
      this.charCmd = await this.service.getCharacteristic(CHAR_CMD_UUID);
      this.charFileReq = await this.service.getCharacteristic(CHAR_FILE_REQ_UUID);
      this.charFileData = await this.service.getCharacteristic(CHAR_FILE_DATA_UUID);

      // Setup Notifications for Commands/Tags
      this.log('Starting Notifications...', 'info');
      await this.charCmd.startNotifications();
      this.charCmd.addEventListener('characteristicvaluechanged', this.handleCmdNotification.bind(this));

      // Setup Notifications for File Data
      await this.charFileData.startNotifications();
      this.charFileData.addEventListener('characteristicvaluechanged', this.handleFileNotification.bind(this));

      this.log('Connected and ready.', 'info');
    } catch (error: any) {
      this.log(`Connection failed: ${error.message}`, 'error');
      throw error;
    }
  }

  disconnect() {
    if (this.device && this.device.gatt?.connected) {
      this.device.gatt.disconnect();
    }
  }

  handleDisconnect() {
    this.log('Device disconnected.', 'error');
    this.resetFileState();
    this.device = null;
    this.server = null;
    this.service = null;
    this.charCmd = null;
    this.charFileReq = null;
    this.charFileData = null;
  }

  private resetFileState() {
    this.isFileTransferring = false;
    this.fileBuffer = [];
    this.fileTotalSize = 0;
    this.fileReceivedSize = 0;
  }

  private handleCmdNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    const decoder = new TextDecoder('utf-8');
    const value = decoder.decode(target.value);

    // Attempt to parse JSON
    try {
        const data = JSON.parse(value);

        // Pass all parsed JSON to the App to handle
        if (this.onDataReceived) {
            this.onDataReceived(data);
        }

        // Log non-tag commands as RX
        if (data.cmd !== 'live_tag') {
             this.log(`RX: ${value}`, 'rx');
        }

    } catch (e) {
        this.log(`RX (Raw): ${value}`, 'rx');
    }
  }

  private handleFileNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value || target.value.byteLength < 2) return;

    const view = new DataView(target.value.buffer);
    // Protocol Header is Big-Endian
    const header = view.getUint16(0, false); 

    if (header === 0xFFFF) {
        // --- START PACKET ---
        this.resetFileState();
        this.isFileTransferring = true;

        // Payload is JSON Metadata
        const payload = new Uint8Array(target.value.buffer.slice(2));
        const decoder = new TextDecoder('utf-8');
        try {
            const jsonStr = decoder.decode(payload);
            const metadata = JSON.parse(jsonStr);
            this.fileTotalSize = metadata.size || 0;

            if (this.onFileTransfer) {
                this.onFileTransfer('start', { total: this.fileTotalSize });
            }
        } catch (e) {
            this.log('Failed to parse START packet', 'error');
            this.isFileTransferring = false;
            if (this.onFileTransfer) this.onFileTransfer('error', 'Invalid START packet');
        }

    } else if (header === 0xFFFE) {
        // --- EOF PACKET ---
        if (!this.isFileTransferring) return;
        this.isFileTransferring = false;

        // Assemble all chunks
        const totalLen = this.fileBuffer.reduce((acc, chunk) => acc + chunk.length, 0);
        const fullFile = new Uint8Array(totalLen);
        let offset = 0;
        for (const chunk of this.fileBuffer) {
            fullFile.set(chunk, offset);
            offset += chunk.length;
        }

        // Decode
        const decoder = new TextDecoder('utf-8');
        const text = decoder.decode(fullFile);

        if (this.onFileTransfer) {
            this.onFileTransfer('complete', text);
        }

    } else {
        // --- DATA PACKET ---
        if (!this.isFileTransferring) return;

        // Header 0x0000 -> 0xFFFD is sequence number, just take payload
        const chunk = new Uint8Array(target.value.buffer.slice(2));
        this.fileBuffer.push(chunk);
        this.fileReceivedSize += chunk.length;

        // Progress
        if (this.onFileTransfer && this.fileTotalSize > 0) {
            const percent = Math.min(100, Math.round((this.fileReceivedSize / this.fileTotalSize) * 100));
            this.onFileTransfer('progress', percent);
        }
    }
  }

  async sendCommand(command: object): Promise<void> {
    if (!this.charCmd) throw new Error('Not connected');
    const str = JSON.stringify(command);
    const encoder = new TextEncoder();
    this.log(`TX: ${str}`, 'tx');
    await this.charCmd.writeValue(encoder.encode(str));
  }

  // Get Settings: Sends a sequence of commands to fetch device state
  async getSettings(): Promise<void> {
    // 1. Get Device Info
    await this.sendCommand({ cmd: 'DI' });
    await this.delay(50);
    // 2. Get Power
    await this.sendCommand({ cmd: 'GP' });
    await this.delay(50);
    // 3. Get Frequency
    await this.sendCommand({ cmd: 'GF' });
    await this.delay(50);
    // 4. Get RF Parameters
    await this.sendCommand({ cmd: 'GRP' });
  }

  private delay(ms: number) {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  async requestFileTransfer(): Promise<void> {
    if (!this.charFileReq) throw new Error('Not connected');

    if (this.isFileTransferring) {
        this.log('File transfer already in progress', 'error');
        return;
    }

    const str = 'send_file';
    const encoder = new TextEncoder();
    this.log(`TX (FileReq): ${str}`, 'tx');
    await this.charFileReq.writeValue(encoder.encode(str));
  }

  private log(msg: string, type: 'info' | 'error' | 'rx' | 'tx') {
    if (this.onLog) this.onLog(msg, type);
    else console.log(`[${type.toUpperCase()}] ${msg}`);
  }
}

