}

export default App;

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export enum ScanMode {
  INTERACTIVE = 'INTERACTIVE',
  BATCH = 'BATCH'
}

export interface Tag {
  epc: string;
  timestamp: number;
  rssi?: number;
  count: number;
}

export interface Settings {
  power: number;
  frequency: string;
  rfParams: string; // "speed,qv,session,target"
  buzzer: boolean;
  deviceInfo: string;
}

export interface BleError {
  message: string;
  timestamp: number;
}

export type LogEntry = {
  type: 'info' | 'error' | 'rx' | 'tx';
  message: string;
  timestamp: number;
};

export type WriteStatus = 'idle' | 'pending' | 'success' | 'error';

// Internal types for component props
export interface ControlsProps {
  status: ConnectionStatus;
  scanMode: ScanMode;
  isScanning: boolean;
  settings: Settings;
  onConnect: () => void;
  onDisconnect: () => void;
  onToggleMode: (mode: ScanMode) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  onUpdateSettings: (key: keyof Settings, value: string | number | boolean) => void;
  onWriteEpc: (oldEpc: string, newEpc: string) => void;
  writeLoading: boolean;
  selectedEpc: string;
  onOpenWriteModal: () => void;
}

export interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export interface BatchResultsProps {
  fileContent: string;
  transferProgress: number; // 0-100, -1 if idle
  isTransferring: boolean;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutDashboard, ScrollText, FileOutput, Radio, Bluetooth } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriteEpcModal } from './components/WriteEpcModal';
import { Button } from './components/ui/Button';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

function App() {
  // --- State ---
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Modal State
  const [isWriteModalOpen, setIsWriteModalOpen] = useState(false);

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs for Performance ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Callbacks ---

  const handleDataReceived = useCallback((data: any) => {
    // 1. Handle Tag Data
    if (data.cmd === 'live_tag' && data.epc) {
        const now = Date.now();
        const newTag: Tag = {
          epc: data.epc,
          timestamp: now,
          rssi: data.rssi,
          count: 1
        };

        // Update Buffer
        const existing = tagBufferRef.current.get(newTag.epc);
        if (existing) {
            newTag.count = existing.count + 1;
        }
        tagBufferRef.current.set(newTag.epc, newTag);
        return;
    }

    // 2. Handle Settings Responses
    if (data.cmd === 'DI') {
        setSettings(prev => ({ ...prev, deviceInfo: data.val }));
        addLog(`Device Info: ${data.val}`, 'rx');
    }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));

    // 3. Handle Write EPC Response
    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Success! New EPC: ${data.epc}`);
        addLog(`Write Success: ${data.epc}`, 'info');
      } else {
        setWriteStatus('error');
        setWriteMessage('Write failed. Device returned error.');
        addLog('Write Failed: Device returned error', 'error');
      }
    }

  }, [addLog]);

  // Handle File Transfer Events
  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') {
        setIsTransferring(true);
        setTransferProgress(0);
        setFileContent('');
        const sizeKB = (data?.total / 1024).toFixed(1);
        addLog(`File transfer started (${sizeKB} KB)...`, 'info');
    } else if (event === 'progress') {
        setTransferProgress(data); // data is percentage
    } else if (event === 'complete') {
        setIsTransferring(false);
        setTransferProgress(100);
        setFileContent(data); // data is file string
        addLog('File transfer completed successfully.', 'info');
    } else if (event === 'error') {
        setIsTransferring(false);
        setTransferProgress(-1);
        addLog(`File transfer error: ${data}`, 'error');
    }
  }, [addLog]);

  // --- Effects ---

  // Initialize BLE listeners
  useEffect(() => {
    bleService.setCallbacks(
        handleDataReceived,
        (msg, type) => addLog(msg, type),
        handleFileEvent
    );
  }, [handleDataReceived, addLog, handleFileEvent]);

  // Render Loop for Tags (throttled to 200ms)
  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 200 && tagBufferRef.current.size > 0) {
        // Convert Map values to array, sort by timestamp desc, take top 500
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        // Sort: newest first
        allTags.sort((a, b) => b.timestamp - a.timestamp);
        const displayTags = allTags.slice(0, 500);

        setTags(displayTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };

    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);


  // --- Actions ---

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);

      // Auto-fetch settings sequence after connection
      setTimeout(async () => {
         addLog('Fetching device settings...', 'tx');
         try {
            await bleService.getSettings();
         } catch(e) {
            addLog('Failed to fetch settings', 'error');
         }
      }, 500);

    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'S' });
      } else {
        // Batch
        setFileContent(''); // Clear previous batch results
        await bleService.sendCommand({ cmd: 'SB' });
      }
      setIsScanning(true);
      addLog(`Started ${scanMode} Scan`, 'info');
    } catch (e: any) {
      addLog(`Scan Start Failed: ${e.message}`, 'error');
    }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'X' });
      } else {
        // Batch
        await bleService.sendCommand({ cmd: 'XB' });
        // Auto trigger file transfer
        setTimeout(async () => {
             addLog('Requesting File Transfer...', 'tx');
             await bleService.requestFileTransfer();
        }, 500);
      }
      setIsScanning(false);
      addLog('Stopped Scan', 'info');
    } catch (e: any) {
      addLog(`Scan Stop Failed: ${e.message}`, 'error');
    }
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    // Optimistic update for App state
    setSettings(prev => ({ ...prev, [key]: value }));

    if (status !== ConnectionStatus.CONNECTED) return;

    try {
        let cmd = {};
        if (key === 'power') cmd = { cmd: 'SP', val: value };
        if (key === 'frequency') cmd = { cmd: 'SF', val: value };
        if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
        if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };

        await bleService.sendCommand(cmd);
        addLog(`Set ${key}: ${value}`, 'info');
    } catch(e: any) {
        addLog(`Settings Update Failed: ${e.message}`, 'error');
    }
  };

  const handleWriteEpc = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc) return;

    setWriteStatus('pending');
    setWriteMessage('');

    try {
        await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
        addLog(`Write Command Sent: ${oldEpc} -> ${newEpc}`, 'info');
        // The actual success/fail is handled in handleDataReceived via 'WE' response
    } catch (e: any) {
        setWriteStatus('error');
        setWriteMessage(e.message);
        addLog(`Write Failed: ${e.message}`, 'error');
    }
  };

  const handleClearLog = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  return (
    // changed from h-screen h-[100dvh] to fixed inset-0 to reliably lock to viewport on Android
    <div className="fixed inset-0 flex flex-col bg-slate-950 text-slate-200 overflow-hidden">

      {/* Write EPC Modal */}
      <WriteEpcModal 
        isOpen={isWriteModalOpen}
        onClose={() => {
            setIsWriteModalOpen(false);
            setWriteStatus('idle'); // Reset status on close
        }}
        onWrite={handleWriteEpc}
        writeStatus={writeStatus}
        writeMessage={writeMessage}

        // Pass scanning capabilities to modal
        onStartScan={handleStartScan}
        onStopScan={handleStopScan}
        isScanning={isScanning}
        liveTags={tags}
      />

      {/* --- Global Mobile/Tablet Header (< lg) --- */}
      <div className="lg:hidden flex items-center justify-between p-3 bg-slate-900 border-b border-slate-800 shrink-0 z-20">
        <div className="flex items-center gap-2 text-blue-400">
          <Radio className="w-5 h-5" />
          <h1 className="font-bold text-base text-slate-100">Nextwaves V3</h1>
        </div>

        <div className="flex items-center gap-3">
          {/* Status Dot */}
          <div className={`w-2.5 h-2.5 rounded-full ${
            status === ConnectionStatus.CONNECTED ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 
            status === ConnectionStatus.ERROR ? 'bg-red-500' : 
            status === ConnectionStatus.CONNECTING ? 'bg-yellow-500 animate-pulse' : 'bg-slate-600'
          }`} title={status} />

          {isConnected ? (
             <Button variant="danger" size="sm" onClick={handleDisconnect} disabled={isScanning}>
               <Bluetooth className="w-3 h-3 mr-1" />
               Disconnect
             </Button>
          ) : (
             <Button variant="primary" size="sm" onClick={handleConnect} disabled={status === ConnectionStatus.CONNECTING}>
               <Bluetooth className="w-3 h-3 mr-1" />
               {status === ConnectionStatus.CONNECTING ? '...' : 'Connect'}
             </Button>
          )}
        </div>
      </div>

      {/* --- Main Content Area --- */}
      <div className="flex-1 flex flex-col lg:flex-row overflow-hidden relative">

        {/* 1. Controls Wrapper - Fixed 80 (320px) on Desktop */}
        <div className={`
          ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
          lg:flex flex-col h-full w-full lg:w-80 shrink-0 z-10 border-b lg:border-b-0 lg:border-r border-slate-800
        `}>
          <Controls 
            status={status}
            scanMode={scanMode}
            isScanning={isScanning}
            settings={settings}
            onConnect={handleConnect}
            onDisconnect={handleDisconnect}
            onToggleMode={setScanMode}
            onStartScan={handleStartScan}
            onStopScan={handleStopScan}
            onUpdateSettings={handleUpdateSettings}
            onWriteEpc={handleWriteEpc}
            writeLoading={writeStatus === 'pending'}
            selectedEpc={selectedEpc}
            onOpenWriteModal={() => setIsWriteModalOpen(true)}
          />
        </div>

        {/* 2. Middle Interactive Log Wrapper - Flexible */}
        <div className={`
          ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
          lg:flex flex-col flex-1 h-full min-w-0
        `}>
          <InteractiveLog 
            tags={tags}
            onClear={handleClearLog}
            onSelectEpc={setSelectedEpc}
            logs={logs}
          />
        </div>

        {/* 3. Right Batch Results Wrapper - Fixed 80 (320px) on Desktop */}
        <div className={`
          ${mobileTab === 'results' ? 'flex' : 'hidden'} 
          lg:flex flex-col h-full w-full lg:w-80 shrink-0 border-t lg:border-t-0 lg:border-l border-slate-800
        `}>
          <BatchResults 
            fileContent={fileContent}
            isTransferring={isTransferring}
            transferProgress={transferProgress} 
          />
        </div>

      </div>

      {/* --- Mobile Tab Navigation (< lg) --- */}
      <div className="lg:hidden flex items-center justify-around bg-slate-900 border-t border-slate-800 h-16 shrink-0 z-50 safe-area-pb">
        <button 
          onClick={() => setMobileTab('controls')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'controls' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <LayoutDashboard size={20} />
          <span className="text-[10px] font-medium">Controls</span>
        </button>

        <button 
          onClick={() => setMobileTab('logs')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'logs' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <div className="relative">
            <ScrollText size={20} />
            {tags.length > 0 && <span className="absolute -top-1 -right-1 w-2 h-2 bg-emerald-500 rounded-full" />}
          </div>
          <span className="text-[10px] font-medium">Logs</span>
        </button>

        <button 
          onClick={() => setMobileTab('results')}
          className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'results' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
        >
          <FileOutput size={20} />
          <span className="text-[10px] font-medium">Batch</span>
        </button>
      </div>

    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { X, FileText, ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriteEpcModalProps {
  isOpen: boolean;
  onClose: () => void;
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;

  // Scanning props
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriteEpcModal: React.FC<WriteEpcModalProps> = ({
  isOpen,
  onClose,
  onWrite,
  writeStatus,
  writeMessage,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  // Reset state when opening
  useEffect(() => {
    if (isOpen) {
      setStep(1);
      setTargetEpc('');
      setNewEpc('');
      setError('');
    }
    // Cleanup: Ensure scan stops if modal closes while scanning
    return () => {
      if (isScanning && isOpen) {
        onStopScan();
      }
    };
  }, [isOpen]);

  // When a user selects a tag in Step 1
  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); // Pre-fill with current for easy editing
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    // Auto-restart scan? Maybe optional. Let's let user click start.
  };

  const validateAndWrite = () => {
    // 1. Hex validation
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('New EPC must contain only Hex characters (0-9, A-F).');
      return;
    }
    // 2. Length validation (must be multiple of 4 chars = 16 bits)
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`Length must be a multiple of 4 characters. Current: ${newEpc.length}`);
        return;
    }

    setError('');
    onWrite(targetEpc, newEpc);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-slate-900 border border-slate-700 rounded-xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-950/50 shrink-0">
          <div className="flex items-center gap-2 text-slate-100">
            <div className="p-1.5 bg-blue-500/10 rounded-lg">
                <FileText className="w-5 h-5 text-blue-400" />
            </div>
            <div>
                <h2 className="font-semibold text-sm">Write EPC Tool</h2>
                <p className="text-[10px] text-slate-400">Step {step} of 2</p>
            </div>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content Body */}
        <div className="flex-1 overflow-y-auto p-6">

          {/* Global Warning */}
          <div className="bg-amber-900/20 border border-amber-800/50 rounded-lg p-3 flex items-start gap-3 mb-6">
            <AlertTriangle className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
            <p className="text-xs text-amber-200/80 leading-relaxed">
              <strong>Safety Warning:</strong> Ensure only <u>ONE</u> tag is near the antenna. Writing with multiple tags in the field may overwrite the wrong tag.
            </p>
          </div>

          {/* Step 1: Scan & Select */}
          {step === 1 && (
            <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                    <h3 className="text-slate-200 font-medium text-sm">1. Find Target Tag</h3>
                    {isScanning ? (
                        <Button size="sm" variant="danger" onClick={onStopScan}>Stop Scan</Button>
                    ) : (
                        <Button size="sm" variant="success" onClick={onStartScan}>Start Scan</Button>
                    )}
                </div>

                <div className="bg-slate-950 border border-slate-800 rounded-lg h-60 overflow-y-auto relative custom-scrollbar">
                    {liveTags.length === 0 ? (
                        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-2">
                            <Radio className={`w-8 h-8 ${isScanning ? 'animate-pulse text-blue-500' : 'text-slate-700'}`} />
                            <p className="text-xs">{isScanning ? 'Scanning for tags...' : 'Press Start Scan to find tags'}</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-slate-800">
                            {liveTags.map((tag, idx) => (
                                <button 
                                    key={idx}
                                    onClick={() => handleSelectTag(tag.epc)}
                                    className="w-full flex items-center justify-between p-3 hover:bg-slate-800 transition-colors group text-left"
                                >
                                    <div>
                                        <p className="font-mono text-emerald-400 text-sm group-hover:text-emerald-300 transition-colors">{tag.epc}</p>
                                        <p className="text-[10px] text-slate-500">RSSI: {tag.rssi} dBm</p>
                                    </div>
                                    <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                                        <span className="text-xs bg-blue-600 text-white px-2 py-1 rounded">Select</span>
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            </div>
          )}

          {/* Step 2: Write */}
          {step === 2 && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
                 <div className="space-y-1">
                    <label className="text-xs text-slate-400 uppercase font-semibold tracking-wider">Target Tag (Locked)</label>
                    <div className="bg-slate-800/50 border border-slate-700 rounded-md p-3 flex items-center gap-2">
                        <Search className="w-4 h-4 text-slate-500" />
                        <span className="font-mono text-slate-300 text-sm">{targetEpc}</span>
                    </div>
                 </div>

                 <div className="flex justify-center py-2">
                    <ArrowRight className="w-6 h-6 text-slate-600 animate-pulse" />
                 </div>

                 <div className="space-y-4">
                     <Input 
                        label="New EPC Value (Hex)"
                        placeholder="E280..."
                        value={newEpc}
                        onChange={(e) => {
                            setNewEpc(e.target.value.toUpperCase());
                            setError('');
                        }}
                        error={error}
                        className="font-mono"
                        disabled={writeStatus === 'pending' || writeStatus === 'success'}
                     />
                     <div className="text-[10px] text-slate-500 flex justify-between">
                        <span>Characters: {newEpc.length}</span>
                        <span>Bits: {newEpc.length * 4}</span>
                     </div>
                 </div>

                 {/* Write Status Feedback */}
                 {writeStatus === 'success' && (
                     <div className="bg-emerald-900/20 border border-emerald-800 rounded-lg p-3 flex items-center gap-3">
                         <CheckCircle2 className="w-5 h-5 text-emerald-500" />
                         <p className="text-sm text-emerald-200">{writeMessage}</p>
                     </div>
                 )}

                 {writeStatus === 'error' && (
                     <div className="bg-red-900/20 border border-red-800 rounded-lg p-3 flex items-center gap-3">
                         <XCircle className="w-5 h-5 text-red-500" />
                         <p className="text-sm text-red-200">{writeMessage}</p>
                     </div>
                 )}

            </div>
          )}

        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-800 bg-slate-950/30 flex justify-between items-center shrink-0">
          {step === 2 ? (
             <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'}>
                Back
             </Button>
          ) : (
             <span /> // Spacer
          )}

          <div className="flex gap-3">
             <Button variant="secondary" onClick={onClose} disabled={writeStatus === 'pending'}>
                {writeStatus === 'success' ? 'Close' : 'Cancel'}
             </Button>

             {step === 2 && writeStatus !== 'success' && (
                <Button 
                    variant="primary" 
                    onClick={validateAndWrite} 
                    disabled={writeStatus === 'pending'}
                >
                    {writeStatus === 'pending' ? 'Writing...' : 'Write Tag'}
                </Button>
             )}
          </div>
        </div>

      </div>
    </div>
  );
};

import { ConnectionStatus } from '../types';

// --- Web Bluetooth Type Definitions ---
interface BluetoothDevice extends EventTarget {
  id: string;
  name?: string;
  gatt?: BluetoothRemoteGATTServer;
}

interface BluetoothRemoteGATTServer {
  device: BluetoothDevice;
  connected: boolean;
  connect(): Promise<BluetoothRemoteGATTServer>;
  disconnect(): void;
  getPrimaryService(service: string | number): Promise<BluetoothRemoteGATTService>;
}

interface BluetoothRemoteGATTService {
  getCharacteristic(characteristic: string | number): Promise<BluetoothRemoteGATTCharacteristic>;
}

interface BluetoothRemoteGATTCharacteristic extends EventTarget {
  value?: DataView;
  writeValue(value: BufferSource): Promise<void>;
  startNotifications(): Promise<BluetoothRemoteGATTCharacteristic>;
}
// --------------------------------------

const SERVICE_UUID = 0x00ff;
const CHAR_CMD_UUID = 0xff01;
const CHAR_FILE_REQ_UUID = 0xff02;
const CHAR_FILE_DATA_UUID = 0xff03;

// Callbacks
type DataCallback = (data: any) => void;
type LogCallback = (msg: string, type: 'info' | 'error' | 'rx' | 'tx') => void;
type FileTransferEvent = 'start' | 'progress' | 'complete' | 'error';
type FileTransferCallback = (event: FileTransferEvent, data?: any) => void;

class BLEService {
  private device: BluetoothDevice | null = null;
  private server: BluetoothRemoteGATTServer | null = null;
  private service: BluetoothRemoteGATTService | null = null;
  private charCmd: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileReq: BluetoothRemoteGATTCharacteristic | null = null;
  private charFileData: BluetoothRemoteGATTCharacteristic | null = null;

  private onDataReceived: DataCallback | null = null;
  private onLog: LogCallback | null = null;
  private onFileTransfer: FileTransferCallback | null = null;

  // File Transfer State
  private isFileTransferring = false;
  private fileBuffer: Uint8Array[] = [];
  private fileTotalSize = 0;
  private fileReceivedSize = 0;

  // Command Queue to prevent GATT collisions
  private commandQueue: Promise<void> = Promise.resolve();

  constructor() {}

  setCallbacks(
    onData: DataCallback,
    onLog: LogCallback,
    onFileTransfer: FileTransferCallback
  ) {
    this.onDataReceived = onData;
    this.onLog = onLog;
    this.onFileTransfer = onFileTransfer;
  }

  async connect(): Promise<void> {
    const nav = navigator as any;
    if (!nav.bluetooth) {
      throw new Error('Web Bluetooth is not supported in this browser.');
    }

    this.log('Requesting device...', 'info');

    try {
      this.device = await nav.bluetooth.requestDevice({
        filters: [{ namePrefix: 'Nextwaves_Scanner_V3' }],
        optionalServices: [SERVICE_UUID],
      });

      this.device!.addEventListener('gattserverdisconnected', this.handleDisconnect.bind(this));

      this.log(`Connecting to ${this.device!.name}...`, 'info');
      this.server = await this.device!.gatt!.connect();

      this.log('Getting Service...', 'info');
      this.service = await this.server.getPrimaryService(SERVICE_UUID);

      this.log('Getting Characteristics...', 'info');
      this.charCmd = await this.service.getCharacteristic(CHAR_CMD_UUID);
      this.charFileReq = await this.service.getCharacteristic(CHAR_FILE_REQ_UUID);
      this.charFileData = await this.service.getCharacteristic(CHAR_FILE_DATA_UUID);

      // Setup Notifications for Commands/Tags
      this.log('Starting Notifications...', 'info');
      await this.charCmd.startNotifications();
      this.charCmd.addEventListener('characteristicvaluechanged', this.handleCmdNotification.bind(this));

      // Setup Notifications for File Data
      await this.charFileData.startNotifications();
      this.charFileData.addEventListener('characteristicvaluechanged', this.handleFileNotification.bind(this));

      this.log('Connected and ready.', 'info');
    } catch (error: any) {
      this.log(`Connection failed: ${error.message}`, 'error');
      throw error;
    }
  }

  disconnect() {
    if (this.device && this.device.gatt?.connected) {
      this.device.gatt.disconnect();
    }
  }

  handleDisconnect() {
    this.log('Device disconnected.', 'error');
    this.resetFileState();
    this.device = null;
    this.server = null;
    this.service = null;
    this.charCmd = null;
    this.charFileReq = null;
    this.charFileData = null;
  }

  private resetFileState() {
    this.isFileTransferring = false;
    this.fileBuffer = [];
    this.fileTotalSize = 0;
    this.fileReceivedSize = 0;
  }

  private handleCmdNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value) return;

    const decoder = new TextDecoder('utf-8');
    const value = decoder.decode(target.value);

    // Attempt to parse JSON
    try {
        const data = JSON.parse(value);

        // Pass all parsed JSON to the App to handle
        if (this.onDataReceived) {
            this.onDataReceived(data);
        }

        // Log non-tag commands as RX
        if (data.cmd !== 'live_tag') {
             this.log(`RX: ${value}`, 'rx');
        }

    } catch (e) {
        this.log(`RX (Raw): ${value}`, 'rx');
    }
  }

  private handleFileNotification(event: Event) {
    const target = event.target as BluetoothRemoteGATTCharacteristic;
    if (!target.value || target.value.byteLength < 2) return;

    const view = new DataView(target.value.buffer);
    // Protocol Header is Big-Endian
    const header = view.getUint16(0, false); 

    if (header === 0xFFFF) {
        // --- START PACKET ---
        this.resetFileState();
        this.isFileTransferring = true;

        // Payload is JSON Metadata
        const payload = new Uint8Array(target.value.buffer.slice(2));
        const decoder = new TextDecoder('utf-8');
        try {
            const jsonStr = decoder.decode(payload);
            const metadata = JSON.parse(jsonStr);
            this.fileTotalSize = metadata.size || 0;

            if (this.onFileTransfer) {
                this.onFileTransfer('start', { total: this.fileTotalSize });
            }
        } catch (e) {
            this.log('Failed to parse START packet', 'error');
            this.isFileTransferring = false;
            if (this.onFileTransfer) this.onFileTransfer('error', 'Invalid START packet');
        }

    } else if (header === 0xFFFE) {
        // --- EOF PACKET ---
        if (!this.isFileTransferring) return;
        this.isFileTransferring = false;

        // Assemble all chunks
        const totalLen = this.fileBuffer.reduce((acc, chunk) => acc + chunk.length, 0);
        const fullFile = new Uint8Array(totalLen);
        let offset = 0;
        for (const chunk of this.fileBuffer) {
            fullFile.set(chunk, offset);
            offset += chunk.length;
        }

        // Decode
        const decoder = new TextDecoder('utf-8');
        const text = decoder.decode(fullFile);

        if (this.onFileTransfer) {
            this.onFileTransfer('complete', text);
        }

    } else {
        // --- DATA PACKET ---
        if (!this.isFileTransferring) return;

        // Header 0x0000 -> 0xFFFD is sequence number, just take payload
        const chunk = new Uint8Array(target.value.buffer.slice(2));
        this.fileBuffer.push(chunk);
        this.fileReceivedSize += chunk.length;

        // Progress
        if (this.onFileTransfer && this.fileTotalSize > 0) {
            const percent = Math.min(100, Math.round((this.fileReceivedSize / this.fileTotalSize) * 100));
            this.onFileTransfer('progress', percent);
        }
    }
  }

  // Queue commands to ensure they are serialized
  async sendCommand(command: object): Promise<void> {
    if (!this.charCmd) throw new Error('Not connected');

    const str = JSON.stringify(command);
    const encoder = new TextEncoder();
    const data = encoder.encode(str);

    // Append to queue
    this.commandQueue = this.commandQueue.then(async () => {
      try {
        this.log(`TX: ${str}`, 'tx');
        if (this.charCmd) {
          await this.charCmd.writeValue(data);
        }
      } catch (error: any) {
        this.log(`TX Failed: ${error.message}`, 'error');
        throw error;
      }
    });

    return this.commandQueue;
  }

  // Get Settings: Sends a sequence of commands to fetch device state
  async getSettings(): Promise<void> {
    // These will be queued automatically by sendCommand
    await this.sendCommand({ cmd: 'DI' });
    await this.sendCommand({ cmd: 'GP' });
    await this.sendCommand({ cmd: 'GF' });
    await this.sendCommand({ cmd: 'GRP' });
  }

  async requestFileTransfer(): Promise<void> {
    if (!this.charFileReq) throw new Error('Not connected');

    if (this.isFileTransferring) {
        this.log('File transfer already in progress', 'error');
        return;
    }

    const str = 'send_file';
    const encoder = new TextEncoder();

    // Also queue file requests if necessary, though it uses a different char
    try {
        this.log(`TX (FileReq): ${str}`, 'tx');
        await this.charFileReq.writeValue(encoder.encode(str));
    } catch (e: any) {
        this.log(`FileReq Failed: ${e.message}`, 'error');
    }
  }

  private log(msg: string, type: 'info' | 'error' | 'rx' | 'tx') {
    if (this.onLog) this.onLog(msg, type);
    else console.log(`[${type.toUpperCase()}] ${msg}`);
  }
}

export const bleService = new BLEService();

import React, { useState, useEffect } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, ScanLine, Zap, Info, Bell } from 'lucide-react';
import { Button } from './ui/Button';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

interface ExtendedControlsProps extends ControlsProps {
  onOpenWriteModal?: () => void; // Deprecated but kept for type compat if needed
}

export const Controls: React.FC<ExtendedControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  // Local state for basic settings
  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  // Local state for complex RF Params [speed, qv, session, target]
  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  // Sync basic state when props change (from device read)
  useEffect(() => {
    setLocalPower(settings.power);
  }, [settings.power]);

  useEffect(() => {
    setLocalFreq(settings.frequency);
  }, [settings.frequency]);

  useEffect(() => {
    setLocalBuzzer(settings.buzzer);
  }, [settings.buzzer]);

  // Parse RF Params String (e.g. "1,4,1,0") into local state
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) {
        setRfSpeed(parts[0]);
        setRfQv(parts[1]);
        setRfSession(parts[2]);
        setRfTarget(parts[3]);
      }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;

  // Dirty Checks
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isBuzzerDirty = localBuzzer !== settings.buzzer;

  // Construct current RF string to check dirty state
  const currentRfString = `${rfSpeed},${rfQv},${rfSession},${rfTarget}`;
  const isRfDirty = currentRfString !== settings.rfParams;

  const handleSetRfParams = () => {
    onUpdateSettings('rfParams', currentRfString);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 p-4 overflow-y-auto w-full gap-6">

      {/* Header / Connection */}
      <div className="hidden lg:block space-y-4">
        <div className="flex items-center gap-2 text-blue-400 mb-2">
          <Radio className="w-6 h-6" />
          <h1 className="font-bold text-lg text-slate-100">Nextwaves V3</h1>
        </div>

        {isConnected && settings.deviceInfo && (
          <div className="bg-slate-800/50 p-2 rounded border border-slate-700 mb-2 flex items-center gap-2">
            <Info className="w-4 h-4 text-blue-400" />
            <span className="text-xs text-slate-300 font-mono truncate">{settings.deviceInfo}</span>
          </div>
        )}

        {isConnected ? (
          <Button variant="danger" fullWidth onClick={onDisconnect} disabled={isScanning}>
            <Bluetooth className="w-4 h-4 mr-2" />
            Disconnect
          </Button>
        ) : (
          <Button variant="primary" fullWidth onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING}>
            <Bluetooth className="w-4 h-4 mr-2" />
            {status === ConnectionStatus.CONNECTING ? 'Connecting...' : 'Connect Scanner'}
          </Button>
        )}

        <div className="flex items-center justify-between text-xs px-1">
          <span className="text-slate-500">Status</span>
          <span className={`font-medium ${
            status === ConnectionStatus.CONNECTED ? 'text-emerald-400' : 
            status === ConnectionStatus.ERROR ? 'text-red-400' : 'text-slate-400'
          }`}>
            {status}
          </span>
        </div>
        <div className="h-px bg-slate-800" />
      </div>

      {/* Scan Controls */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <ScanLine className="w-4 h-4" />
          <h2>Scanning</h2>
        </div>

        <div className="bg-slate-800 p-1 rounded-lg flex text-xs">
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.INTERACTIVE ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
            disabled={isScanning}
          >
            Interactive
          </button>
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.BATCH ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.BATCH)}
            disabled={isScanning}
          >
            Batch
          </button>
        </div>

        {isScanning ? (
          <Button variant="danger" fullWidth onClick={onStopScan} disabled={!isConnected}>
            Stop Scan
          </Button>
        ) : (
          <Button variant="success" fullWidth onClick={onStartScan} disabled={!isConnected}>
            Start Scan
          </Button>
        )}
      </div>

      <div className="h-px bg-slate-800" />

      {/* Settings */}
      <div className="space-y-6 flex-1">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <SettingsIcon className="w-4 h-4" />
          <h2>Settings</h2>
        </div>

        {/* Tx Power */}
        <div>
          <label className="flex justify-between text-xs text-slate-400 mb-2">
            <span>Tx Power</span>
            <span className={isPowerDirty ? "text-amber-400 font-medium" : "text-slate-400"}>
              {localPower} dBm
            </span>
          </label>
          <div className="flex items-center gap-3">
            <input 
              type="range" 
              min="0" 
              max="33" 
              value={localPower}
              onChange={(e) => setLocalPower(parseInt(e.target.value))}
              disabled={!isConnected || isScanning}
              className="flex-1 h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
            <Button 
              size="sm" 
              variant={isPowerDirty ? 'primary' : 'outline'}
              className={!isPowerDirty ? "border-slate-700 text-slate-500" : ""}
              disabled={!isConnected || isScanning || !isPowerDirty}
              onClick={() => onUpdateSettings('power', localPower)}
            >
              Set
            </Button>
          </div>
        </div>

        {/* Region */}
        <div className="space-y-2">
            <label className="text-xs text-slate-400">Region</label>
            <div className="flex gap-2">
              <select 
                className="flex-1 bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-md p-2 focus:ring-1 focus:ring-blue-500 focus:outline-none"
                value={localFreq}
                onChange={(e) => setLocalFreq(e.target.value)}
                disabled={!isConnected || isScanning}
              >
                <option value="US">US (902-928 MHz)</option>
                <option value="EU">EU (865-868 MHz)</option>
                <option value="CN">CN (920-925 MHz)</option>
                <option value="VN">VN (918-923 MHz)</option>
              </select>
              <Button 
                size="sm" 
                variant={isFreqDirty ? 'primary' : 'outline'}
                className={!isFreqDirty ? "border-slate-700 text-slate-500" : ""}
                disabled={!isConnected || isScanning || !isFreqDirty}
                onClick={() => onUpdateSettings('frequency', localFreq)}
              >
                Set
              </Button>
            </div>
        </div>

        {/* Buzzer */}
        <div className="flex items-center justify-between">
             <div className="flex items-center gap-2 text-slate-400 text-xs">
                 <Bell className="w-3 h-3" />
                 <span>Buzzer</span>
             </div>
             <div className="flex items-center gap-2">
                 <button 
                     className={`w-10 h-5 rounded-full relative transition-colors ${localBuzzer ? 'bg-blue-600' : 'bg-slate-700'}`}
                     onClick={() => setLocalBuzzer(!localBuzzer)}
                     disabled={!isConnected || isScanning}
                 >
                     <div className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full transition-transform ${localBuzzer ? 'translate-x-5' : 'translate-x-0'}`} />
                 </button>
                 <Button 
                    size="sm" 
                    variant={isBuzzerDirty ? 'primary' : 'outline'}
                    className={`px-2 py-0.5 text-xs h-6 ${!isBuzzerDirty ? "border-slate-700 text-slate-500" : ""}`}
                    disabled={!isConnected || isScanning || !isBuzzerDirty}
                    onClick={() => onUpdateSettings('buzzer', localBuzzer)}
                  >
                    Set
                  </Button>
             </div>
        </div>

        {/* Complex RF Params */}
        <div className="space-y-3 pt-2 border-t border-slate-800">
           <div className="flex items-center justify-between">
                <label className="text-xs text-slate-400 flex items-center gap-1">
                    <Zap className="w-3 h-3" /> RF Parameters
                </label>
                <Button 
                    size="sm" 
                    variant={isRfDirty ? 'primary' : 'outline'}
                    className={!isRfDirty ? "border-slate-700 text-slate-500" : ""}
                    disabled={!isConnected || isScanning || !isRfDirty}
                    onClick={handleSetRfParams}
                >
                    Set RF
                </Button>
           </div>

           <div className="grid grid-cols-2 gap-2">
               {/* EPC Speed */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Mode / Speed</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfSpeed}
                       onChange={(e) => setRfSpeed(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>Tari 25us / FM0 / 40K</option>
                       <option value={1}>Tari 25us / M4 / 250K</option>
                       <option value={2}>Tari 25us / M4 / 300K</option>
                       <option value={3}>Tari 6.25us / FM0 / 400K</option>
                   </select>
               </div>

               {/* Q Value */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Q Value ({rfQv})</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfQv}
                       onChange={(e) => setRfQv(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       {[...Array(16)].map((_, i) => (
                           <option key={i} value={i}>{i}</option>
                       ))}
                   </select>
               </div>

               {/* Session */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Session</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfSession}
                       onChange={(e) => setRfSession(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>S0</option>
                       <option value={1}>S1</option>
                       <option value={2}>S2</option>
                       <option value={3}>S3</option>
                   </select>
               </div>

                {/* Target */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Target</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfTarget}
                       onChange={(e) => setRfTarget(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>A</option>
                       <option value={1}>B</option>
                       <option value={2}>A & B</option>
                   </select>
               </div>
           </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { FileText, ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search, PenTool } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriterViewProps {
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;
  setWriteStatus: (status: WriteStatus) => void;

  // Scanning props
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriterView: React.FC<WriterViewProps> = ({
  onWrite,
  writeStatus,
  writeMessage,
  setWriteStatus,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  // When a user selects a tag in Step 1
  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); // Pre-fill with current for easy editing
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    setWriteStatus('idle');
  };

  const validateAndWrite = () => {
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('New EPC must contain only Hex characters (0-9, A-F).');
      return;
    }
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`Length must be a multiple of 4 characters. Current: ${newEpc.length}`);
        return;
    }

    setError('');
    onWrite(targetEpc, newEpc);
  };

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 p-4 lg:p-8 overflow-y-auto">
        <div className="max-w-3xl mx-auto w-full flex flex-col gap-6">

            {/* Header */}
            <div className="flex items-center gap-3 pb-4 border-b border-slate-800">
                <div className="p-2 bg-blue-500/10 rounded-lg">
                    <PenTool className="w-6 h-6 text-blue-400" />
                </div>
                <div>
                    <h1 className="text-xl font-bold text-slate-100">Tag Writer</h1>
                    <p className="text-slate-400 text-sm">Update the EPC of your RFID tags safely.</p>
                </div>
            </div>

            {/* Warning */}
            <div className="bg-amber-900/20 border border-amber-800/50 rounded-lg p-4 flex items-start gap-3">
                <AlertTriangle className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
                <div className="space-y-1">
                    <p className="text-sm font-medium text-amber-200">Single Tag Safety Check</p>
                    <p className="text-xs text-amber-200/70 leading-relaxed">
                        RFID is a broadcast technology. Ensure <strong>only ONE tag</strong> is near the antenna when writing. 
                        If multiple tags are detected, remove them to prevent overwriting the wrong tag.
                    </p>
                </div>
            </div>

            {/* Step 1: Scan & Select */}
            {step === 1 && (
                <div className="flex flex-col gap-4 animate-in slide-in-from-right-4 duration-300">
                    <div className="flex items-center justify-between bg-slate-900 p-4 rounded-lg border border-slate-800">
                        <div className="flex items-center gap-3">
                             <div className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 text-slate-300 font-bold border border-slate-700">1</div>
                             <div>
                                 <h3 className="text-slate-200 font-medium">Find Target Tag</h3>
                                 <p className="text-xs text-slate-500">Scan nearby tags and select the one you want to edit.</p>
                             </div>
                        </div>
                        {isScanning ? (
                            <Button size="sm" variant="danger" onClick={onStopScan} className="min-w-[100px]">Stop Scan</Button>
                        ) : (
                            <Button size="sm" variant="success" onClick={onStartScan} className="min-w-[100px]">Start Scan</Button>
                        )}
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-lg min-h-[300px] flex-1 overflow-hidden flex flex-col">
                        <div className="bg-slate-800/50 px-4 py-2 border-b border-slate-700/50 text-xs font-medium text-slate-400 flex justify-between">
                            <span>Detected Tags</span>
                            <span>{liveTags.length} found</span>
                        </div>
                        <div className="flex-1 overflow-y-auto relative custom-scrollbar">
                            {liveTags.length === 0 ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 gap-3">
                                    <Radio className={`w-10 h-10 ${isScanning ? 'animate-pulse text-blue-500' : 'text-slate-700'}`} />
                                    <p className="text-sm">{isScanning ? 'Scanning...' : 'Press "Start Scan" to begin'}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-slate-800">
                                    {liveTags.map((tag, idx) => (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectTag(tag.epc)}
                                            className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors group text-left"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                                                <div>
                                                    <p className="font-mono text-emerald-400 font-medium group-hover:text-emerald-300 transition-colors text-base">{tag.epc}</p>
                                                    <p className="text-xs text-slate-500 mt-0.5">RSSI: {tag.rssi} dBm &bull; Count: {tag.count}</p>
                                                </div>
                                            </div>
                                            <div className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-2 group-hover:translate-x-0 duration-200">
                                                <span className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium">Select & Edit</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Step 2: Write */}
            {step === 2 && (
                <div className="flex flex-col gap-6 animate-in slide-in-from-right-4 duration-300">
                     <div className="flex items-center gap-3">
                         <div className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 text-slate-300 font-bold border border-slate-700">2</div>
                         <h3 className="text-slate-200 font-medium">Enter New EPC</h3>
                     </div>

                     <div className="bg-slate-900 border border-slate-800 rounded-lg p-6 space-y-8">

                         {/* Old vs New Comparison */}
                         <div className="grid gap-6">
                            <div className="space-y-2">
                                <label className="text-xs text-slate-500 uppercase font-semibold tracking-wider">Current EPC (Target)</label>
                                <div className="bg-slate-950 border border-slate-800 rounded-md p-3 flex items-center gap-3">
                                    <Search className="w-4 h-4 text-slate-500" />
                                    <span className="font-mono text-slate-400 text-lg">{targetEpc}</span>
                                </div>
                            </div>

                            <div className="flex justify-center">
                                <div className="bg-slate-800 p-2 rounded-full">
                                    <ArrowRight className="w-5 h-5 text-slate-400" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-blue-400 uppercase font-semibold tracking-wider">New EPC Value</label>
                                <Input 
                                    value={newEpc}
                                    onChange={(e) => {
                                        setNewEpc(e.target.value.toUpperCase());
                                        setError('');
                                    }}
                                    error={error}
                                    className="font-mono text-lg py-3 border-slate-700 bg-slate-950 focus:border-blue-500"
                                    placeholder="Enter Hex Value..."
                                    disabled={writeStatus === 'pending' || writeStatus === 'success'}
                                    autoFocus
                                />
                                <div className="flex justify-between text-xs text-slate-500 px-1">
                                    <span>Hex Characters: {newEpc.length}</span>
                                    <span>Bits: {newEpc.length * 4}</span>
                                </div>
                            </div>
                         </div>

                         {/* Actions */}
                         <div className="flex items-center gap-4 pt-4 border-t border-slate-800">
                            <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'} size="lg">
                                Cancel
                            </Button>

                            {writeStatus !== 'success' && (
                                <Button 
                                    variant="primary" 
                                    onClick={validateAndWrite} 
                                    disabled={writeStatus === 'pending'}
                                    size="lg"
                                    className="flex-1"
                                >
                                    {writeStatus === 'pending' ? 'Writing Tag...' : 'Write New EPC'}
                                </Button>
                            )}
                         </div>

                         {/* Status Messages */}
                         {writeStatus === 'success' && (
                             <div className="bg-emerald-900/20 border border-emerald-800/50 rounded-lg p-4 flex items-center gap-3 animate-in fade-in zoom-in duration-300">
                                 <CheckCircle2 className="w-6 h-6 text-emerald-500" />
                                 <div>
                                     <p className="font-medium text-emerald-400">Write Successful!</p>
                                     <p className="text-sm text-emerald-200/70 mt-1">{writeMessage}</p>
                                 </div>
                                 <Button variant="outline" size="sm" onClick={handleBackToScan} className="ml-auto border-emerald-800 text-emerald-400 hover:bg-emerald-900/50">
                                     Write Another
                                 </Button>
                             </div>
                         )}

                         {writeStatus === 'error' && (
                             <div className="bg-red-900/20 border border-red-800/50 rounded-lg p-4 flex items-center gap-3 animate-in fade-in zoom-in duration-300">
                                 <XCircle className="w-6 h-6 text-red-500" />
                                 <div>
                                     <p className="font-medium text-red-400">Write Failed</p>
                                     <p className="text-sm text-red-200/70 mt-1">{writeMessage}</p>
                                 </div>
                             </div>
                         )}
                     </div>
                </div>
            )}
        </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutDashboard, ScrollText, FileOutput, Radio, Bluetooth, PenTool, ScanLine } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

// Define Main Application Views
type AppView = 'scanner' | 'writer';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs for Scanner View
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs for Performance ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Callbacks ---

  const handleDataReceived = useCallback((data: any) => {
    // 1. Handle Tag Data
    if (data.cmd === 'live_tag' && data.epc) {
        const now = Date.now();
        const newTag: Tag = {
          epc: data.epc,
          timestamp: now,
          rssi: data.rssi,
          count: 1
        };

        // Update Buffer
        const existing = tagBufferRef.current.get(newTag.epc);
        if (existing) {
            newTag.count = existing.count + 1;
        }
        tagBufferRef.current.set(newTag.epc, newTag);
        return;
    }

    // 2. Handle Settings Responses
    if (data.cmd === 'DI') {
        setSettings(prev => ({ ...prev, deviceInfo: data.val }));
        addLog(`Device Info: ${data.val}`, 'rx');
    }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));

    // 3. Handle Write EPC Response
    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Success! New EPC: ${data.epc}`);
        addLog(`Write Success: ${data.epc}`, 'info');
      } else {
        setWriteStatus('error');
        setWriteMessage('Write failed. Check device log.');
        addLog('Write Failed: Device returned error status.', 'error');
      }
    }

  }, [addLog]);

  // Handle File Transfer Events
  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') {
        setIsTransferring(true);
        setTransferProgress(0);
        setFileContent('');
        const sizeKB = (data?.total / 1024).toFixed(1);
        addLog(`File transfer started (${sizeKB} KB)...`, 'info');
    } else if (event === 'progress') {
        setTransferProgress(data); // data is percentage
    } else if (event === 'complete') {
        setIsTransferring(false);
        setTransferProgress(100);
        setFileContent(data); // data is file string
        addLog('File transfer completed successfully.', 'info');
    } else if (event === 'error') {
        setIsTransferring(false);
        setTransferProgress(-1);
        addLog(`File transfer error: ${data}`, 'error');
    }
  }, [addLog]);

  // --- Effects ---

  // Initialize BLE listeners
  useEffect(() => {
    bleService.setCallbacks(
        handleDataReceived,
        (msg, type) => addLog(msg, type),
        handleFileEvent
    );
  }, [handleDataReceived, addLog, handleFileEvent]);

  // Render Loop for Tags (throttled to 200ms)
  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 200 && tagBufferRef.current.size > 0) {
        // Convert Map values to array, sort by timestamp desc, take top 500
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        // Sort: newest first
        allTags.sort((a, b) => b.timestamp - a.timestamp);
        const displayTags = allTags.slice(0, 500);

        setTags(displayTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };

    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);


  // --- Actions ---

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);

      // Auto-fetch settings sequence after connection
      setTimeout(async () => {
         addLog('Fetching device settings...', 'tx');
         try {
            await bleService.getSettings();
         } catch(e) {
            addLog('Failed to fetch settings', 'error');
         }
      }, 500);

    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'S' });
      } else {
        // Batch
        setFileContent(''); // Clear previous batch results
        await bleService.sendCommand({ cmd: 'SB' });
      }
      setIsScanning(true);
      addLog(`Started ${scanMode} Scan`, 'info');
    } catch (e: any) {
      addLog(`Scan Start Failed: ${e.message}`, 'error');
    }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'X' });
      } else {
        // Batch
        await bleService.sendCommand({ cmd: 'XB' });
        // Auto trigger file transfer
        setTimeout(async () => {
             addLog('Requesting File Transfer...', 'tx');
             await bleService.requestFileTransfer();
        }, 500);
      }
      setIsScanning(false);
      addLog('Stopped Scan', 'info');
    } catch (e: any) {
      addLog(`Scan Stop Failed: ${e.message}`, 'error');
    }
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    // Optimistic update for App state
    setSettings(prev => ({ ...prev, [key]: value }));

    if (status !== ConnectionStatus.CONNECTED) return;

    try {
        let cmd = {};
        if (key === 'power') cmd = { cmd: 'SP', val: value };
        if (key === 'frequency') cmd = { cmd: 'SF', val: value };
        if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
        if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };

        await bleService.sendCommand(cmd);
        addLog(`Set ${key}: ${value}`, 'info');
    } catch(e: any) {
        addLog(`Settings Update Failed: ${e.message}`, 'error');
    }
  };

  const handleWriteEpc = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc) return;

    setWriteStatus('pending');
    setWriteMessage('');

    try {
        await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
        addLog(`Write Command Sent: ${oldEpc} -> ${newEpc}`, 'info');
    } catch (e: any) {
        setWriteStatus('error');
        setWriteMessage(e.message);
        addLog(`Write Failed: ${e.message}`, 'error');
    }
  };

  const handleClearLog = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  const handleViewSwitch = (view: AppView) => {
    if (view === activeView) return;

    // Safety: Stop scanning if active when switching views
    if (isScanning) {
        handleStopScan();
        // We continue to switch view immediately. The command queue in BLEService
        // ensures the Stop command goes out before any new commands in the new view.
    }
    setActiveView(view);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  return (
    <div className="fixed inset-0 flex flex-col bg-slate-950 text-slate-200 overflow-hidden">

      {/* --- Global Mobile/Tablet Header (< lg) --- */}
      <div className="lg:hidden flex items-center justify-between p-3 bg-slate-900 border-b border-slate-800 shrink-0 z-20">
        <div className="flex items-center gap-2 text-blue-400">
          <Radio className="w-5 h-5" />
          <h1 className="font-bold text-base text-slate-100">Nextwaves V3</h1>
        </div>

        <div className="flex items-center gap-3">
          {/* View Switcher for Mobile */}
          <div className="flex bg-slate-800 rounded-lg p-1">
             <button 
                onClick={() => handleViewSwitch('scanner')}
                className={`p-1.5 rounded-md ${activeView === 'scanner' ? 'bg-slate-700 text-white' : 'text-slate-400'}`}
             >
                <ScanLine className="w-4 h-4" />
             </button>
             <button 
                onClick={() => handleViewSwitch('writer')}
                className={`p-1.5 rounded-md ${activeView === 'writer' ? 'bg-slate-700 text-white' : 'text-slate-400'}`}
             >
                <PenTool className="w-4 h-4" />
             </button>
          </div>

          {/* Status Dot */}
          <div className={`w-2.5 h-2.5 rounded-full ${
            status === ConnectionStatus.CONNECTED ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 
            status === ConnectionStatus.ERROR ? 'bg-red-500' : 
            status === ConnectionStatus.CONNECTING ? 'bg-yellow-500 animate-pulse' : 'bg-slate-600'
          }`} title={status} />

          {isConnected ? (
             <Button variant="danger" size="sm" onClick={handleDisconnect} disabled={isScanning}>
               <Bluetooth className="w-3 h-3" />
             </Button>
          ) : (
             <Button variant="primary" size="sm" onClick={handleConnect} disabled={status === ConnectionStatus.CONNECTING}>
               <Bluetooth className="w-3 h-3" />
             </Button>
          )}
        </div>
      </div>

      {/* --- Main Content Area with Desktop Sidebar --- */}
      <div className="flex-1 flex overflow-hidden">

        {/* DESKTOP SIDEBAR NAV */}
        <nav className="hidden lg:flex flex-col w-20 bg-slate-950 border-r border-slate-800 items-center py-6 gap-6 shrink-0 z-20">
            <div className="text-blue-500 mb-2">
                <Radio className="w-8 h-8" />
            </div>

            <button 
                onClick={() => handleViewSwitch('scanner')}
                className={`flex flex-col items-center gap-1 p-3 rounded-xl transition-all ${activeView === 'scanner' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-slate-900'}`}
            >
                <ScanLine className="w-6 h-6" />
                <span className="text-[10px] font-medium">Scanner</span>
            </button>

            <button 
                onClick={() => handleViewSwitch('writer')}
                className={`flex flex-col items-center gap-1 p-3 rounded-xl transition-all ${activeView === 'writer' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-slate-900'}`}
            >
                <PenTool className="w-6 h-6" />
                <span className="text-[10px] font-medium">Writer</span>
            </button>
        </nav>

        {/* View Content */}
        <div className="flex-1 relative overflow-hidden flex flex-col">

            {/* VIEW 1: SCANNER */}
            {activeView === 'scanner' && (
                <div className="flex-1 flex flex-col lg:flex-row h-full">
                    {/* 1. Controls Wrapper */}
                    <div className={`
                    ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                    lg:flex flex-col h-full w-full lg:w-80 shrink-0 z-10 border-b lg:border-b-0 lg:border-r border-slate-800
                    `}>
                    <Controls 
                        status={status}
                        scanMode={scanMode}
                        isScanning={isScanning}
                        settings={settings}
                        onConnect={handleConnect}
                        onDisconnect={handleDisconnect}
                        onToggleMode={setScanMode}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        onUpdateSettings={handleUpdateSettings}
                        onWriteEpc={handleWriteEpc}
                        writeLoading={writeStatus === 'pending'}
                        selectedEpc={selectedEpc}
                    />
                    </div>

                    {/* 2. Middle Interactive Log Wrapper */}
                    <div className={`
                    ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                    lg:flex flex-col flex-1 h-full min-w-0
                    `}>
                    <InteractiveLog 
                        tags={tags}
                        onClear={handleClearLog}
                        onSelectEpc={setSelectedEpc}
                        logs={logs}
                    />
                    </div>

                    {/* 3. Right Batch Results Wrapper */}
                    <div className={`
                    ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                    lg:flex flex-col h-full w-full lg:w-80 shrink-0 border-t lg:border-t-0 lg:border-l border-slate-800
                    `}>
                    <BatchResults 
                        fileContent={fileContent}
                        isTransferring={isTransferring}
                        transferProgress={transferProgress} 
                    />
                    </div>
                </div>
            )}

            {/* VIEW 2: WRITER */}
            {activeView === 'writer' && (
                <WriterView 
                    onWrite={handleWriteEpc}
                    writeStatus={writeStatus}
                    writeMessage={writeMessage}
                    setWriteStatus={setWriteStatus}
                    onStartScan={handleStartScan}
                    onStopScan={handleStopScan}
                    isScanning={isScanning}
                    liveTags={tags}
                />
            )}

        </div>
      </div>

      {/* --- Mobile Bottom Nav (Only valid for Scanner View) --- */}
      {activeView === 'scanner' && (
        <div className="lg:hidden flex items-center justify-around bg-slate-900 border-t border-slate-800 h-16 shrink-0 z-50 safe-area-pb">
            <button 
            onClick={() => setMobileTab('controls')}
            className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'controls' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
            >
            <LayoutDashboard size={20} />
            <span className="text-[10px] font-medium">Controls</span>
            </button>

            <button 
            onClick={() => setMobileTab('logs')}
            className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'logs' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
            >
            <div className="relative">
                <ScrollText size={20} />
                {tags.length > 0 && <span className="absolute -top-1 -right-1 w-2 h-2 bg-emerald-500 rounded-full" />}
            </div>
            <span className="text-[10px] font-medium">Logs</span>
            </button>

            <button 
            onClick={() => setMobileTab('results')}
            className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'results' ? 'text-blue-400 bg-slate-800/50' : 'text-slate-500 hover:bg-slate-800/20'}`}
            >
            <FileOutput size={20} />
            <span className="text-[10px] font-medium">Batch</span>
            </button>
        </div>
      )}

    </div>
  );
}

