import React, { useState, useEffect } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, ScanLine, Zap, Info, Bell } from 'lucide-react';
import { Button } from './ui/Button';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  // Local state for basic settings
  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  // Local state for complex RF Params [speed, qv, session, target]
  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  // Sync basic state when props change (from device read)
  useEffect(() => {
    setLocalPower(settings.power);
  }, [settings.power]);

  useEffect(() => {
    setLocalFreq(settings.frequency);
  }, [settings.frequency]);

  useEffect(() => {
    setLocalBuzzer(settings.buzzer);
  }, [settings.buzzer]);

  // Parse RF Params String (e.g. "1,4,1,0") into local state
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) {
        setRfSpeed(parts[0]);
        setRfQv(parts[1]);
        setRfSession(parts[2]);
        setRfTarget(parts[3]);
      }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;

  // Dirty Checks
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isBuzzerDirty = localBuzzer !== settings.buzzer;

  // Construct current RF string to check dirty state
  const currentRfString = `${rfSpeed},${rfQv},${rfSession},${rfTarget}`;
  const isRfDirty = currentRfString !== settings.rfParams;

  const handleSetRfParams = () => {
    onUpdateSettings('rfParams', currentRfString);
  };

  return (
    <div className="flex flex-col h-full bg-slate-900 p-4 overflow-y-auto w-full gap-6">

      {/* Header / Connection */}
      <div className="hidden lg:block space-y-4">
        <div className="flex items-center gap-2 text-blue-400 mb-2">
          <Radio className="w-6 h-6" />
          <h1 className="font-bold text-lg text-slate-100">Nextwaves V3</h1>
        </div>

        {isConnected && settings.deviceInfo && (
          <div className="bg-slate-800/50 p-2 rounded border border-slate-700 mb-2 flex items-center gap-2">
            <Info className="w-4 h-4 text-blue-400" />
            <span className="text-xs text-slate-300 font-mono truncate">{settings.deviceInfo}</span>
          </div>
        )}

        {isConnected ? (
          <Button variant="danger" fullWidth onClick={onDisconnect} disabled={isScanning}>
            <Bluetooth className="w-4 h-4 mr-2" />
            Disconnect
          </Button>
        ) : (
          <Button variant="primary" fullWidth onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING}>
            <Bluetooth className="w-4 h-4 mr-2" />
            {status === ConnectionStatus.CONNECTING ? 'Connecting...' : 'Connect Scanner'}
          </Button>
        )}

        <div className="flex items-center justify-between text-xs px-1">
          <span className="text-slate-500">Status</span>
          <span className={`font-medium ${
            status === ConnectionStatus.CONNECTED ? 'text-emerald-400' : 
            status === ConnectionStatus.ERROR ? 'text-red-400' : 'text-slate-400'
          }`}>
            {status}
          </span>
        </div>
        <div className="h-px bg-slate-800" />
      </div>

      {/* Scan Controls */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <ScanLine className="w-4 h-4" />
          <h2>Scanning</h2>
        </div>

        <div className="bg-slate-800 p-1 rounded-lg flex text-xs">
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.INTERACTIVE ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
            disabled={isScanning}
          >
            Interactive
          </button>
          <button
            className={`flex-1 py-1.5 rounded-md transition-colors ${scanMode === ScanMode.BATCH ? 'bg-blue-600 text-white shadow-sm' : 'text-slate-400 hover:text-slate-200'}`}
            onClick={() => onToggleMode(ScanMode.BATCH)}
            disabled={isScanning}
          >
            Batch
          </button>
        </div>

        {isScanning ? (
          <Button variant="danger" fullWidth onClick={onStopScan} disabled={!isConnected}>
            Stop Scan
          </Button>
        ) : (
          <Button variant="success" fullWidth onClick={onStartScan} disabled={!isConnected}>
            Start Scan
          </Button>
        )}
      </div>

      <div className="h-px bg-slate-800" />

      {/* Settings */}
      <div className="space-y-6 flex-1">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <SettingsIcon className="w-4 h-4" />
          <h2>Settings</h2>
        </div>

        {/* Tx Power */}
        <div>
          <label className="flex justify-between text-xs text-slate-400 mb-2">
            <span>Tx Power</span>
            <span className={isPowerDirty ? "text-amber-400 font-medium" : "text-slate-400"}>
              {localPower} dBm
            </span>
          </label>
          <div className="flex items-center gap-3">
            <input 
              type="range" 
              min="0" 
              max="33" 
              value={localPower}
              onChange={(e) => setLocalPower(parseInt(e.target.value))}
              disabled={!isConnected || isScanning}
              className="flex-1 h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
            <Button 
              size="sm" 
              variant={isPowerDirty ? 'primary' : 'outline'}
              className={!isPowerDirty ? "border-slate-700 text-slate-500" : ""}
              disabled={!isConnected || isScanning || !isPowerDirty}
              onClick={() => onUpdateSettings('power', localPower)}
            >
              Set
            </Button>
          </div>
        </div>

        {/* Region */}
        <div className="space-y-2">
            <label className="text-xs text-slate-400">Region</label>
            <div className="flex gap-2">
              <select 
                className="flex-1 bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-md p-2 focus:ring-1 focus:ring-blue-500 focus:outline-none"
                value={localFreq}
                onChange={(e) => setLocalFreq(e.target.value)}
                disabled={!isConnected || isScanning}
              >
                <option value="US">US (902-928 MHz)</option>
                <option value="EU">EU (865-868 MHz)</option>
                <option value="CN">CN (920-925 MHz)</option>
                <option value="VN">VN (918-923 MHz)</option>
              </select>
              <Button 
                size="sm" 
                variant={isFreqDirty ? 'primary' : 'outline'}
                className={!isFreqDirty ? "border-slate-700 text-slate-500" : ""}
                disabled={!isConnected || isScanning || !isFreqDirty}
                onClick={() => onUpdateSettings('frequency', localFreq)}
              >
                Set
              </Button>
            </div>
        </div>

        {/* Buzzer */}
        <div className="flex items-center justify-between">
             <div className="flex items-center gap-2 text-slate-400 text-xs">
                 <Bell className="w-3 h-3" />
                 <span>Buzzer</span>
             </div>
             <div className="flex items-center gap-2">
                 <button 
                     className={`w-10 h-5 rounded-full relative transition-colors ${localBuzzer ? 'bg-blue-600' : 'bg-slate-700'}`}
                     onClick={() => setLocalBuzzer(!localBuzzer)}
                     disabled={!isConnected || isScanning}
                 >
                     <div className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full transition-transform ${localBuzzer ? 'translate-x-5' : 'translate-x-0'}`} />
                 </button>
                 <Button 
                    size="sm" 
                    variant={isBuzzerDirty ? 'primary' : 'outline'}
                    className={`px-2 py-0.5 text-xs h-6 ${!isBuzzerDirty ? "border-slate-700 text-slate-500" : ""}`}
                    disabled={!isConnected || isScanning || !isBuzzerDirty}
                    onClick={() => onUpdateSettings('buzzer', localBuzzer)}
                  >
                    Set
                  </Button>
             </div>
        </div>

        {/* Complex RF Params */}
        <div className="space-y-3 pt-2 border-t border-slate-800">
           <div className="flex items-center justify-between">
                <label className="text-xs text-slate-400 flex items-center gap-1">
                    <Zap className="w-3 h-3" /> RF Parameters
                </label>
                <Button 
                    size="sm" 
                    variant={isRfDirty ? 'primary' : 'outline'}
                    className={!isRfDirty ? "border-slate-700 text-slate-500" : ""}
                    disabled={!isConnected || isScanning || !isRfDirty}
                    onClick={handleSetRfParams}
                >
                    Set RF
                </Button>
           </div>

           <div className="grid grid-cols-2 gap-2">
               {/* EPC Speed */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Mode / Speed</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfSpeed}
                       onChange={(e) => setRfSpeed(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>Tari 25us / FM0 / 40K</option>
                       <option value={1}>Tari 25us / M4 / 250K</option>
                       <option value={2}>Tari 25us / M4 / 300K</option>
                       <option value={3}>Tari 6.25us / FM0 / 400K</option>
                   </select>
               </div>

               {/* Q Value */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Q Value ({rfQv})</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfQv}
                       onChange={(e) => setRfQv(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       {[...Array(16)].map((_, i) => (
                           <option key={i} value={i}>{i}</option>
                       ))}
                   </select>
               </div>

               {/* Session */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Session</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfSession}
                       onChange={(e) => setRfSession(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>S0</option>
                       <option value={1}>S1</option>
                       <option value={2}>S2</option>
                       <option value={3}>S3</option>
                   </select>
               </div>

                {/* Target */}
               <div className="space-y-1">
                   <label className="text-[10px] text-slate-500">Target</label>
                   <select 
                       className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs rounded-md p-1.5 focus:outline-none"
                       value={rfTarget}
                       onChange={(e) => setRfTarget(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>A</option>
                       <option value={1}>B</option>
                       <option value={2}>A & B</option>
                   </select>
               </div>
           </div>
        </div>

      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Tag, LogEntry } from '../types';
import { Trash2, Terminal } from 'lucide-react';

interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export const InteractiveLog: React.FC<InteractiveLogProps> = ({ tags, onClear, onSelectEpc, logs }) => {
  const logEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logs
  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  return (
    <div className="flex-1 flex flex-col h-full bg-slate-950 border-r border-slate-800 min-w-0 md:min-w-[300px]">

      {/* Top Panel: Live Tags */}
      <div className="flex-1 flex flex-col min-h-0">
        <div className="flex items-center justify-between p-4 border-b border-slate-800 bg-slate-900/50 shrink-0">
          <div className="flex items-center gap-2">
            <span className="font-semibold text-slate-200">Live Tags</span>
            <span className="bg-blue-900/50 text-blue-400 text-xs px-2 py-0.5 rounded-full border border-blue-800">
              {tags.length}
            </span>
          </div>
          <button 
            onClick={onClear}
            className="text-slate-400 hover:text-red-400 transition-colors p-1"
            title="Clear List"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>

        {/* Table Header */}
        <div className="flex items-center px-4 py-2 bg-slate-900 border-b border-slate-800 text-xs font-semibold text-slate-400 uppercase tracking-wider shrink-0">
            <div className="w-8 text-center shrink-0">#</div>
            <div className="flex-1 px-3">EPC</div>
            <div className="w-16 text-center shrink-0">Count</div>
            <div className="w-16 text-center shrink-0">RSSI</div>
        </div>

        {/* Table Body */}
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-slate-950">
          {tags.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-600 text-sm">
              <p>No tags scanned yet.</p>
              <p className="text-xs mt-1 opacity-70">Start a scan to see data.</p>
            </div>
          ) : (
            <div className="divide-y divide-slate-800/50">
                {tags.map((tag, idx) => (
                <div 
                    key={`${tag.epc}-${idx}`}
                    onClick={() => onSelectEpc(tag.epc)}
                    className="flex items-center px-4 py-2 hover:bg-slate-900 transition-colors cursor-pointer group"
                >
                    <div className="w-8 text-center shrink-0 text-slate-500 text-xs">{idx + 1}</div>
                    <div className="flex-1 px-3 font-mono text-emerald-400 font-medium truncate text-sm group-hover:text-emerald-300" title={tag.epc}>
                        {tag.epc}
                    </div>
                    <div className="w-16 text-center shrink-0">
                        <span className="bg-slate-800 text-slate-300 px-1.5 py-0.5 rounded text-xs font-mono border border-slate-700">{tag.count}</span>
                    </div>
                    <div className="w-16 text-center shrink-0 text-slate-500 text-xs">
                        N/A
                    </div>
                </div>
                ))}
            </div>
          )}
        </div>
      </div>

      {/* Bottom Panel: System Logs */}
      <div className="h-1/3 border-t border-slate-800 flex flex-col bg-black">
        <div className="flex items-center gap-2 px-4 py-2 bg-slate-900 border-b border-slate-800 text-xs font-mono text-slate-400 shrink-0">
          <Terminal className="w-3 h-3" />
          <span>System Log</span>
        </div>
        <div className="flex-1 overflow-y-auto p-2 font-mono text-xs space-y-1">
          {logs.map((log, i) => (
            <div key={i} className="flex gap-2">
              <span className="text-slate-600 shrink-0 select-none">
                {new Date(log.timestamp).toLocaleTimeString([], {hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit'})}
              </span>
              <span className={`break-all ${
                log.type === 'error' ? 'text-red-400' :
                log.type === 'tx' ? 'text-cyan-600' :
                log.type === 'rx' ? 'text-emerald-600' :
                'text-slate-300'
              }`}>
                {log.type === 'tx' && '> '}
                {log.type === 'rx' && '< '}
                {log.message}
              </span>
            </div>
          ))}
          <div ref={logEndRef} />
        </div>
      </div>
    </div>
  );
};

