          </div>
        )}
      </div>

      <div className="text-xs text-slate-500 text-center">
        Batch data is transferred over characteristic 0xFF03
      </div>
    </div>
  );
};

import React from 'react';
import { Download, FileDown, RefreshCw, Share2 } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring,
  onRequestFile
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    if (!fileContent) return;

    try {
      const fileName = `scan_batch_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.txt`;
      const file = new File([fileContent], fileName, { type: 'text/plain' });

      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Batch Scan Results',
          text: 'Attached RFID scan results.',
        });
      } else {
        // Fallback for browsers that support text share but not file share, or neither
        if (navigator.share) {
             await navigator.share({
                title: 'Batch Scan Results',
                text: fileContent
             });
        } else {
             alert('Sharing is not supported on this device/browser. Please use "Save .txt"');
        }
      }
    } catch (error) {
      console.log('Share canceled or failed', error);
    }
  };

  const hasContent = !!fileContent && !isTransferring;
  // Check if browser supports sharing (basic check)
  const canShare = typeof navigator !== 'undefined' && !!navigator.share;

  return (
    <div className="w-full flex flex-col h-full bg-slate-950 p-4 gap-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <FileDown className="w-5 h-5 text-purple-400" />
          <h2>Batch Results</h2>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={onRequestFile}
                disabled={isTransferring}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white rounded text-xs border border-slate-700 transition-colors disabled:opacity-50"
            >
                <RefreshCw className={`w-3.5 h-3.5 ${isTransferring ? 'animate-spin' : ''}`} />
                Get Data
            </button>

            {hasContent && (
              <>
                <button 
                    onClick={handleDownload}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-blue-400 hover:text-blue-300 rounded text-xs border border-slate-700 transition-colors"
                    title="Download to Device"
                >
                    <Download className="w-3.5 h-3.5" />
                    Save .txt
                </button>

                {canShare && (
                    <button 
                        onClick={handleShare}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs transition-colors shadow-sm"
                        title="Share to Zalo, Drive, etc."
                    >
                        <Share2 className="w-3.5 h-3.5" />
                        Share
                    </button>
                )}
              </>
            )}
        </div>
      </div>

      <div className="flex-1 bg-slate-900 rounded-lg border border-slate-800 overflow-hidden relative flex flex-col">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-10 p-8 text-center">
            <RefreshCw className="w-10 h-10 text-blue-500 animate-spin mb-4" />
            <h3 className="text-slate-200 font-medium">Transferring File...</h3>
            {transferProgress >= 0 && (
                <p className="text-slate-400 text-sm mt-2">{transferProgress}%</p>
            )}
            <p className="text-slate-500 text-xs mt-4">Please wait while data is retrieved from the scanner.</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-600 p-8 text-center">
            <p className="mb-2">No batch data available.</p>
            <p className="text-xs max-w-xs">Run a Batch Scan then press "Get Data" to retrieve results.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar">
            <pre className="font-mono text-xs text-slate-300 whitespace-pre-wrap break-all leading-relaxed">
              {fileContent}
            </pre>
          </div>
        )}
      </div>

      <div className="text-xs text-slate-500 text-center">
        Batch data is transferred over characteristic 0xFF03
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutDashboard, ScrollText, FileOutput, Radio, Bluetooth, Binary, ScanLine } from 'lucide-react';
