import React, { useState, useEffect } from 'react';
import { ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search, Binary, Database } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriterViewProps {
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;
  setWriteStatus: (status: WriteStatus) => void;

  // Scanning props
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriterView: React.FC<WriterViewProps> = ({
  onWrite,
  writeStatus,
  writeMessage,
  setWriteStatus,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  // When a user selects a tag in Step 1
  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); // Pre-fill with current for easy editing
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    setWriteStatus('idle');
  };

  const validateAndWrite = () => {
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('New EPC must contain only Hex characters (0-9, A-F).');
      return;
    }
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`Length must be a multiple of 4 characters (16 bits). Current: ${newEpc.length}`);
        return;
    }

    setError('');
    onWrite(targetEpc, newEpc);
  };

  return (
    <div className="w-full h-full flex flex-col bg-slate-950 p-4 lg:p-8 overflow-y-auto">
        <div className="max-w-3xl mx-auto w-full flex flex-col gap-6">

            {/* Header */}
            <div className="flex items-center gap-3 pb-4 border-b border-slate-800">
                <div className="p-2 bg-blue-500/10 rounded-lg">
                    <Binary className="w-6 h-6 text-blue-400" />
                </div>
                <div>
                    <h1 className="text-xl font-bold text-slate-100">Tag Encode</h1>
                    <p className="text-slate-400 text-sm">Program the EPC Memory Bank (Bank 1) of Gen2 UHF RFID tags.</p>
                </div>
            </div>

            {/* Warning */}
            <div className="bg-amber-900/20 border border-amber-800/50 rounded-lg p-4 flex items-start gap-3">
                <AlertTriangle className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
                <div className="space-y-1">
                    <p className="text-sm font-medium text-amber-200">Proximity Check</p>
                    <p className="text-xs text-amber-200/70 leading-relaxed">
                        RFID is a broadcast technology. Ensure <strong>only ONE tag</strong> is near the antenna field when encoding. 
                        Programming in a multi-tag environment may result in overwriting the wrong tag.
                    </p>
                </div>
            </div>

            {/* Step 1: Scan & Select */}
            {step === 1 && (
                <div className="flex flex-col gap-4 animate-in slide-in-from-right-4 duration-300">
                    <div className="flex items-center justify-between bg-slate-900 p-4 rounded-lg border border-slate-800">
                        <div className="flex items-center gap-3">
                             <div className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 text-slate-300 font-bold border border-slate-700">1</div>
                             <div>
                                 <h3 className="text-slate-200 font-medium">Select Target Tag</h3>
                                 <p className="text-xs text-slate-500">Inventory nearby tags and select the EPC to program.</p>
                             </div>
                        </div>
                        {isScanning ? (
                            <Button size="sm" variant="danger" onClick={onStopScan} className="min-w-[100px]">Stop Scan</Button>
                        ) : (
                            <Button size="sm" variant="success" onClick={onStartScan} className="min-w-[100px]">Start Scan</Button>
                        )}
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-lg min-h-[300px] flex-1 overflow-hidden flex flex-col">
                        <div className="bg-slate-800/50 px-4 py-2 border-b border-slate-700/50 text-xs font-medium text-slate-400 flex justify-between">
                            <span>Detected Tags</span>
                            <span>{liveTags.length} found</span>
                        </div>
                        <div className="flex-1 overflow-y-auto relative custom-scrollbar">
                            {liveTags.length === 0 ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 gap-3">
                                    <Radio className={`w-10 h-10 ${isScanning ? 'animate-pulse text-blue-500' : 'text-slate-700'}`} />
                                    <p className="text-sm">{isScanning ? 'Scanning...' : 'Press "Start Scan" to begin'}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-slate-800">
                                    {liveTags.map((tag, idx) => (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectTag(tag.epc)}
                                            className="w-full flex items-center justify-between p-4 hover:bg-slate-800 transition-colors group text-left"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
                                                <div>
                                                    <p className="font-mono text-emerald-400 font-medium group-hover:text-emerald-300 transition-colors text-base">{tag.epc}</p>
                                                    <p className="text-xs text-slate-500 mt-0.5">RSSI: {tag.rssi} dBm &bull; Reads: {tag.count}</p>
                                                </div>
                                            </div>
                                            <div className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-2 group-hover:translate-x-0 duration-200">
                                                <span className="text-xs bg-blue-600 text-white px-3 py-1.5 rounded-md font-medium">Select & Encode</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Step 2: Write */}
            {step === 2 && (
                <div className="flex flex-col gap-6 animate-in slide-in-from-right-4 duration-300">
                     <div className="flex items-center gap-3">
                         <div className="flex items-center justify-center w-8 h-8 rounded-full bg-slate-800 text-slate-300 font-bold border border-slate-700">2</div>
                         <h3 className="text-slate-200 font-medium">Enter New EPC Data</h3>
                     </div>

                     <div className="bg-slate-900 border border-slate-800 rounded-lg p-6 space-y-8">

                         {/* Old vs New Comparison */}
                         <div className="grid gap-6">
                            <div className="space-y-2">
                                <label className="text-xs text-slate-500 uppercase font-semibold tracking-wider">Current EPC (Target)</label>
                                <div className="bg-slate-950 border border-slate-800 rounded-md p-3 flex items-center gap-3">
                                    <Database className="w-4 h-4 text-slate-500" />
                                    <span className="font-mono text-slate-400 text-lg">{targetEpc}</span>
                                </div>
                            </div>

                            <div className="flex justify-center">
                                <div className="bg-slate-800 p-2 rounded-full">
                                    <ArrowRight className="w-5 h-5 text-slate-400" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs text-blue-400 uppercase font-semibold tracking-wider">New EPC Value</label>
                                <Input 
                                    value={newEpc}
                                    onChange={(e) => {
                                        setNewEpc(e.target.value.toUpperCase());
                                        setError('');
                                    }}
                                    error={error}
                                    className="font-mono text-lg py-3 border-slate-700 bg-slate-950 focus:border-blue-500"
                                    placeholder="Enter Hex Value..."
                                    disabled={writeStatus === 'pending' || writeStatus === 'success'}
                                    autoFocus
                                />
                                <div className="flex justify-between text-xs text-slate-500 px-1">
                                    <span>Hex Characters: {newEpc.length}</span>
                                    <span>Bits: {newEpc.length * 4}</span>
                                </div>
                            </div>
                         </div>

                         {/* Actions */}
                         <div className="flex items-center gap-4 pt-4 border-t border-slate-800">
                            <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'} size="lg">
                                Cancel
                            </Button>

                            {writeStatus !== 'success' && (
                                <Button 
                                    variant="primary" 
                                    onClick={validateAndWrite} 
                                    disabled={writeStatus === 'pending'}
                                    size="lg"
                                    className="flex-1"
                                >
                                    {writeStatus === 'pending' ? 'Encoding Tag...' : 'Encode Tag'}
                                </Button>
                            )}
                         </div>

                         {/* Status Messages */}
                         {writeStatus === 'success' && (
                             <div className="bg-emerald-900/20 border border-emerald-800/50 rounded-lg p-4 flex items-center gap-3 animate-in fade-in zoom-in duration-300">
                                 <CheckCircle2 className="w-6 h-6 text-emerald-500" />
                                 <div>
                                     <p className="font-medium text-emerald-400">Encoding Successful!</p>
                                     <p className="text-sm text-emerald-200/70 mt-1">{writeMessage}</p>
                                 </div>
                                 <Button variant="outline" size="sm" onClick={handleBackToScan} className="ml-auto border-emerald-800 text-emerald-400 hover:bg-emerald-900/50">
                                     Encode Another
                                 </Button>
                             </div>
                         )}

                         {writeStatus === 'error' && (
                             <div className="bg-red-900/20 border border-red-800/50 rounded-lg p-4 flex items-center gap-3 animate-in fade-in zoom-in duration-300">
                                 <XCircle className="w-6 h-6 text-red-500" />
                                 <div>
                                     <p className="font-medium text-red-400">Encoding Failed</p>
                                     <p className="text-sm text-red-200/70 mt-1">{writeMessage}</p>
                                 </div>
                             </div>
                         )}
                     </div>
                </div>
            )}
        </div>
    </div>
  );
};

import React from 'react';
import { Download, FileDown, RefreshCw, Share2 } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring,
  onRequestFile
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    if (!fileContent) return;

    try {
      const fileName = `scan_batch_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.txt`;
      const file = new File([fileContent], fileName, { type: 'text/plain' });

      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Batch Scan Results',
          text: 'Attached RFID scan results.',
        });
      } else {
        // Fallback for browsers that support text share but not file share, or neither
        if (navigator.share) {
             await navigator.share({
                title: 'Batch Scan Results',
                text: fileContent
             });
        } else {
             alert('Sharing is not supported on this device/browser. Please use "Save .txt"');
        }
      }
    } catch (error) {
      console.log('Share canceled or failed', error);
    }
  };

  const hasContent = !!fileContent && !isTransferring;
  // Check if browser supports sharing (basic check)
  const canShare = typeof navigator !== 'undefined' && !!navigator.share;

  return (
    <div className="w-full flex flex-col h-full bg-slate-950 p-4 gap-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
        <div className="flex items-center gap-2 text-slate-100 font-semibold">
          <FileDown className="w-5 h-5 text-purple-400" />
          <h2>Batch Results</h2>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={onRequestFile}
                disabled={isTransferring}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white rounded text-xs border border-slate-700 transition-colors disabled:opacity-50"
            >
                <RefreshCw className={`w-3.5 h-3.5 ${isTransferring ? 'animate-spin' : ''}`} />
                Get Data
            </button>

            {hasContent && (
              <>
                <button 
                    onClick={handleDownload}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-blue-400 hover:text-blue-300 rounded text-xs border border-slate-700 transition-colors"
                    title="Download to Device"
                >
                    <Download className="w-3.5 h-3.5" />
                    Save .txt
                </button>

                {canShare && (
                    <button 
                        onClick={handleShare}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 hover:bg-blue-500 text-white rounded text-xs transition-colors shadow-sm"
                        title="Share to Zalo, Drive, etc."
                    >
                        <Share2 className="w-3.5 h-3.5" />
                        Share
                    </button>
                )}
              </>
            )}
        </div>
      </div>

      <div className="flex-1 bg-slate-900 rounded-lg border border-slate-800 overflow-hidden relative flex flex-col">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900/90 z-10 p-8 text-center">
            <RefreshCw className="w-10 h-10 text-blue-500 animate-spin mb-4" />
            <h3 className="text-slate-200 font-medium">Transferring File...</h3>
            {transferProgress >= 0 && (
                <p className="text-slate-400 text-sm mt-2">{transferProgress}%</p>
            )}
            <p className="text-slate-500 text-xs mt-4">Please wait while data is retrieved from the scanner.</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-600 p-8 text-center">
            <p className="mb-2">No batch data available.</p>
            <p className="text-xs max-w-xs">Run a Batch Scan then press "Get Data" to retrieve results.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar">
            <pre className="font-mono text-xs text-slate-300 whitespace-pre-wrap break-all leading-relaxed">
              {fileContent}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded font-medium transition-all duration-200 focus:outline-none focus:ring-1 focus:ring-offset-1 focus:ring-offset-black disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-wider';

  const variants = {
    primary: 'bg-gradient-to-r from-cyan-600 to-blue-600 text-white hover:from-cyan-500 hover:to-blue-500 hover:shadow-[0_0_15px_rgba(6,182,212,0.4)] border border-cyan-500/30',
    secondary: 'bg-slate-800/80 text-slate-300 hover:bg-slate-700 hover:text-white border border-slate-700',
    danger: 'bg-gradient-to-r from-red-600 to-orange-600 text-white hover:from-red-500 hover:to-orange-500 hover:shadow-[0_0_15px_rgba(239,68,68,0.4)] border border-red-500/30',
    success: 'bg-gradient-to-r from-emerald-600 to-green-600 text-white hover:from-emerald-500 hover:to-green-500 hover:shadow-[0_0_15px_rgba(16,185,129,0.4)] border border-emerald-500/30',
    outline: 'border border-slate-600 text-cyan-400 hover:bg-cyan-950/30 hover:border-cyan-500/50 hover:text-cyan-300 bg-transparent'
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-[10px]',
    md: 'px-4 py-2 text-xs',
    lg: 'px-6 py-3 text-sm'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
