import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

// Define Main Application Views
type AppView = 'scanner' | 'writer';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs for Scanner View
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs for Performance ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Callbacks ---

  const handleDataReceived = useCallback((data: any) => {
    // 1. Handle Tag Data
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);

        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = {
              epc: data.epc,
              timestamp: Date.now(),
              rssi: data.rssi,
              count: 1
            };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }

    // 2. Handle Settings Responses
    if (data.cmd === 'DI') {
        setSettings(prev => ({ ...prev, deviceInfo: data.val }));
        addLog(`Device Info: ${data.val}`, 'rx');
    }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));

    // 3. Handle Write EPC Response
    if (data.cmd === 'WE') {
      if (data.status === 'ok') {
        setWriteStatus('success');
        setWriteMessage(`Encoded: ${data.epc}`);
        addLog(`Encode Success: ${data.epc}`, 'info');
      } else {
        setWriteStatus('error');
        setWriteMessage('Encoding failed. Check log.');
        addLog('Encode Failed: Device returned error status.', 'error');
      }
    }

  }, [addLog]);

  // Handle File Transfer Events
  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') {
        setIsTransferring(true);
        setTransferProgress(0);
        setFileContent('');
        const sizeKB = (data?.total / 1024).toFixed(1);
        addLog(`File transfer started (${sizeKB} KB)...`, 'info');
    } else if (event === 'progress') {
        setTransferProgress(data);
    } else if (event === 'complete') {
        setIsTransferring(false);
        setTransferProgress(100);
        setFileContent(data);
        addLog('File transfer completed successfully.', 'info');
    } else if (event === 'error') {
        setIsTransferring(false);
        setTransferProgress(-1);
        addLog(`File transfer error: ${data}`, 'error');
    }
  }, [addLog]);

  // --- Effects ---

  useEffect(() => {
    bleService.setCallbacks(
        handleDataReceived,
        (msg, type) => addLog(msg, type),
        handleFileEvent
    );
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 200 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        const displayTags = allTags.slice(0, 500);
        setTags(displayTags);
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };

    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => {
        if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, []);

  // --- Actions ---

  const handleConnect = async () => {
    try {
      setStatus(ConnectionStatus.CONNECTING);
      await bleService.connect();
      setStatus(ConnectionStatus.CONNECTED);
      setTimeout(async () => {
         addLog('Fetching configuration...', 'tx');
         try {
            await bleService.getSettings();
         } catch(e) {
            addLog('Failed to fetch settings', 'error');
         }
      }, 500);
    } catch (e) {
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const handleDisconnect = () => {
    bleService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
    setIsScanning(false);
  };

  const handleStartScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'S' });
      } else {
        setFileContent('');
        await bleService.sendCommand({ cmd: 'SB' });
      }
      setIsScanning(true);
      addLog(`Started ${scanMode} Scan`, 'info');
    } catch (e: any) {
      addLog(`Scan Start Failed: ${e.message}`, 'error');
    }
  };

  const handleStopScan = async () => {
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
      if (scanMode === ScanMode.INTERACTIVE) {
        await bleService.sendCommand({ cmd: 'X' });
      } else {
        await bleService.sendCommand({ cmd: 'XB' });
        setTimeout(async () => {
             addLog('Requesting File Transfer...', 'tx');
             await bleService.requestFileTransfer();
        }, 500);
      }
      setIsScanning(false);
      addLog('Stopped Scan', 'info');
    } catch (e: any) {
      addLog(`Scan Stop Failed: ${e.message}`, 'error');
    }
  };

  const handleRequestBatchFile = async () => {
    if (status !== ConnectionStatus.CONNECTED) {
        addLog('Device not connected', 'error');
        return;
    }
    if (isTransferring) return;
    try {
        setFileContent(''); 
        addLog('Manual File Transfer Requested...', 'tx');
        await bleService.requestFileTransfer();
    } catch (e: any) {
        addLog(`Request Failed: ${e.message}`, 'error');
    }
  };

  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    try {
        let cmd = {};
        if (key === 'power') cmd = { cmd: 'SP', val: value };
        if (key === 'frequency') cmd = { cmd: 'SF', val: value };
        if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
        if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
        await bleService.sendCommand(cmd);
        addLog(`Set ${key}: ${value}`, 'info');
    } catch(e: any) {
        addLog(`Settings Update Failed: ${e.message}`, 'error');
    }
  };

  const handleWriteEpc = async (oldEpc: string, newEpc: string) => {
    if (!oldEpc || !newEpc) return;
    setWriteStatus('pending');
    setWriteMessage('');
    try {
        await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc });
        addLog(`Encode Command Sent: ${oldEpc} -> ${newEpc}`, 'info');
    } catch (e: any) {
        setWriteStatus('error');
        setWriteMessage(e.message);
        addLog(`Encode Failed: ${e.message}`, 'error');
    }
  };

  const handleClearLog = () => {
    tagBufferRef.current.clear();
    setTags([]);
  };

  const handleViewSwitch = (view: AppView) => {
    if (view === activeView) return;
    if (isScanning) {
        handleStopScan();
    }
    setActiveView(view);
  };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // Render Logo Text Component
  const Logo = () => (
    <div className="flex items-center gap-2 group cursor-default">
        <div className="relative w-7 h-7 flex items-center justify-center">
            <div className="absolute inset-0 bg-cyan-500 rounded-full blur opacity-20 group-hover:opacity-40 transition-opacity"></div>
            <Globe className="w-6 h-6 text-cyan-400 relative z-10" strokeWidth={1.5} />
            <div className="absolute w-full h-0.5 bg-cyan-400 top-1/2 left-0 -rotate-12 group-hover:rotate-0 transition-transform duration-500"></div>
            <div className="absolute w-full h-0.5 bg-cyan-400 top-1/2 left-0 rotate-12 group-hover:rotate-0 transition-transform duration-500"></div>
        </div>
        <div className="flex flex-col leading-none">
            <h1 className="font-bold text-lg text-white tracking-wide font-sans">
                Next<span className="text-cyan-400">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex flex-col overflow-hidden text-slate-200">

      {/* --- Mobile Header --- */}
      <div className="lg:hidden flex items-center justify-between p-3 glass-panel border-b-0 shrink-0 z-20">
        <Logo />
        <div className="flex items-center gap-3">
          <div className="flex bg-slate-900/50 rounded p-1 border border-slate-700/50">
             <button 
                onClick={() => handleViewSwitch('scanner')}
                className={`p-1.5 rounded ${activeView === 'scanner' ? 'bg-cyan-600/20 text-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.2)]' : 'text-slate-500'}`}
             >
                <ScanLine className="w-4 h-4" />
             </button>
             <button 
                onClick={() => handleViewSwitch('writer')}
                className={`p-1.5 rounded ${activeView === 'writer' ? 'bg-cyan-600/20 text-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.2)]' : 'text-slate-500'}`}
             >
                <Binary className="w-4 h-4" />
             </button>
          </div>
          <div className={`w-2 h-2 rounded-full ${
            status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 shadow-[0_0_10px_#22d3ee]' : 
            status === ConnectionStatus.ERROR ? 'bg-red-500' : 
            status === ConnectionStatus.CONNECTING ? 'bg-amber-400 animate-pulse' : 'bg-slate-700'
          }`} />
          <Button variant={isConnected ? "danger" : "primary"} size="sm" onClick={isConnected ? handleDisconnect : handleConnect} disabled={isScanning}>
             <Bluetooth className="w-3 h-3" />
          </Button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">

        {/* DESKTOP SIDEBAR */}
        <nav className="hidden lg:flex flex-col w-24 glass-panel border-r border-slate-700/30 items-center py-6 gap-8 shrink-0 z-20">
            <div className="mb-2 hover:scale-105 transition-transform duration-300">
                <div className="relative w-10 h-10 flex items-center justify-center bg-cyan-950/30 rounded-full border border-cyan-500/20">
                    <Globe className="w-6 h-6 text-cyan-400" />
                </div>
            </div>

            <div className="flex flex-col gap-4 w-full px-2">
                <button 
                    onClick={() => handleViewSwitch('scanner')}
                    className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 group ${activeView === 'scanner' ? 'bg-cyan-900/20 border border-cyan-500/30 text-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.15)]' : 'text-slate-500 hover:text-cyan-200 hover:bg-slate-800/50'}`}
                >
                    <ScanLine className="w-6 h-6" />
                    <span className="text-[9px] font-bold uppercase tracking-wider">Scanner</span>
                </button>

                <button 
                    onClick={() => handleViewSwitch('writer')}
                    className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 group ${activeView === 'writer' ? 'bg-cyan-900/20 border border-cyan-500/30 text-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.15)]' : 'text-slate-500 hover:text-cyan-200 hover:bg-slate-800/50'}`}
                >
                    <Binary className="w-6 h-6" />
                    <span className="text-[9px] font-bold uppercase tracking-wider">Encode</span>
                </button>
            </div>

            <div className="mt-auto flex flex-col items-center gap-2">
                 <div className={`w-1.5 h-1.5 rounded-full transition-all duration-500 ${isConnected ? 'bg-cyan-400 shadow-[0_0_10px_#22d3ee]' : 'bg-slate-700'}`} />
                 <div className="h-8 w-px bg-gradient-to-b from-slate-800 to-transparent"></div>
            </div>
        </nav>

        {/* VIEW CONTENT */}
        <div className="flex-1 relative overflow-hidden flex flex-col">
            {activeView === 'scanner' && (
                <div className="flex-1 flex flex-col lg:flex-row h-full">
                    {/* Left Panel */}
                    <div className={`
                    ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                    lg:flex flex-col h-full w-full lg:w-80 shrink-0 z-10 glass-panel border-r-0 lg:border-r border-b lg:border-b-0 border-slate-700/30
                    `}>
                    <Controls 
                        status={status}
                        scanMode={scanMode}
                        isScanning={isScanning}
                        settings={settings}
                        onConnect={handleConnect}
                        onDisconnect={handleDisconnect}
                        onToggleMode={setScanMode}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        onUpdateSettings={handleUpdateSettings}
                        onWriteEpc={handleWriteEpc}
                        writeLoading={writeStatus === 'pending'}
                        selectedEpc={selectedEpc}
                    />
                    </div>

                    {/* Middle Panel */}
                    <div className={`
                    ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                    lg:flex flex-col flex-1 h-full min-w-0 bg-transparent
                    `}>
                    <InteractiveLog 
                        tags={tags}
                        onClear={handleClearLog}
                        onSelectEpc={setSelectedEpc}
                        logs={logs}
                    />
                    </div>

                    {/* Right Panel */}
                    <div className={`
                    ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                    lg:flex flex-col h-full w-full lg:w-80 shrink-0 glass-panel border-l lg:border-l border-t lg:border-t-0 border-slate-700/30
                    `}>
                    <BatchResults 
                        fileContent={fileContent}
                        isTransferring={isTransferring}
                        transferProgress={transferProgress} 
                        onRequestFile={handleRequestBatchFile}
                    />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <WriterView 
                    onWrite={handleWriteEpc}
                    writeStatus={writeStatus}
                    writeMessage={writeMessage}
                    setWriteStatus={setWriteStatus}
                    onStartScan={handleStartScan}
                    onStopScan={handleStopScan}
                    isScanning={isScanning}
                    liveTags={tags}
                />
            )}
        </div>
      </div>

      {/* Mobile Nav */}
      {activeView === 'scanner' && (
        <div className="lg:hidden flex items-center justify-around glass-panel border-t border-slate-700/50 h-16 shrink-0 z-50">
            <button onClick={() => setMobileTab('controls')} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'controls' ? 'text-cyan-400' : 'text-slate-500'}`}>
               <LayoutDashboard size={18} />
               <span className="text-[9px] uppercase tracking-wide">Controls</span>
            </button>
            <button onClick={() => setMobileTab('logs')} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'logs' ? 'text-cyan-400' : 'text-slate-500'}`}>
               <div className="relative">
                 <ScrollText size={18} />
                 {tags.length > 0 && <span className="absolute -top-1 -right-1 w-2 h-2 bg-cyan-400 rounded-full shadow-[0_0_5px_#22d3ee]" />}
               </div>
               <span className="text-[9px] uppercase tracking-wide">Live Data</span>
            </button>
            <button onClick={() => setMobileTab('results')} className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${mobileTab === 'results' ? 'text-cyan-400' : 'text-slate-500'}`}>
               <FileOutput size={18} />
               <span className="text-[9px] uppercase tracking-wide">Batch</span>
            </button>
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, ScanLine, Zap, Info, Bell, Signal, Globe } from 'lucide-react';
import { Button } from './ui/Button';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  useEffect(() => { setLocalPower(settings.power); }, [settings.power]);
  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => { setLocalBuzzer(settings.buzzer); }, [settings.buzzer]);

  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) {
        setRfSpeed(parts[0]);
        setRfQv(parts[1]);
        setRfSession(parts[2]);
        setRfTarget(parts[3]);
      }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isBuzzerDirty = localBuzzer !== settings.buzzer;
  const currentRfString = `${rfSpeed},${rfQv},${rfSession},${rfTarget}`;
  const isRfDirty = currentRfString !== settings.rfParams;

  const handleSetRfParams = () => {
    onUpdateSettings('rfParams', currentRfString);
  };

  return (
    <div className="flex flex-col h-full overflow-y-auto w-full gap-6 p-5 custom-scrollbar bg-transparent">

      {/* Brand Header */}
      <div className="hidden lg:flex flex-col gap-1 mb-2">
         <div className="flex items-center gap-2">
            <Globe className="w-5 h-5 text-cyan-400" />
            <h1 className="font-bold text-lg text-white tracking-wide font-sans leading-none">
                Next<span className="text-cyan-400">waves</span>
            </h1>
         </div>
         <p className="text-[10px] text-cyan-500/60 uppercase tracking-[0.2em] ml-7">UHF RFID Scanner V3</p>
      </div>

      {/* Connection Status Panel */}
      <div className="bg-slate-900/40 border border-slate-700/50 rounded p-3 relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-2 opacity-20 group-hover:opacity-40 transition-opacity">
            <Bluetooth className="w-12 h-12 text-slate-500" />
         </div>

         <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] text-slate-400 uppercase tracking-wider font-semibold">Device Status</span>
            <div className="flex items-center gap-1.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isConnected ? 'bg-cyan-400 shadow-[0_0_8px_#22d3ee]' : 'bg-red-500'}`}></span>
                <span className={`text-[10px] font-mono ${isConnected ? 'text-cyan-300' : 'text-red-400'}`}>{status}</span>
            </div>
         </div>

         {isConnected && settings.deviceInfo && (
            <div className="text-xs font-mono text-cyan-100/70 mb-3 truncate flex items-center gap-1">
                <Info className="w-3 h-3" /> {settings.deviceInfo}
            </div>
         )}

         {isConnected ? (
          <Button variant="danger" fullWidth onClick={onDisconnect} disabled={isScanning} size="sm" className="relative z-10">
            Disconnect
          </Button>
        ) : (
          <Button variant="primary" fullWidth onClick={onConnect} disabled={status === ConnectionStatus.CONNECTING} size="sm" className="relative z-10">
            {status === ConnectionStatus.CONNECTING ? 'Connecting...' : 'Connect Scanner'}
          </Button>
        )}
      </div>

      <div className="h-px bg-gradient-to-r from-transparent via-slate-700 to-transparent" />

      {/* Scan Operations */}
      <div className="space-y-4">
        <div className="flex items-center gap-2 text-cyan-400 font-semibold text-xs uppercase tracking-wider">
          <ScanLine className="w-4 h-4" />
          <h2>Operation Mode</h2>
        </div>

        <div className="grid grid-cols-2 gap-2 bg-black/20 p-1 rounded border border-slate-800">
          <button
            className={`py-2 rounded text-[10px] font-medium transition-all ${scanMode === ScanMode.INTERACTIVE ? 'bg-cyan-900/40 text-cyan-300 border border-cyan-500/30 shadow-[inset_0_0_10px_rgba(34,211,238,0.1)]' : 'text-slate-500 hover:text-slate-300'}`}
            onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
            disabled={isScanning}
          >
            INTERACTIVE
          </button>
          <button
            className={`py-2 rounded text-[10px] font-medium transition-all ${scanMode === ScanMode.BATCH ? 'bg-cyan-900/40 text-cyan-300 border border-cyan-500/30 shadow-[inset_0_0_10px_rgba(34,211,238,0.1)]' : 'text-slate-500 hover:text-slate-300'}`}
            onClick={() => onToggleMode(ScanMode.BATCH)}
            disabled={isScanning}
          >
            BATCH
          </button>
        </div>

        {isScanning ? (
          <Button variant="danger" fullWidth onClick={onStopScan} disabled={!isConnected} className="animate-pulse shadow-[0_0_15px_rgba(239,68,68,0.3)]">
            STOP SCANNING
          </Button>
        ) : (
          <Button variant="success" fullWidth onClick={onStartScan} disabled={!isConnected}>
            START SCAN
          </Button>
        )}
      </div>

      <div className="h-px bg-gradient-to-r from-transparent via-slate-700 to-transparent" />

      {/* Settings */}
      <div className="space-y-6 flex-1">
        <div className="flex items-center gap-2 text-cyan-400 font-semibold text-xs uppercase tracking-wider">
          <SettingsIcon className="w-4 h-4" />
          <h2>Configuration</h2>
        </div>

        {/* Tx Power Slider */}
        <div className="bg-slate-900/30 p-3 rounded border border-slate-800">
          <label className="flex justify-between text-[10px] text-slate-400 mb-3 uppercase tracking-wider font-bold">
            <span>Signal Strength (dBm)</span>
            <span className={`font-mono ${isPowerDirty ? "text-amber-400" : "text-cyan-400"}`}>
              {localPower}
            </span>
          </label>
          <div className="flex items-center gap-3">
            <input 
              type="range" 
              min="0" 
              max="33" 
              value={localPower}
              onChange={(e) => setLocalPower(parseInt(e.target.value))}
              disabled={!isConnected || isScanning}
              className="flex-1 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-cyan-500"
            />
            <Button 
              size="sm" 
              variant={isPowerDirty ? 'primary' : 'outline'}
              className="h-6 px-2 min-w-[40px]"
              disabled={!isConnected || isScanning || !isPowerDirty}
              onClick={() => onUpdateSettings('power', localPower)}
            >
              SET
            </Button>
          </div>
        </div>

        {/* Region */}
        <div className="space-y-1">
            <label className="text-[10px] text-slate-400 uppercase tracking-wider font-bold">Region / Freq</label>
            <div className="flex gap-2">
              <select 
                className="flex-1 bg-black/40 border border-slate-700 text-cyan-50 text-xs rounded p-2 focus:border-cyan-500 focus:outline-none"
                value={localFreq}
                onChange={(e) => setLocalFreq(e.target.value)}
                disabled={!isConnected || isScanning}
              >
                <option value="US">US (902-928 MHz)</option>
                <option value="EU">EU (865-868 MHz)</option>
                <option value="CN">CN (920-925 MHz)</option>
                <option value="VN">VN (918-923 MHz)</option>
              </select>
              <Button 
                size="sm" 
                variant={isFreqDirty ? 'primary' : 'outline'}
                className="h-9 px-3"
                disabled={!isConnected || isScanning || !isFreqDirty}
                onClick={() => onUpdateSettings('frequency', localFreq)}
              >
                SET
              </Button>
            </div>
        </div>

        {/* Buzzer Switch */}
        <div className="flex items-center justify-between bg-slate-900/30 p-3 rounded border border-slate-800">
             <div className="flex items-center gap-2 text-slate-400 text-xs uppercase tracking-wider font-bold">
                 <Bell className="w-3 h-3 text-cyan-500" />
                 <span>Buzzer</span>
             </div>
             <div className="flex items-center gap-2">
                 <button 
                     className={`w-8 h-4 rounded-full relative transition-colors ${localBuzzer ? 'bg-cyan-600 shadow-[0_0_8px_rgba(8,145,178,0.5)]' : 'bg-slate-700'}`}
                     onClick={() => setLocalBuzzer(!localBuzzer)}
                     disabled={!isConnected || isScanning}
                 >
                     <div className={`absolute top-0.5 left-0.5 bg-white w-3 h-3 rounded-full transition-transform ${localBuzzer ? 'translate-x-4' : 'translate-x-0'}`} />
                 </button>
                 {isBuzzerDirty && (
                     <button onClick={() => onUpdateSettings('buzzer', localBuzzer)} className="text-[10px] text-cyan-400 hover:underline">SAVE</button>
                 )}
             </div>
        </div>

        {/* RF Parameters */}
        <div className="space-y-3 pt-3 border-t border-slate-700/50">
           <div className="flex items-center justify-between">
                <label className="text-[10px] text-cyan-500/80 flex items-center gap-1 uppercase tracking-wider font-bold">
                    <Zap className="w-3 h-3" /> Advanced RF
                </label>
                <Button 
                    size="sm" 
                    variant={isRfDirty ? 'primary' : 'outline'}
                    className="py-0.5 px-2 text-[10px] h-6"
                    disabled={!isConnected || isScanning || !isRfDirty}
                    onClick={handleSetRfParams}
                >
                    APPLY
                </Button>
           </div>

           <div className="grid grid-cols-2 gap-3">
               <div className="space-y-1">
                   <label className="text-[9px] text-slate-500 font-mono">LINK PROFILE</label>
                   <select 
                       className="w-full bg-black/40 border border-slate-700 text-slate-300 text-[10px] rounded p-1.5 focus:border-cyan-500 focus:outline-none"
                       value={rfSpeed}
                       onChange={(e) => setRfSpeed(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>M0 / 40K</option>
                       <option value={1}>M4 / 250K</option>
                       <option value={2}>M4 / 300K</option>
                       <option value={3}>M0 / 400K</option>
                   </select>
               </div>

               <div className="space-y-1">
                   <label className="text-[9px] text-slate-500 font-mono">Q FACTOR ({rfQv})</label>
                   <select 
                       className="w-full bg-black/40 border border-slate-700 text-slate-300 text-[10px] rounded p-1.5 focus:border-cyan-500 focus:outline-none"
                       value={rfQv}
                       onChange={(e) => setRfQv(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       {[...Array(16)].map((_, i) => (
                           <option key={i} value={i}>{i}</option>
                       ))}
                   </select>
               </div>

               <div className="space-y-1">
                   <label className="text-[9px] text-slate-500 font-mono">SESSION</label>
                   <select 
                       className="w-full bg-black/40 border border-slate-700 text-slate-300 text-[10px] rounded p-1.5 focus:border-cyan-500 focus:outline-none"
                       value={rfSession}
                       onChange={(e) => setRfSession(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>S0 (Immediate)</option>
                       <option value={1}>S1 (Persist A)</option>
                       <option value={2}>S2 (Persist B)</option>
                       <option value={3}>S3 (Long)</option>
                   </select>
               </div>

               <div className="space-y-1">
                   <label className="text-[9px] text-slate-500 font-mono">TARGET</label>
                   <select 
                       className="w-full bg-black/40 border border-slate-700 text-slate-300 text-[10px] rounded p-1.5 focus:border-cyan-500 focus:outline-none"
                       value={rfTarget}
                       onChange={(e) => setRfTarget(parseInt(e.target.value))}
                       disabled={!isConnected || isScanning}
                   >
                       <option value={0}>A (Default)</option>
                       <option value={1}>B (Inverted)</option>
                       <option value={2}>A & B (Dual)</option>
                   </select>
               </div>
           </div>
        </div>

      </div>
    </div>
  );
};

