import React, { useState, useEffect } from 'react';
import { ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search, Binary, Database, Cpu } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriterViewProps {
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;
  setWriteStatus: (status: WriteStatus) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriterView: React.FC<WriterViewProps> = ({
  onWrite,
  writeStatus,
  writeMessage,
  setWriteStatus,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); 
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    setWriteStatus('idle');
  };

  const validateAndWrite = () => {
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('HEX CHARACTERS ONLY (0-9, A-F)');
      return;
    }
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`INVALID LENGTH (MUST BE MULTIPLE OF 4). CURRENT: ${newEpc.length}`);
        return;
    }
    setError('');
    onWrite(targetEpc, newEpc);
  };

  return (
    <div className="w-full h-full flex flex-col p-4 lg:p-8 overflow-y-auto glass-panel border-none bg-transparent">
        <div className="max-w-3xl mx-auto w-full flex flex-col gap-6">

            {/* Header */}
            <div className="flex items-center gap-4 pb-4 border-b border-cyan-500/20">
                <div className="p-3 bg-cyan-950/40 rounded-lg border border-cyan-500/30 shadow-[0_0_15px_rgba(6,182,212,0.2)]">
                    <Cpu className="w-8 h-8 text-cyan-400" />
                </div>
                <div>
                    <h1 className="text-2xl font-bold text-white tracking-wider font-sans">MEMORY ENCODER</h1>
                    <p className="text-cyan-400/60 text-xs font-mono uppercase">Bank 1: EPC Gen2 Programmable Interface</p>
                </div>
            </div>

            {/* Warning Panel */}
            <div className="bg-amber-950/30 border border-amber-600/30 rounded p-4 flex items-start gap-4 shadow-[0_0_20px_rgba(245,158,11,0.1)]">
                <AlertTriangle className="w-6 h-6 text-amber-500 shrink-0 mt-0.5 animate-pulse" />
                <div className="space-y-1">
                    <p className="text-sm font-bold text-amber-400 uppercase tracking-wide">Proximity Alert</p>
                    <p className="text-xs text-amber-200/60 leading-relaxed font-mono">
                        ISOLATION REQUIRED. Ensure only TARGET TAG is within antenna range during write cycles.
                    </p>
                </div>
            </div>

            {/* Step 1: Scan & Select */}
            {step === 1 && (
                <div className="flex flex-col gap-4 animate-in slide-in-from-right-4 duration-300">
                    <div className="flex items-center justify-between bg-slate-900/60 p-4 rounded border border-slate-700 backdrop-blur-sm">
                        <div className="flex items-center gap-4">
                             <div className="flex items-center justify-center w-8 h-8 rounded bg-cyan-900/50 text-cyan-300 font-bold border border-cyan-700">1</div>
                             <div>
                                 <h3 className="text-slate-200 font-bold text-sm uppercase">Select Target</h3>
                                 <p className="text-[10px] text-slate-500 font-mono">Scan environment to identify target EPC.</p>
                             </div>
                        </div>
                        {isScanning ? (
                            <Button size="sm" variant="danger" onClick={onStopScan} className="min-w-[100px]">STOP SCAN</Button>
                        ) : (
                            <Button size="sm" variant="success" onClick={onStartScan} className="min-w-[100px]">START SCAN</Button>
                        )}
                    </div>

                    <div className="bg-black/40 border border-slate-800 rounded min-h-[300px] flex-1 overflow-hidden flex flex-col relative">
                        {/* Grid lines overlay */}
                        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMSIgY3k9IjEiIHI9IjEiIGZpbGw9InJnYmEoMzQs 211, 238, 0.05)"/)] pointer-events-none"></div>

                        <div className="bg-slate-900/80 px-4 py-2 border-b border-slate-800 text-xs font-bold text-cyan-500 flex justify-between uppercase tracking-wider">
                            <span>Detected Signals</span>
                            <span>{liveTags.length} UNITS</span>
                        </div>
                        <div className="flex-1 overflow-y-auto relative custom-scrollbar z-10">
                            {liveTags.length === 0 ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 gap-4">
                                    <div className="relative">
                                        <div className={`absolute inset-0 bg-cyan-500 blur-xl opacity-20 rounded-full ${isScanning ? 'animate-pulse' : 'hidden'}`}></div>
                                        <Radio className={`w-12 h-12 ${isScanning ? 'text-cyan-400' : 'text-slate-800'}`} />
                                    </div>
                                    <p className="text-xs font-mono uppercase tracking-widest">{isScanning ? 'SCANNING FREQUENCIES...' : 'SYSTEM IDLE'}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-slate-800/50">
                                    {liveTags.map((tag, idx) => (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectTag(tag.epc)}
                                            className="w-full flex items-center justify-between p-4 hover:bg-cyan-900/20 transition-all group text-left border-l-2 border-transparent hover:border-cyan-500"
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className="w-2 h-2 rounded-full bg-cyan-500 shadow-[0_0_5px_#22d3ee]" />
                                                <div>
                                                    <p className="font-mono text-cyan-300 font-medium group-hover:text-white transition-colors text-base shadow-cyan-500/50">{tag.epc}</p>
                                                    <p className="text-[10px] text-slate-500 mt-1 font-mono">RSSI: {tag.rssi} dBm</p>
                                                </div>
                                            </div>
                                            <div className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0 duration-300">
                                                <span className="text-[10px] bg-cyan-600/20 text-cyan-300 border border-cyan-500/50 px-3 py-1 rounded font-bold uppercase">Initialize</span>
                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Step 2: Write */}
            {step === 2 && (
                <div className="flex flex-col gap-6 animate-in slide-in-from-right-4 duration-300">
                     <div className="flex items-center gap-4">
                         <div className="flex items-center justify-center w-8 h-8 rounded bg-cyan-900/50 text-cyan-300 font-bold border border-cyan-700">2</div>
                         <h3 className="text-slate-200 font-bold text-sm uppercase">Program Data</h3>
                     </div>

                     <div className="bg-slate-900/50 border border-slate-700 rounded p-6 space-y-8 backdrop-blur-sm">

                         <div className="grid gap-6">
                            <div className="space-y-2">
                                <label className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Target Identifier</label>
                                <div className="bg-black/60 border border-slate-800 rounded p-4 flex items-center gap-3">
                                    <Database className="w-5 h-5 text-slate-600" />
                                    <span className="font-mono text-slate-400 text-lg tracking-widest">{targetEpc}</span>
                                </div>
                            </div>

                            <div className="flex justify-center">
                                <div className="bg-slate-800 p-2 rounded-full border border-slate-700">
                                    <ArrowRight className="w-5 h-5 text-cyan-500 animate-pulse" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-[10px] text-cyan-400 uppercase font-bold tracking-widest">New Payload (Hex)</label>
                                <Input 
                                    value={newEpc}
                                    onChange={(e) => {
                                        setNewEpc(e.target.value.toUpperCase());
                                        setError('');
                                    }}
                                    error={error}
                                    className="font-mono text-lg py-4 border-slate-700 bg-black/60 focus:border-cyan-500 text-center tracking-widest text-cyan-300 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)]"
