                                    autoFocus
                                />
                                <div className="flex justify-between text-[10px] text-slate-500 px-1 font-mono">
                                    <span>LEN: {newEpc.length} CHARS</span>
                                    <span>SIZE: {newEpc.length * 4} BITS</span>
                                </div>
                            </div>
                         </div>

                         {/* Actions */}
                         <div className="flex items-center gap-4 pt-4 border-t border-slate-800">
                            <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'} size="lg">
                                CANCEL
                            </Button>

                            {writeStatus !== 'success' && (
                                <Button 
                                    variant="primary" 
                                    onClick={validateAndWrite} 
                                    disabled={writeStatus === 'pending'}
                                    size="lg"
                                    className="flex-1 shadow-[0_0_20px_rgba(6,182,212,0.3)]"
                                >
                                    {writeStatus === 'pending' ? 'PROGRAMMING...' : 'EXECUTE WRITE'}
                                </Button>
                            )}
                         </div>

                         {/* Status Messages */}
                         {writeStatus === 'success' && (
                             <div className="bg-emerald-950/40 border border-emerald-500/30 rounded p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300 shadow-[0_0_20px_rgba(16,185,129,0.1)]">
                                 <CheckCircle2 className="w-8 h-8 text-emerald-500" />
                                 <div className="flex-1">
                                     <p className="font-bold text-emerald-400 uppercase tracking-wide">Write Successful</p>
                                     <p className="text-xs text-emerald-200/70 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                                 <Button variant="outline" size="sm" onClick={handleBackToScan} className="border-emerald-800 text-emerald-400 hover:bg-emerald-900/30">
                                     NEW TASK
                                 </Button>
                             </div>
                         )}

                         {writeStatus === 'error' && (
                             <div className="bg-red-950/40 border border-red-500/30 rounded p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300 shadow-[0_0_20px_rgba(239,68,68,0.1)]">
                                 <XCircle className="w-8 h-8 text-red-500" />
                                 <div>
                                     <p className="font-bold text-red-400 uppercase tracking-wide">Write Failed</p>
                                     <p className="text-xs text-red-200/70 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                             </div>
                         )}
                     </div>
                </div>
            )}
        </div>
    </div>
  );
};

import React from 'react';
import { Download, FileDown, RefreshCw, Share2, FileCode } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring,
  onRequestFile
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    if (!fileContent) return;
    try {
      const fileName = `scan_batch_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.txt`;
      const file = new File([fileContent], fileName, { type: 'text/plain' });
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Batch Scan Results',
          text: 'Attached RFID scan results.',
        });
      } else {
        if (navigator.share) {
             await navigator.share({
                title: 'Batch Scan Results',
                text: fileContent
             });
        } else {
             alert('Sharing is not supported on this device/browser. Please use "Save .txt"');
        }
      }
    } catch (error) {
      console.log('Share canceled or failed', error);
    }
  };

  const hasContent = !!fileContent && !isTransferring;
  const canShare = typeof navigator !== 'undefined' && !!navigator.share;

  return (
    <div className="w-full flex flex-col h-full p-4 gap-4 bg-transparent">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 pb-2 border-b border-purple-500/20">
        <div className="flex items-center gap-2 text-purple-400 font-bold uppercase tracking-wider">
          <FileDown className="w-5 h-5" />
          <h2>Data Export</h2>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={onRequestFile}
                disabled={isTransferring}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 hover:text-white rounded text-[10px] font-bold uppercase border border-slate-600 transition-colors disabled:opacity-50"
            >
                <RefreshCw className={`w-3 h-3 ${isTransferring ? 'animate-spin' : ''}`} />
                FETCH DATA
            </button>

            {hasContent && (
              <>
                <button 
                    onClick={handleDownload}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-cyan-900/30 hover:bg-cyan-800/50 text-cyan-400 hover:text-cyan-200 rounded text-[10px] font-bold uppercase border border-cyan-700 transition-colors shadow-[0_0_10px_rgba(6,182,212,0.1)]"
                >
                    <Download className="w-3 h-3" />
                    SAVE .TXT
                </button>

                {canShare && (
                    <button 
                        onClick={handleShare}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-purple-900/30 hover:bg-purple-800/50 text-purple-400 hover:text-purple-200 rounded text-[10px] font-bold uppercase border border-purple-700 transition-colors shadow-[0_0_10px_rgba(168,85,247,0.1)]"
                    >
                        <Share2 className="w-3 h-3" />
                        SHARE
                    </button>
                )}
              </>
            )}
        </div>
      </div>

      <div className="flex-1 bg-black/40 rounded border border-slate-800 overflow-hidden relative flex flex-col shadow-inner shadow-black/80">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/80 z-10 p-8 text-center backdrop-blur-sm">
            <RefreshCw className="w-12 h-12 text-purple-500 animate-spin mb-4" />
            <h3 className="text-purple-300 font-bold uppercase tracking-widest">TRANSFERRING PACKETS...</h3>
            {transferProgress >= 0 && (
                <div className="w-48 h-1 bg-slate-800 rounded-full mt-4 overflow-hidden">
                    <div className="h-full bg-purple-500 transition-all duration-300" style={{width: `${transferProgress}%`}}></div>
                </div>
            )}
            <p className="text-slate-500 text-[10px] font-mono mt-4">DO NOT DISCONNECT DEVICE</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-700 p-8 text-center gap-2">
            <FileCode className="w-16 h-16 opacity-20" />
            <p className="text-sm font-bold text-slate-600 uppercase tracking-widest">NO DATA BUFFERED</p>
            <p className="text-[10px] max-w-xs font-mono opacity-60">Initiate BATCH SCAN mode to accumulate data logs.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar bg-black/60">
            <pre className="font-mono text-[10px] text-purple-200 whitespace-pre-wrap break-all leading-relaxed shadow-none">
              {fileContent}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

