import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded-lg font-medium transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed tracking-wide';

  const variants = {
    // Tesla Blue/Cyan Accent
    primary: 'bg-cyan-500 text-black hover:bg-cyan-400 hover:shadow-glow font-semibold',
    // Dark Surface
    secondary: 'bg-[#2A2A2A] text-white hover:bg-[#333333]',
    // Alert
    danger: 'bg-red-500/10 text-red-500 hover:bg-red-500 hover:text-white border border-red-500/20',
    // Success
    success: 'bg-emerald-500 text-black hover:bg-emerald-400 font-semibold',
    // Minimal border
    outline: 'border border-[#333] text-slate-400 hover:border-cyan-500 hover:text-cyan-400 bg-transparent',
    // Navigation style
    ghost: 'text-slate-500 hover:text-white hover:bg-white/5'
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-5 py-2.5 text-sm',
    lg: 'px-8 py-4 text-base'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

