import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, ScanLine, Globe, Zap, Settings as SettingsIcon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer' | 'settings';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic (Simplified for brevity - logic remains same) ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 150 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        setTags(allTags.slice(0, 500));
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- New Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        {/* Abstract "Wave" Logo Icon */}
        <div className="relative w-8 h-8">
            <div className="absolute inset-0 bg-cyan-500 rounded-lg opacity-20 transform rotate-45"></div>
            <div className="absolute inset-1 bg-gradient-to-tr from-cyan-400 to-blue-600 rounded-md flex items-center justify-center">
                 <Globe className="text-white w-5 h-5" strokeWidth={2.5} />
            </div>
        </div>
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-white leading-none font-sans">
                Next<span className="text-cyan-400">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-black text-slate-200 font-sans">

      {/* --- DESKTOP DOCK (Left Rail) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-[#0A0A0A] border-r border-[#1A1A1A] items-center py-8 z-30">
         <div className="mb-12">
            <div className="w-10 h-10 bg-cyan-500 rounded-xl flex items-center justify-center shadow-glow">
                <Globe className="text-black w-6 h-6" strokeWidth={2.5} />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
