  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => { setLocalBuzzer(settings.buzzer); }, [settings.buzzer]);
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) { setRfSpeed(parts[0]); setRfQv(parts[1]); setRfSession(parts[2]); setRfTarget(parts[3]); }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isRfDirty = `${rfSpeed},${rfQv},${rfSession},${rfTarget}` !== settings.rfParams;

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-6 gap-8 bg-[#121212]">

