               <span className="h-px flex-1 bg-[#2A2A2A]"></span>
          </div>

          {/* Power Slider */}
          <div className="bg-[#161616] rounded-xl p-4 border border-[#222]">
              <div className="flex justify-between items-center mb-4">
                  <div className="flex items-center gap-2 text-slate-400">
                      <Wifi size={14} />
                      <span className="text-xs font-bold uppercase tracking-wide">Signal Gain</span>
                  </div>
                  <span className={`text-sm font-mono font-bold ${isPowerDirty ? 'text-cyan-400' : 'text-slate-500'}`}>{localPower} dBm</span>
              </div>
              <input 
                 type="range" min="0" max="33" 
                 value={localPower}
                 onChange={(e) => setLocalPower(parseInt(e.target.value))}
                 disabled={!isConnected || isScanning}
                 className="w-full h-1.5 bg-[#333] rounded-lg appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400"
