                     value={localFreq}
                     onChange={(e) => setLocalFreq(e.target.value)}
                     disabled={!isConnected || isScanning}
                  >
                      <option value="US">US FCC</option>
                      <option value="EU">EU ETSI</option>
                      <option value="CN">CHINA</option>
                      <option value="VN">VIETNAM</option>
                  </select>
                  {isFreqDirty && <button onClick={() => onUpdateSettings('frequency', localFreq)} className="text-[10px] text-cyan-400 mt-1 text-right font-bold">SAVE</button>}
              </div>

              <div className="bg-[#161616] rounded-xl p-3 border border-[#222] flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-slate-400">
                      <Volume2 size={14} />
                      <span className="text-[10px] uppercase font-bold">Audio</span>
                  </div>
                  <div className="flex justify-end mt-2">
                       <button 
                           onClick={() => { const n = !localBuzzer; setLocalBuzzer(n); onUpdateSettings('buzzer', n); }}
                           disabled={!isConnected || isScanning}
                           className={`w-10 h-5 rounded-full relative transition-colors ${localBuzzer ? 'bg-cyan-600' : 'bg-[#333]'}`}
                       >
                           <div className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full transition-transform ${localBuzzer ? 'translate-x-5' : 'translate-x-0'}`} />
                       </button>
