              </div>
          </div>

           {/* Quick Advanced RF */}
           <div className="pt-2">
                <button 
                    className={`w-full text-[10px] uppercase font-bold tracking-wider py-3 border border-dashed border-[#333] rounded-lg hover:bg-[#1A1A1A] hover:border-cyan-500/50 hover:text-cyan-400 transition-colors ${isRfDirty ? 'text-cyan-400 border-cyan-500' : 'text-slate-600'}`}
                    onClick={() => onUpdateSettings('rfParams', `${rfSpeed},${rfQv},${rfSession},${rfTarget}`)}
                >
