                </button>
           </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
import { Tag, LogEntry } from '../types';
import { Trash2, Terminal, Activity, Wifi } from 'lucide-react';

interface InteractiveLogProps {
  tags: Tag[];
  onClear: () => void;
  onSelectEpc: (epc: string) => void;
  logs: LogEntry[];
}

export const InteractiveLog: React.FC<InteractiveLogProps> = ({ tags, onClear, onSelectEpc, logs }) => {
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (logEndRef.current) {
      logEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs]);

  return (
    <div className="flex-1 flex flex-col h-full min-w-0">

      {/* Top Bar */}
      <div className="h-16 flex items-center justify-between px-6 border-b border-[#1A1A1A] bg-[#0A0A0A]">
          <div className="flex items-center gap-3">
              <div className="w-8 h-8 rounded-lg bg-cyan-500/10 flex items-center justify-center border border-cyan-500/20">
                  <Activity size={16} className="text-cyan-400" />
              </div>
              <div>
                  <h2 className="text-sm font-bold text-white tracking-wide">Live Data Feed</h2>
                  <div className="flex items-center gap-2">
                      <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                      <span className="text-[10px] text-slate-500 font-mono uppercase">Monitoring {tags.length} entities</span>
                  </div>
              </div>
          </div>
          <button onClick={onClear} className="p-2 hover:bg-[#1A1A1A] rounded-lg text-slate-500 hover:text-red-400 transition-colors">
              <Trash2 size={16} />
          </button>
      </div>

      {/* Grid Header */}
      <div className="flex items-center px-6 py-3 bg-[#121212] border-b border-[#1A1A1A] text-[10px] font-bold text-slate-500 uppercase tracking-widest">
          <div className="w-12">#</div>
          <div className="flex-1">EPC / Identifier</div>
          <div className="w-24 text-right">RSSI</div>
          <div className="w-24 text-right">Count</div>
      </div>

      {/* Grid Body */}
      <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#000000]">
          {tags.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-800 gap-4">
                  <Wifi size={48} strokeWidth={1} className="opacity-20" />
                  <p className="text-xs font-medium uppercase tracking-widest opacity-40">No Signal Detected</p>
              </div>
          ) : (
              <div className="divide-y divide-[#1A1A1A]">
                  {tags.map((tag, idx) => (
                      <div 
                          key={`${tag.epc}-${idx}`}
                          onClick={() => onSelectEpc(tag.epc)}
                          className="flex items-center px-6 py-3 hover:bg-[#0A0A0A] cursor-pointer group transition-colors"
                      >
                          <div className="w-12 text-slate-600 font-mono text-xs">{idx + 1}</div>
                          <div className="flex-1 font-mono text-sm text-cyan-500 group-hover:text-cyan-300 transition-colors font-medium">
                              {tag.epc}
                          </div>
                          <div className="w-24 text-right font-mono text-xs text-slate-400">
                              {tag.rssi} <span className="text-[9px] text-slate-600">dBm</span>
                          </div>
                          <div className="w-24 text-right">
                              <span className="bg-[#1A1A1A] text-slate-300 px-2 py-1 rounded text-xs font-mono font-bold">{tag.count}</span>
                          </div>
                      </div>
                  ))}
              </div>
          )}
      </div>

      {/* Terminal Log */}
      <div className="h-48 border-t border-[#1A1A1A] bg-[#050505] flex flex-col">
          <div className="px-4 py-2 border-b border-[#1A1A1A] flex items-center gap-2">
              <Terminal size={12} className="text-slate-600" />
              <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">System Events</span>
          </div>
          <div className="flex-1 overflow-y-auto p-4 font-mono text-[11px] space-y-1 custom-scrollbar">
              {logs.map((log, i) => (
                  <div key={i} className="flex gap-3 text-slate-400">
                      <span className="opacity-30 select-none">
                          {new Date(log.timestamp).toLocaleTimeString([], {hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit'})}
                      </span>
                      <span className={
                          log.type === 'error' ? 'text-red-400' :
                          log.type === 'tx' ? 'text-slate-500' :
                          log.type === 'rx' ? 'text-emerald-500' :
                          'text-slate-300'
                      }>
                          {log.type === 'tx' && '→ '}
                          {log.type === 'rx' && '← '}
                          {log.message}
                      </span>
                  </div>
              ))}
              <div ref={logEndRef} />
          </div>
      </div>
    </div>
  );
};

