);

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, ScanLine, Zap, Settings as SettingsIcon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { Logo } from './components/ui/Logo';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer' | 'settings';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic (Simplified for brevity - logic remains same) ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 150 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        setTags(allTags.slice(0, 500));
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- Brand Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        <Logo className="w-8 h-8" />
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-white leading-none font-sans">
                Next<span className="text-cyan-400">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-black text-slate-200 font-sans">

      {/* --- DESKTOP DOCK (Left Rail) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-[#0A0A0A] border-r border-[#1A1A1A] items-center py-8 z-30">
         <div className="mb-12">
            <div className="w-12 h-12 bg-cyan-900/10 rounded-xl flex items-center justify-center border border-cyan-500/20 shadow-glow">
                <Logo className="w-8 h-8" />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-[#1A1A1A] text-cyan-400' : 'text-slate-500 hover:text-white hover:bg-[#1A1A1A]'}`}
            >
                <LayoutGrid size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Dashboard</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'writer' ? 'bg-[#1A1A1A] text-cyan-400' : 'text-slate-500 hover:text-white hover:bg-[#1A1A1A]'}`}
            >
                <Cpu size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Encoder</span>
            </button>
         </div>

         <div className="mt-auto mb-4">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : 'bg-red-500 shadow-[0_0_10px_#ef4444]'}`} title={status}></div>
         </div>
      </nav>

      {/* --- MAIN STAGE --- */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-black">

        {/* Mobile Header */}
        <div className="lg:hidden h-16 bg-[#0A0A0A] flex items-center justify-between px-4 border-b border-[#1A1A1A] z-20">
            <BrandLogo />
            <div className="flex items-center gap-3">
                 <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500' : 'bg-red-500'}`} />
                 <Button size="sm" variant={isConnected ? "danger" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect}>
                    <Bluetooth size={16} />
                 </Button>
            </div>
        </div>

        {/* Content Wrapper */}
        <div className="flex-1 overflow-hidden relative p-0 lg:p-6">

            {activeView === 'scanner' && (
                <div className="w-full h-full flex flex-col lg:flex-row gap-6">
                    {/* LEFT: Controls (The Dashboard) */}
                    <div className={`
                        ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[360px] shrink-0 bg-[#121212] lg:rounded-2xl border border-[#1A1A1A] overflow-hidden
                    `}>
                        <Controls 
                            status={status}
                            scanMode={scanMode}
                            isScanning={isScanning}
                            settings={settings}
                            onConnect={handleConnect}
                            onDisconnect={handleDisconnect}
                            onToggleMode={setScanMode}
                            onStartScan={handleStartScan}
                            onStopScan={handleStopScan}
                            onUpdateSettings={handleUpdateSettings}
                            onWriteEpc={handleWriteEpc}
                            writeLoading={writeStatus === 'pending'}
                            selectedEpc={selectedEpc}
                        />
                    </div>

                    {/* CENTER: Data Visualization */}
                    <div className={`
                        ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                        lg:flex flex-col flex-1 bg-[#121212] lg:rounded-2xl border border-[#1A1A1A] overflow-hidden min-w-0
                    `}>
                        <InteractiveLog 
                            tags={tags}
                            onClear={handleClearLog}
                            onSelectEpc={setSelectedEpc}
                            logs={logs}
                        />
                    </div>

                    {/* RIGHT: History/Batch (Collapsed on smaller desktops if needed) */}
                    <div className={`
                        ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[320px] shrink-0 bg-[#121212] lg:rounded-2xl border border-[#1A1A1A] overflow-hidden
                    `}>
                        <BatchResults 
                            fileContent={fileContent}
                            isTransferring={isTransferring}
                            transferProgress={transferProgress} 
                            onRequestFile={handleRequestBatchFile}
                        />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <div className="w-full h-full bg-[#121212] lg:rounded-2xl border border-[#1A1A1A] overflow-hidden">
                    <WriterView 
                        onWrite={handleWriteEpc}
                        writeStatus={writeStatus}
                        writeMessage={writeMessage}
                        setWriteStatus={setWriteStatus}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        isScanning={isScanning}
                        liveTags={tags}
                    />
                </div>
            )}

        </div>

        {/* Mobile Tab Bar */}
        {activeView === 'scanner' && (
            <div className="lg:hidden h-16 bg-[#0A0A0A] border-t border-[#1A1A1A] flex justify-around items-center z-20">
                <button onClick={() => setMobileTab('controls')} className={mobileTab === 'controls' ? 'text-cyan-400' : 'text-slate-600'}>
                    <LayoutGrid />
                </button>
                <button onClick={() => setMobileTab('logs')} className={mobileTab === 'logs' ? 'text-cyan-400' : 'text-slate-600'}>
                    <ScrollText />
                </button>
                <button onClick={() => setMobileTab('results')} className={mobileTab === 'results' ? 'text-cyan-400' : 'text-slate-600'}>
                    <Database />
                </button>
            </div>
        )}

      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, Play, Square, Wifi, Volume2, Zap, Globe, Database, ChevronDown, ChevronUp } from 'lucide-react';
import { Button } from './ui/Button';
import { Logo } from './ui/Logo';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  // RF Params State
  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  // UI State
  const [showRfSettings, setShowRfSettings] = useState(false);

  useEffect(() => { setLocalPower(settings.power); }, [settings.power]);
  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => { setLocalBuzzer(settings.buzzer); }, [settings.buzzer]);
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) { setRfSpeed(parts[0]); setRfQv(parts[1]); setRfSession(parts[2]); setRfTarget(parts[3]); }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isRfDirty = `${rfSpeed},${rfQv},${rfSession},${rfTarget}` !== settings.rfParams;

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-6 gap-8 bg-[#121212]">

      {/* 1. Header & Branding (Desktop Only - Mobile handles in App.tsx) */}
      <div className="hidden lg:block mb-2">
         <div className="flex items-center gap-3 select-none">
            <Logo className="w-8 h-8" />
            <div className="font-sans text-2xl tracking-tight leading-none">
                <span className="font-medium text-white">Next</span>
                <span className="font-bold text-cyan-400">waves</span>
            </div>
         </div>
         <div className="text-[10px] text-slate-500 uppercase tracking-[0.3em] mt-2 font-medium pl-1">
            UHF Control Center
         </div>
      </div>

      {/* 2. Status Monitor (The "Tesla" Widget) */}
      <div className="relative w-full min-h-[160px] bg-gradient-to-br from-[#1E1E1E] to-[#0A0A0A] rounded-2xl overflow-hidden shadow-lg border border-[#2A2A2A] flex flex-col justify-between p-6 gap-6 group">
          {/* Status Glow Background */}
          <div className={`absolute top-0 right-0 w-32 h-32 blur-[60px] rounded-full transition-all duration-700 ${isConnected ? 'bg-emerald-500/20' : 'bg-red-500/20'}`}></div>

          <div className="flex justify-between items-start z-10 relative">
              <div className="flex flex-col">
                  <span className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">System Status</span>
                  <div className={`text-xl font-bold mt-1 tracking-wide ${isConnected ? 'text-white' : 'text-slate-300'}`}>
                      {status === ConnectionStatus.CONNECTED ? 'ONLINE' : status === ConnectionStatus.CONNECTING ? 'SYNCING...' : 'OFFLINE'}
                  </div>
              </div>
              <Bluetooth className={`w-6 h-6 ${isConnected ? 'text-blue-400' : 'text-slate-600'}`} />
          </div>

          <div className="z-10 mt-auto relative">
             {isConnected ? (
                <div className="flex items-center gap-4">
                    <div className="flex flex-col">
                         <span className="text-[9px] text-slate-500 uppercase font-bold">Battery</span>
                         <span className="text-sm font-mono text-emerald-400">100%</span>
                    </div>
                    <div className="w-px h-6 bg-slate-700"></div>
                    <div className="flex flex-col">
                         <span className="text-[9px] text-slate-500 uppercase font-bold">Device</span>
                         <span className="text-sm font-mono text-white truncate max-w-[120px]">{settings.deviceInfo || 'Scanner V3'}</span>
                    </div>
                </div>
             ) : (
                <Button 
                    fullWidth 
                    variant="primary"
                    onClick={onConnect}
                    disabled={status === ConnectionStatus.CONNECTING}
                    className="shadow-glow"
                >
                    {status === ConnectionStatus.CONNECTING ? 'Pairing...' : 'Initialize Connection'}
                </Button>
             )}
          </div>

          {/* If connected, show disconnect small button */}
          {isConnected && (
             <button onClick={onDisconnect} disabled={isScanning} className="absolute bottom-5 right-5 text-xs text-red-400 hover:text-red-300 font-medium z-10 hover:underline decoration-red-400/30 underline-offset-4">
                Term. Link
             </button>
          )}
      </div>

      {/* 3. Main Controls */}
      <div className="space-y-6">
          <div className="flex items-center gap-2 mb-2">
               <span className="h-px flex-1 bg-[#2A2A2A]"></span>
               <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Operation</span>
               <span className="h-px flex-1 bg-[#2A2A2A]"></span>
          </div>

          <div className="grid grid-cols-2 gap-3">
              <button 
                  onClick={() => onToggleMode(ScanMode.INTERACTIVE)}
                  disabled={isScanning}
                  className={`relative p-4 rounded-xl border flex flex-col items-center justify-center gap-2 transition-all duration-300 ${scanMode === ScanMode.INTERACTIVE ? 'bg-[#1E1E1E] border-cyan-500/50 text-cyan-400 shadow-glow' : 'bg-[#0F0F0F] border-[#222] text-slate-500 hover:border-slate-600'}`}
              >
                  <Radio size={20} />
                  <span className="text-xs font-bold tracking-wide">INTERACTIVE</span>
              </button>
              <button 
                  onClick={() => onToggleMode(ScanMode.BATCH)}
                  disabled={isScanning}
                  className={`relative p-4 rounded-xl border flex flex-col items-center justify-center gap-2 transition-all duration-300 ${scanMode === ScanMode.BATCH ? 'bg-[#1E1E1E] border-cyan-500/50 text-cyan-400 shadow-glow' : 'bg-[#0F0F0F] border-[#222] text-slate-500 hover:border-slate-600'}`}
              >
                  <Database size={20} />
                  <span className="text-xs font-bold tracking-wide">BATCH</span>
              </button>
          </div>

          <Button 
             variant={isScanning ? 'danger' : 'success'} 
             fullWidth 
             size="lg"
             onClick={isScanning ? onStopScan : onStartScan}
             disabled={!isConnected}
             className={isScanning ? 'animate-pulse' : ''}
          >
             {isScanning ? (
                <div className="flex items-center gap-2"><Square size={16} fill="currentColor" /> STOP SEQUENCE</div>
             ) : (
                <div className="flex items-center gap-2"><Play size={16} fill="currentColor" /> INITIATE SCAN</div>
             )}
          </Button>
      </div>

      {/* 4. Settings Panel */}
      <div className="space-y-6">
          <div className="flex items-center gap-2 mb-2">
               <span className="h-px flex-1 bg-[#2A2A2A]"></span>
               <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">Configuration</span>
               <span className="h-px flex-1 bg-[#2A2A2A]"></span>
          </div>

          {/* Power Slider */}
          <div className="bg-[#161616] rounded-xl p-4 border border-[#222]">
              <div className="flex justify-between items-center mb-4">
                  <div className="flex items-center gap-2 text-slate-400">
                      <Wifi size={14} />
                      <span className="text-xs font-bold uppercase tracking-wide">Signal Gain</span>
                  </div>
                  <span className={`text-sm font-mono font-bold ${isPowerDirty ? 'text-cyan-400' : 'text-slate-500'}`}>{localPower} dBm</span>
              </div>
              <input 
                 type="range" min="0" max="33" 
                 value={localPower}
                 onChange={(e) => setLocalPower(parseInt(e.target.value))}
                 disabled={!isConnected || isScanning}
                 className="w-full h-1.5 bg-[#333] rounded-lg appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400"
              />
              {isPowerDirty && (
                 <div className="mt-3 flex justify-end">
                    <Button size="sm" onClick={() => onUpdateSettings('power', localPower)}>Apply Change</Button>
                 </div>
              )}
          </div>

          {/* Region & Buzzer */}
          <div className="grid grid-cols-2 gap-3">
              <div className="bg-[#161616] rounded-xl p-3 border border-[#222] flex flex-col justify-between">
                  <span className="text-[10px] uppercase font-bold text-slate-500 mb-2">Region</span>
                  <select 
                     className="bg-black text-white text-xs p-2 rounded border border-[#333] focus:border-cyan-500 outline-none w-full"
                     value={localFreq}
                     onChange={(e) => setLocalFreq(e.target.value)}
                     disabled={!isConnected || isScanning}
                  >
                      <option value="US">US FCC</option>
                      <option value="EU">EU ETSI</option>
                      <option value="CN">CHINA</option>
                      <option value="VN">VIETNAM</option>
                  </select>
                  {isFreqDirty && <button onClick={() => onUpdateSettings('frequency', localFreq)} className="text-[10px] text-cyan-400 mt-1 text-right font-bold w-full">SAVE</button>}
              </div>

              <div className="bg-[#161616] rounded-xl p-3 border border-[#222] flex flex-col justify-between">
                  <div className="flex items-center gap-2 text-slate-400">
                      <Volume2 size={14} />
                      <span className="text-[10px] uppercase font-bold">Audio</span>
                  </div>
                  <div className="flex justify-end mt-2">
                       <button 
                           onClick={() => { const n = !localBuzzer; setLocalBuzzer(n); onUpdateSettings('buzzer', n); }}
                           disabled={!isConnected || isScanning}
                           className={`w-10 h-5 rounded-full relative transition-colors ${localBuzzer ? 'bg-cyan-600' : 'bg-[#333]'}`}
                       >
                           <div className={`absolute top-1 left-1 bg-white w-3 h-3 rounded-full transition-transform ${localBuzzer ? 'translate-x-5' : 'translate-x-0'}`} />
                       </button>
                  </div>
              </div>
          </div>

           {/* Expandable Advanced RF Configuration */}
           <div className="pt-2 space-y-3 pb-8">
                <button 
                    onClick={() => setShowRfSettings(!showRfSettings)}
                    className="w-full flex items-center justify-between text-[10px] uppercase font-bold tracking-wider py-3 px-4 border border-[#222] bg-[#161616] rounded-lg text-slate-400 hover:text-white transition-colors hover:border-slate-700"
                >
                    <div className="flex items-center gap-2">
                        <Zap size={14} className={isRfDirty ? "text-cyan-400" : "text-slate-600"} />
                        <span className={isRfDirty ? "text-cyan-400" : ""}>Advanced RF Config</span>
                    </div>
                    {showRfSettings ? <ChevronUp size={14}/> : <ChevronDown size={14}/>}
                </button>

                {showRfSettings && (
                    <div className="bg-[#161616] rounded-xl p-4 border border-[#222] space-y-5 animate-in slide-in-from-top-2 duration-300">
                        <div className="grid grid-cols-2 gap-4">
                            {/* Profile */}
                            <div className="space-y-1">
                                <label className="text-[9px] text-slate-500 uppercase font-bold">Link Profile</label>
                                <select 
                                    className="bg-black text-white text-xs p-2 rounded border border-[#333] focus:border-cyan-500 outline-none w-full"
                                    value={rfSpeed}
                                    onChange={(e) => setRfSpeed(parseInt(e.target.value))}
                                    disabled={!isConnected || isScanning}
                                >
                                    <option value={0}>M0 (40K)</option>
                                    <option value={1}>M4 (250K)</option>
                                    <option value={2}>M4 (300K)</option>
                                    <option value={3}>M0 (400K)</option>
                                </select>
                            </div>

                            {/* Q Factor */}
                            <div className="space-y-1">
                                <label className="text-[9px] text-slate-500 uppercase font-bold">Q Factor ({rfQv})</label>
                                <select 
                                    className="bg-black text-white text-xs p-2 rounded border border-[#333] focus:border-cyan-500 outline-none w-full"
                                    value={rfQv}
                                    onChange={(e) => setRfQv(parseInt(e.target.value))}
                                    disabled={!isConnected || isScanning}
                                >
                                    {[...Array(16)].map((_, i) => (
                                        <option key={i} value={i}>Q = {i}</option>
                                    ))}
                                </select>
                            </div>

                            {/* Session */}
                            <div className="space-y-1">
                                <label className="text-[9px] text-slate-500 uppercase font-bold">Session</label>
                                <select 
                                    className="bg-black text-white text-xs p-2 rounded border border-[#333] focus:border-cyan-500 outline-none w-full"
                                    value={rfSession}
                                    onChange={(e) => setRfSession(parseInt(e.target.value))}
                                    disabled={!isConnected || isScanning}
                                >
                                    <option value={0}>S0 (Immediate)</option>
                                    <option value={1}>S1 (Persist A)</option>
                                    <option value={2}>S2 (Persist B)</option>
                                    <option value={3}>S3 (Long)</option>
                                </select>
                            </div>

                            {/* Target */}
                            <div className="space-y-1">
                                <label className="text-[9px] text-slate-500 uppercase font-bold">Target</label>
                                <select 
                                    className="bg-black text-white text-xs p-2 rounded border border-[#333] focus:border-cyan-500 outline-none w-full"
                                    value={rfTarget}
                                    onChange={(e) => setRfTarget(parseInt(e.target.value))}
                                    disabled={!isConnected || isScanning}
                                >
                                    <option value={0}>A (Default)</option>
                                    <option value={1}>B (Inverted)</option>
                                    <option value={2}>A & B (Toggle)</option>
                                </select>
                            </div>
                        </div>

                        <Button 
                            fullWidth 
                            size="sm" 
                            variant={isRfDirty ? 'primary' : 'outline'}
                            className="h-9"
                            disabled={!isConnected || isScanning || !isRfDirty}
                            onClick={() => onUpdateSettings('rfParams', `${rfSpeed},${rfQv},${rfSession},${rfTarget}`)}
                        >
                            {isRfDirty ? 'APPLY CONFIGURATION' : 'CONFIGURATION SYNCED'}
                        </Button>
                    </div>
                )}
           </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { LayoutGrid, ScrollText, Database, Bluetooth, Cpu, ScanLine, Zap, Settings as SettingsIcon } from 'lucide-react';
import { bleService } from './services/bleService';
import { Controls } from './components/Controls';
import { InteractiveLog } from './components/InteractiveLog';
import { BatchResults } from './components/BatchResults';
import { WriterView } from './components/WriterView';
import { Button } from './components/ui/Button';
import { Logo } from './components/ui/Logo';
import { 
  ConnectionStatus, 
  ScanMode, 
  Tag, 
  Settings, 
  LogEntry,
  WriteStatus
} from './types';

type AppView = 'scanner' | 'writer' | 'settings';

function App() {
  // --- State ---
  const [activeView, setActiveView] = useState<AppView>('scanner');

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [scanMode, setScanMode] = useState<ScanMode>(ScanMode.INTERACTIVE);
  const [isScanning, setIsScanning] = useState(false);

  // Mobile Tabs
  const [mobileTab, setMobileTab] = useState<'controls' | 'logs' | 'results'>('controls');

  // Settings
  const [settings, setSettings] = useState<Settings>({
    power: 30,
    frequency: 'US',
    rfParams: '1,4,1,0',
    buzzer: true,
    deviceInfo: ''
  });

  // Data
  const [tags, setTags] = useState<Tag[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [selectedEpc, setSelectedEpc] = useState('');

  // File Transfer
  const [fileContent, setFileContent] = useState<string>('');
  const [isTransferring, setIsTransferring] = useState(false);
  const [transferProgress, setTransferProgress] = useState(-1);

  // Write EPC State
  const [writeStatus, setWriteStatus] = useState<WriteStatus>('idle');
  const [writeMessage, setWriteMessage] = useState('');

  // --- Refs ---
  const tagBufferRef = useRef<Map<string, Tag>>(new Map());
  const lastRenderTimeRef = useRef(0);
  const animationFrameRef = useRef<number>(0);

  // --- Helpers ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev.slice(-100), { type, message, timestamp: Date.now() }]);
  }, []);

  // --- BLE Logic (Simplified for brevity - logic remains same) ---
  const handleDataReceived = useCallback((data: any) => {
    if (data.cmd === 'live_tag' && data.epc) {
        const existing = tagBufferRef.current.get(data.epc);
        if (existing) {
            existing.count += 1;
            existing.rssi = data.rssi;
            tagBufferRef.current.set(data.epc, existing);
        } else {
            const newTag: Tag = { epc: data.epc, timestamp: Date.now(), rssi: data.rssi, count: 1 };
            tagBufferRef.current.set(data.epc, newTag);
        }
        return;
    }
    if (data.cmd === 'DI') { setSettings(prev => ({ ...prev, deviceInfo: data.val })); addLog(`Device Info: ${data.val}`, 'rx'); }
    if (data.cmd === 'GP') setSettings(prev => ({ ...prev, power: data.val }));
    if (data.cmd === 'GF') setSettings(prev => ({ ...prev, frequency: data.val }));
    if (data.cmd === 'GRP') setSettings(prev => ({ ...prev, rfParams: data.val }));
    if (data.cmd === 'BZ') setSettings(prev => ({ ...prev, buzzer: data.val === 'on' }));
    if (data.cmd === 'WE') {
      if (data.status === 'ok') { setWriteStatus('success'); setWriteMessage(`Encoded: ${data.epc}`); addLog(`Encode Success: ${data.epc}`, 'info'); } 
      else { setWriteStatus('error'); setWriteMessage('Encoding failed. Check log.'); addLog('Encode Failed.', 'error'); }
    }
  }, [addLog]);

  const handleFileEvent = useCallback((event: 'start' | 'progress' | 'complete' | 'error', data?: any) => {
    if (event === 'start') { setIsTransferring(true); setTransferProgress(0); setFileContent(''); addLog(`File transfer started...`, 'info'); } 
    else if (event === 'progress') { setTransferProgress(data); } 
    else if (event === 'complete') { setIsTransferring(false); setTransferProgress(100); setFileContent(data); addLog('Transfer complete.', 'info'); } 
    else if (event === 'error') { setIsTransferring(false); setTransferProgress(-1); addLog(`Transfer error: ${data}`, 'error'); }
  }, [addLog]);

  useEffect(() => {
    bleService.setCallbacks(handleDataReceived, (msg, type) => addLog(msg, type), handleFileEvent);
  }, [handleDataReceived, addLog, handleFileEvent]);

  useEffect(() => {
    const renderLoop = () => {
      const now = Date.now();
      if (now - lastRenderTimeRef.current > 150 && tagBufferRef.current.size > 0) {
        const allTags: Tag[] = Array.from(tagBufferRef.current.values());
        allTags.sort((a, b) => a.timestamp - b.timestamp);
        setTags(allTags.slice(0, 500));
        lastRenderTimeRef.current = now;
      }
      animationFrameRef.current = requestAnimationFrame(renderLoop);
    };
    animationFrameRef.current = requestAnimationFrame(renderLoop);
    return () => { if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current); };
  }, []);

  const handleConnect = async () => {
    try { setStatus(ConnectionStatus.CONNECTING); await bleService.connect(); setStatus(ConnectionStatus.CONNECTED); setTimeout(async () => { try { await bleService.getSettings(); } catch(e) {} }, 500); } catch (e) { setStatus(ConnectionStatus.ERROR); }
  };
  const handleDisconnect = () => { bleService.disconnect(); setStatus(ConnectionStatus.DISCONNECTED); setIsScanning(false); };
  const handleStartScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'S' : 'SB' }); setIsScanning(true); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleStopScan = async () => { if (status !== ConnectionStatus.CONNECTED) return; try { await bleService.sendCommand({ cmd: scanMode === ScanMode.INTERACTIVE ? 'X' : 'XB' }); if (scanMode === ScanMode.BATCH) setTimeout(() => bleService.requestFileTransfer(), 500); setIsScanning(false); } catch (e: any) { addLog(e.message, 'error'); } };
  const handleRequestBatchFile = async () => { if (!isTransferring) { setFileContent(''); await bleService.requestFileTransfer(); } };
  const handleUpdateSettings = async (key: keyof Settings, value: string | number | boolean) => {
    setSettings(prev => ({ ...prev, [key]: value }));
    if (status !== ConnectionStatus.CONNECTED) return;
    let cmd = {};
    if (key === 'power') cmd = { cmd: 'SP', val: value };
    if (key === 'frequency') cmd = { cmd: 'SF', val: value };
    if (key === 'rfParams') cmd = { cmd: 'SRP', val: value };
    if (key === 'buzzer') cmd = { cmd: 'BZ', val: value ? 'on' : 'off' };
    await bleService.sendCommand(cmd);
  };
  const handleWriteEpc = async (oldEpc: string, newEpc: string) => { setWriteStatus('pending'); setWriteMessage(''); try { await bleService.sendCommand({ cmd: 'WE', old: oldEpc, new: newEpc }); } catch (e: any) { setWriteStatus('error'); setWriteMessage(e.message); } };
  const handleClearLog = () => { tagBufferRef.current.clear(); setTags([]); };

  const isConnected = status === ConnectionStatus.CONNECTED;

  // --- Brand Logo Component ---
  const BrandLogo = () => (
    <div className="flex items-center gap-3 select-none">
        <Logo className="w-8 h-8" />
        <div className="flex flex-col justify-center h-full">
            <h1 className="text-2xl font-bold tracking-tight text-slate-900 leading-none font-sans">
                Next<span className="text-cyan-500">waves</span>
            </h1>
        </div>
    </div>
  );

  return (
    <div className="fixed inset-0 flex bg-ui-bg text-slate-800 font-sans">

      {/* --- DESKTOP DOCK (Left Rail) --- */}
      <nav className="hidden lg:flex flex-col w-24 bg-white border-r border-ui-border items-center py-8 z-30 shadow-sm">
         <div className="mb-12">
            <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center border border-slate-200 shadow-sm">
                <Logo className="w-8 h-8" />
            </div>
         </div>

         <div className="flex flex-col gap-6 w-full px-4">
            <button 
                onClick={() => setActiveView('scanner')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'scanner' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <LayoutGrid size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Dashboard</span>
            </button>

            <button 
                onClick={() => setActiveView('writer')}
                className={`flex flex-col items-center gap-2 p-3 rounded-xl transition-all duration-300 ${activeView === 'writer' ? 'bg-slate-100 text-cyan-600 shadow-inner' : 'text-slate-400 hover:text-slate-600 hover:bg-slate-50'}`}
            >
                <Cpu size={24} />
                <span className="text-[10px] font-semibold tracking-wide">Encoder</span>
            </button>
         </div>

         <div className="mt-auto mb-4">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.4)]' : 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.4)]'}`} title={status}></div>
         </div>
      </nav>

      {/* --- MAIN STAGE --- */}
      <div className="flex-1 flex flex-col relative overflow-hidden bg-ui-bg">

        {/* Mobile Header */}
        <div className="lg:hidden h-16 bg-white flex items-center justify-between px-4 border-b border-ui-border z-20 shadow-sm">
            <BrandLogo />
            <div className="flex items-center gap-3">
                 <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-emerald-500' : 'bg-red-500'}`} />
                 <Button size="sm" variant={isConnected ? "danger" : "primary"} onClick={isConnected ? handleDisconnect : handleConnect}>
                    <Bluetooth size={16} />
                 </Button>
            </div>
        </div>

        {/* Content Wrapper */}
        <div className="flex-1 overflow-hidden relative p-0 lg:p-6">

            {activeView === 'scanner' && (
                <div className="w-full h-full flex flex-col lg:flex-row gap-6">
                    {/* LEFT: Controls (The Dashboard) */}
                    <div className={`
                        ${mobileTab === 'controls' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[360px] shrink-0 bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft
                    `}>
                        <Controls 
                            status={status}
                            scanMode={scanMode}
                            isScanning={isScanning}
                            settings={settings}
                            onConnect={handleConnect}
                            onDisconnect={handleDisconnect}
                            onToggleMode={setScanMode}
                            onStartScan={handleStartScan}
                            onStopScan={handleStopScan}
                            onUpdateSettings={handleUpdateSettings}
                            onWriteEpc={handleWriteEpc}
                            writeLoading={writeStatus === 'pending'}
                            selectedEpc={selectedEpc}
                        />
                    </div>

                    {/* CENTER: Data Visualization */}
                    <div className={`
                        ${mobileTab === 'logs' ? 'flex' : 'hidden'} 
                        lg:flex flex-col flex-1 bg-white lg:rounded-2xl border border-ui-border overflow-hidden min-w-0 shadow-soft
                    `}>
                        <InteractiveLog 
                            tags={tags}
                            onClear={handleClearLog}
                            onSelectEpc={setSelectedEpc}
                            logs={logs}
                        />
                    </div>

                    {/* RIGHT: History/Batch (Collapsed on smaller desktops if needed) */}
                    <div className={`
                        ${mobileTab === 'results' ? 'flex' : 'hidden'} 
                        lg:flex flex-col w-full lg:w-[320px] shrink-0 bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft
                    `}>
                        <BatchResults 
                            fileContent={fileContent}
                            isTransferring={isTransferring}
                            transferProgress={transferProgress} 
                            onRequestFile={handleRequestBatchFile}
                        />
                    </div>
                </div>
            )}

            {activeView === 'writer' && (
                <div className="w-full h-full bg-white lg:rounded-2xl border border-ui-border overflow-hidden shadow-soft">
                    <WriterView 
                        onWrite={handleWriteEpc}
                        writeStatus={writeStatus}
                        writeMessage={writeMessage}
                        setWriteStatus={setWriteStatus}
                        onStartScan={handleStartScan}
                        onStopScan={handleStopScan}
                        isScanning={isScanning}
                        liveTags={tags}
                    />
                </div>
            )}

        </div>

        {/* Mobile Tab Bar */}
        {activeView === 'scanner' && (
            <div className="lg:hidden h-16 bg-white border-t border-ui-border flex justify-around items-center z-20">
                <button onClick={() => setMobileTab('controls')} className={mobileTab === 'controls' ? 'text-cyan-600' : 'text-slate-400'}>
                    <LayoutGrid />
                </button>
                <button onClick={() => setMobileTab('logs')} className={mobileTab === 'logs' ? 'text-cyan-600' : 'text-slate-400'}>
                    <ScrollText />
                </button>
                <button onClick={() => setMobileTab('results')} className={mobileTab === 'results' ? 'text-cyan-600' : 'text-slate-400'}>
                    <Database />
                </button>
            </div>
        )}

      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Bluetooth, Settings as SettingsIcon, Radio, Play, Square, Wifi, Volume2, Zap, Globe, Database, ChevronDown, ChevronUp } from 'lucide-react';
import { Button } from './ui/Button';
import { Logo } from './ui/Logo';
import { ControlsProps, ScanMode, ConnectionStatus } from '../types';

export const Controls: React.FC<ControlsProps> = ({
  status,
  scanMode,
  isScanning,
  settings,
  onConnect,
  onDisconnect,
  onToggleMode,
  onStartScan,
  onStopScan,
  onUpdateSettings
}) => {

  const [localPower, setLocalPower] = useState(settings.power);
  const [localFreq, setLocalFreq] = useState(settings.frequency);
  const [localBuzzer, setLocalBuzzer] = useState(settings.buzzer);

  // RF Params State
  const [rfSpeed, setRfSpeed] = useState(1);
  const [rfQv, setRfQv] = useState(4);
  const [rfSession, setRfSession] = useState(1);
  const [rfTarget, setRfTarget] = useState(0);

  // UI State
  const [showRfSettings, setShowRfSettings] = useState(false);

  useEffect(() => { setLocalPower(settings.power); }, [settings.power]);
  useEffect(() => { setLocalFreq(settings.frequency); }, [settings.frequency]);
  useEffect(() => { setLocalBuzzer(settings.buzzer); }, [settings.buzzer]);
  useEffect(() => {
    if (settings.rfParams) {
      const parts = settings.rfParams.split(',').map(Number);
      if (parts.length === 4) { setRfSpeed(parts[0]); setRfQv(parts[1]); setRfSession(parts[2]); setRfTarget(parts[3]); }
    }
  }, [settings.rfParams]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isPowerDirty = localPower !== settings.power;
  const isFreqDirty = localFreq !== settings.frequency;
  const isRfDirty = `${rfSpeed},${rfQv},${rfSession},${rfTarget}` !== settings.rfParams;

  return (
    <div className="flex flex-col h-full overflow-y-auto custom-scrollbar p-6 gap-8 bg-white">

      {/* 1. Header & Branding (Desktop Only - Mobile handles in App.tsx) */}
      <div className="hidden lg:block mb-2">
         <div className="flex items-center gap-3 select-none">
