          {/* Status Indicator Dot */}
          <div className={`absolute top-4 right-4 w-3 h-3 rounded-full ${isConnected ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]'}`}></div>

          <div className="flex justify-between items-start z-10 relative">
              <div className="flex flex-col">
                  <span className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">System Status</span>
                  <div className={`text-xl font-bold mt-1 tracking-wide ${isConnected ? 'text-slate-900' : 'text-slate-500'}`}>
                      {status === ConnectionStatus.CONNECTED ? 'ONLINE' : status === ConnectionStatus.CONNECTING ? 'SYNCING...' : 'OFFLINE'}
                  </div>
              </div>
              <Bluetooth className={`w-6 h-6 mr-4 ${isConnected ? 'text-blue-500' : 'text-slate-300'}`} />
          </div>

          <div className="z-10 mt-auto relative">
             {isConnected ? (
                <div className="flex items-center gap-4">
                    <div className="flex flex-col">
                         <span className="text-[9px] text-slate-400 uppercase font-bold">Battery</span>
                         <span className="text-sm font-mono text-emerald-600 font-bold">100%</span>
