import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = 'inline-flex items-center justify-center rounded-lg font-medium transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed tracking-wide shadow-sm';

  const variants = {
    // High Contrast Black for Primary action in light mode (like "Clear All")
    primary: 'bg-slate-900 text-white hover:bg-slate-800 hover:shadow-md font-semibold',
    // White surface
    secondary: 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200',
    // Alert
    danger: 'bg-red-50 text-red-600 hover:bg-red-100 border border-red-200 shadow-none',
    // Success
    success: 'bg-emerald-500 text-white hover:bg-emerald-600 font-semibold shadow-emerald-100',
    // Minimal border
    outline: 'border border-slate-300 text-slate-500 hover:border-cyan-500 hover:text-cyan-600 bg-transparent shadow-none',
    // Navigation style
    ghost: 'text-slate-500 hover:text-slate-800 hover:bg-slate-100 shadow-none'
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-5 py-2.5 text-sm',
    lg: 'px-8 py-4 text-base'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

