import React from 'react';
import { Download, FileDown, RefreshCw, Share2, FileCode } from 'lucide-react';
import { BatchResultsProps } from '../types';

export const BatchResults: React.FC<BatchResultsProps> = ({ 
  fileContent, 
  transferProgress, 
  isTransferring,
  onRequestFile
}) => {

  const handleDownload = () => {
    if (!fileContent) return;
    const blob = new Blob([fileContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scan_batch_${new Date().toISOString()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    if (!fileContent) return;
    try {
      const fileName = `scan_batch_${new Date().toISOString().slice(0, 19).replace(/:/g, '-')}.txt`;
      const file = new File([fileContent], fileName, { type: 'text/plain' });
      if (navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share({
          files: [file],
          title: 'Batch Scan Results',
          text: 'Attached RFID scan results.',
        });
      } else {
        if (navigator.share) {
             await navigator.share({
                title: 'Batch Scan Results',
                text: fileContent
             });
        } else {
             alert('Sharing is not supported on this device/browser. Please use "Save .txt"');
        }
      }
    } catch (error) {
      console.log('Share canceled or failed', error);
    }
  };

  const hasContent = !!fileContent && !isTransferring;
  const canShare = typeof navigator !== 'undefined' && !!navigator.share;

  return (
    <div className="w-full flex flex-col h-full p-4 gap-4 bg-transparent">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 pb-2 border-b border-purple-200">
        <div className="flex items-center gap-2 text-purple-600 font-bold uppercase tracking-wider">
          <FileDown className="w-5 h-5" />
          <h2>Data Export</h2>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={onRequestFile}
                disabled={isTransferring}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 hover:bg-slate-200 text-slate-600 hover:text-slate-800 rounded text-[10px] font-bold uppercase border border-slate-300 transition-colors disabled:opacity-50"
            >
                <RefreshCw className={`w-3 h-3 ${isTransferring ? 'animate-spin' : ''}`} />
                FETCH DATA
            </button>

            {hasContent && (
              <>
                <button 
                    onClick={handleDownload}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-cyan-50 hover:bg-cyan-100 text-cyan-600 hover:text-cyan-700 rounded text-[10px] font-bold uppercase border border-cyan-200 transition-colors"
                >
                    <Download className="w-3 h-3" />
                    SAVE .TXT
                </button>

                {canShare && (
                    <button 
                        onClick={handleShare}
                        className="flex items-center gap-1.5 px-3 py-1.5 bg-purple-50 hover:bg-purple-100 text-purple-600 hover:text-purple-700 rounded text-[10px] font-bold uppercase border border-purple-200 transition-colors"
                    >
                        <Share2 className="w-3 h-3" />
                        SHARE
                    </button>
                )}
              </>
            )}
        </div>
      </div>

      <div className="flex-1 bg-slate-50 rounded border border-slate-200 overflow-hidden relative flex flex-col shadow-inner">
        {isTransferring ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/80 z-10 p-8 text-center backdrop-blur-sm">
            <RefreshCw className="w-12 h-12 text-purple-500 animate-spin mb-4" />
            <h3 className="text-purple-600 font-bold uppercase tracking-widest">TRANSFERRING PACKETS...</h3>
            {transferProgress >= 0 && (
                <div className="w-48 h-1 bg-slate-200 rounded-full mt-4 overflow-hidden">
                    <div className="h-full bg-purple-500 transition-all duration-300" style={{width: `${transferProgress}%`}}></div>
                </div>
            )}
            <p className="text-slate-500 text-[10px] font-mono mt-4">DO NOT DISCONNECT DEVICE</p>
          </div>
        ) : !fileContent ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400 p-8 text-center gap-2">
            <FileCode className="w-16 h-16 opacity-30" />
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">NO DATA BUFFERED</p>
            <p className="text-[10px] max-w-xs font-mono opacity-60">Initiate BATCH SCAN mode to accumulate data logs.</p>
          </div>
        ) : (
          <div className="flex-1 overflow-auto p-4 custom-scrollbar bg-white">
            <pre className="font-mono text-[10px] text-slate-700 whitespace-pre-wrap break-all leading-relaxed shadow-none">
              {fileContent}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowRight, AlertTriangle, Radio, CheckCircle2, XCircle, Search, Binary, Database, Cpu } from 'lucide-react';
import { Button } from './ui/Button';
import { Input } from './ui/Input';
import { Tag, WriteStatus } from '../types';

interface WriterViewProps {
  onWrite: (oldEpc: string, newEpc: string) => void;
  writeStatus: WriteStatus;
  writeMessage: string;
  setWriteStatus: (status: WriteStatus) => void;
  onStartScan: () => void;
  onStopScan: () => void;
  isScanning: boolean;
  liveTags: Tag[];
}

export const WriterView: React.FC<WriterViewProps> = ({
  onWrite,
  writeStatus,
  writeMessage,
  setWriteStatus,
  onStartScan,
  onStopScan,
  isScanning,
  liveTags
}) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [targetEpc, setTargetEpc] = useState('');
  const [newEpc, setNewEpc] = useState('');
  const [error, setError] = useState('');

  const handleSelectTag = (epc: string) => {
    if (isScanning) onStopScan();
    setTargetEpc(epc);
    setNewEpc(epc); 
    setStep(2);
    setError('');
  };

  const handleBackToScan = () => {
    setStep(1);
    setTargetEpc('');
    setWriteStatus('idle');
  };

  const validateAndWrite = () => {
    const hexRegex = /^[0-9A-Fa-f]+$/;
    if (!hexRegex.test(newEpc)) {
      setError('HEX CHARACTERS ONLY (0-9, A-F)');
      return;
    }
    if (newEpc.length === 0 || newEpc.length % 4 !== 0) {
        setError(`INVALID LENGTH (MUST BE MULTIPLE OF 4). CURRENT: ${newEpc.length}`);
        return;
    }
    setError('');
    onWrite(targetEpc, newEpc);
  };

  return (
    <div className="w-full h-full flex flex-col p-4 lg:p-8 overflow-y-auto glass-panel border-none bg-transparent">
        <div className="max-w-3xl mx-auto w-full flex flex-col gap-6">

            {/* Header */}
            <div className="flex items-center gap-4 pb-4 border-b border-cyan-100">
                <div className="p-3 bg-cyan-50 rounded-lg border border-cyan-100 shadow-sm">
                    <Cpu className="w-8 h-8 text-cyan-600" />
                </div>
                <div>
                    <h1 className="text-2xl font-bold text-slate-800 tracking-wider font-sans">MEMORY ENCODER</h1>
                    <p className="text-slate-500 text-xs font-mono uppercase">Bank 1: EPC Gen2 Programmable Interface</p>
                </div>
            </div>

            {/* Warning Panel */}
            <div className="bg-amber-50 border border-amber-200 rounded p-4 flex items-start gap-4">
                <AlertTriangle className="w-6 h-6 text-amber-500 shrink-0 mt-0.5 animate-pulse" />
                <div className="space-y-1">
                    <p className="text-sm font-bold text-amber-600 uppercase tracking-wide">Proximity Alert</p>
                    <p className="text-xs text-amber-700/80 leading-relaxed font-mono">
                        ISOLATION REQUIRED. Ensure only TARGET TAG is within antenna range during write cycles.
                    </p>
                </div>
            </div>

            {/* Step 1: Scan & Select */}
            {step === 1 && (
                <div className="flex flex-col gap-4 animate-in slide-in-from-right-4 duration-300">
                    <div className="flex items-center justify-between bg-white p-4 rounded border border-slate-200 shadow-sm">
                        <div className="flex items-center gap-4">
                             <div className="flex items-center justify-center w-8 h-8 rounded bg-cyan-100 text-cyan-700 font-bold border border-cyan-200">1</div>
                             <div>
                                 <h3 className="text-slate-800 font-bold text-sm uppercase">Select Target</h3>
                                 <p className="text-[10px] text-slate-500 font-mono">Scan environment to identify target EPC.</p>
                             </div>
                        </div>
                        {isScanning ? (
                            <Button size="sm" variant="danger" onClick={onStopScan} className="min-w-[100px]">STOP SCAN</Button>
                        ) : (
                            <Button size="sm" variant="success" onClick={onStartScan} className="min-w-[100px]">START SCAN</Button>
                        )}
                    </div>

                    <div className="bg-slate-50 border border-slate-200 rounded min-h-[300px] flex-1 overflow-hidden flex flex-col relative shadow-inner">
                        {/* Grid lines overlay */}
                        <div className="absolute inset-0 bg-[url('data:image/svg+xml;base64,PHN2ZyB3aWR0aD0iMjAiIGhlaWdodD0iMjAiIHhtbG5zPSJodHRwOi8vd3d3LnczLm9yZy8yMDAwL3N2ZyI+PGNpcmNsZSBjeD0iMSIgY3k9IjEiIHI9IjEiIGZpbGw9InJnYmEoMCwwLDAsMC4wNSkiLz48L3N2Zz4=')] pointer-events-none"></div>

                        <div className="bg-white px-4 py-2 border-b border-slate-200 text-xs font-bold text-cyan-600 flex justify-between uppercase tracking-wider">
                            <span>Detected Signals</span>
                            <span>{liveTags.length} UNITS</span>
                        </div>
                        <div className="flex-1 overflow-y-auto relative custom-scrollbar z-10">
                            {liveTags.length === 0 ? (
                                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400 gap-4">
                                    <div className="relative">
                                        <div className={`absolute inset-0 bg-cyan-400 blur-xl opacity-20 rounded-full ${isScanning ? 'animate-pulse' : 'hidden'}`}></div>
                                        <Radio className={`w-12 h-12 ${isScanning ? 'text-cyan-600' : 'text-slate-300'}`} />
                                    </div>
                                    <p className="text-xs font-mono uppercase tracking-widest">{isScanning ? 'SCANNING FREQUENCIES...' : 'SYSTEM IDLE'}</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-slate-200">
                                    {liveTags.map((tag, idx) => (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectTag(tag.epc)}
                                            className="w-full flex items-center justify-between p-4 hover:bg-cyan-50 transition-all group text-left border-l-2 border-transparent hover:border-cyan-500"
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className="w-2 h-2 rounded-full bg-cyan-500 shadow-[0_0_5px_rgba(6,182,212,0.6)]" />
                                                <div>
                                                    <p className="font-mono text-slate-800 font-medium group-hover:text-cyan-800 transition-colors text-base">{tag.epc}</p>
                                                    <p className="text-[10px] text-slate-500 mt-1 font-mono">RSSI: {tag.rssi} dBm</p>
                                                </div>
                                            </div>
                                            <div className="opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0 duration-300">
