                                            </div>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* Step 2: Write */}
            {step === 2 && (
                <div className="flex flex-col gap-6 animate-in slide-in-from-right-4 duration-300">
                     <div className="flex items-center gap-4">
                         <div className="flex items-center justify-center w-8 h-8 rounded bg-cyan-100 text-cyan-700 font-bold border border-cyan-200">2</div>
                         <h3 className="text-slate-800 font-bold text-sm uppercase">Program Data</h3>
                     </div>

                     <div className="bg-white border border-slate-200 rounded p-6 space-y-8 shadow-sm">

                         <div className="grid gap-6">
                            <div className="space-y-2">
                                <label className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">Target Identifier</label>
                                <div className="bg-slate-50 border border-slate-200 rounded p-4 flex items-center gap-3">
                                    <Database className="w-5 h-5 text-slate-400" />
                                    <span className="font-mono text-slate-600 text-lg tracking-widest">{targetEpc}</span>
                                </div>
                            </div>

                            <div className="flex justify-center">
                                <div className="bg-slate-100 p-2 rounded-full border border-slate-200">
                                    <ArrowRight className="w-5 h-5 text-cyan-500 animate-pulse" />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-[10px] text-cyan-600 uppercase font-bold tracking-widest">New Payload (Hex)</label>
                                <Input 
                                    value={newEpc}
                                    onChange={(e) => {
                                        setNewEpc(e.target.value.toUpperCase());
                                        setError('');
                                    }}
                                    error={error}
                                    className="font-mono text-lg py-4 border-slate-200 bg-white focus:border-cyan-500 text-center tracking-widest text-slate-800 shadow-inner"
                                    placeholder="0000..."
                                    disabled={writeStatus === 'pending' || writeStatus === 'success'}
                                    autoFocus
                                />
                                <div className="flex justify-between text-[10px] text-slate-400 px-1 font-mono">
                                    <span>LEN: {newEpc.length} CHARS</span>
                                    <span>SIZE: {newEpc.length * 4} BITS</span>
                                </div>
                            </div>
                         </div>

                         {/* Actions */}
                         <div className="flex items-center gap-4 pt-4 border-t border-slate-100">
                            <Button variant="outline" onClick={handleBackToScan} disabled={writeStatus === 'pending'} size="lg">
                                CANCEL
                            </Button>

                            {writeStatus !== 'success' && (
                                <Button 
                                    variant="primary" 
                                    onClick={validateAndWrite} 
                                    disabled={writeStatus === 'pending'}
                                    size="lg"
                                    className="flex-1 shadow-md shadow-cyan-100"
                                >
                                    {writeStatus === 'pending' ? 'PROGRAMMING...' : 'EXECUTE WRITE'}
                                </Button>
                            )}
                         </div>

                         {/* Status Messages */}
                         {writeStatus === 'success' && (
                             <div className="bg-emerald-50 border border-emerald-200 rounded p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300">
                                 <CheckCircle2 className="w-8 h-8 text-emerald-500" />
                                 <div className="flex-1">
                                     <p className="font-bold text-emerald-600 uppercase tracking-wide">Write Successful</p>
                                     <p className="text-xs text-emerald-700/70 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                                 <Button variant="outline" size="sm" onClick={handleBackToScan} className="border-emerald-200 text-emerald-600 hover:bg-emerald-50">
                                     NEW TASK
                                 </Button>
                             </div>
                         )}

                         {writeStatus === 'error' && (
                             <div className="bg-red-50 border border-red-200 rounded p-4 flex items-center gap-4 animate-in fade-in zoom-in duration-300">
                                 <XCircle className="w-8 h-8 text-red-500" />
                                 <div>
                                     <p className="font-bold text-red-600 uppercase tracking-wide">Write Failed</p>
                                     <p className="text-xs text-red-700/70 mt-1 font-mono">{writeMessage}</p>
                                 </div>
                             </div>
                         )}
                     </div>
                </div>
            )}
        </div>
    </div>
  );
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  // Update: rounded-full for pill shape, softer shadows
  const baseStyles = 'inline-flex items-center justify-center rounded-full font-medium transition-all duration-300 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed tracking-wide';

  const variants = {
    // Solid Black/Dark Slate - High contrast
    primary: 'bg-slate-900 text-white hover:bg-slate-800 shadow-lg shadow-slate-200 hover:shadow-xl hover:-translate-y-0.5',
    // White with border
    secondary: 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200 shadow-sm',
    // Alert/Destructive
    danger: 'bg-red-50 text-red-600 hover:bg-red-100 border border-red-100 shadow-sm',
    // Positive Action
    success: 'bg-emerald-500 text-white hover:bg-emerald-600 shadow-lg shadow-emerald-100 hover:shadow-xl hover:-translate-y-0.5',
    // Ghost/Outline
    outline: 'border border-slate-300 text-slate-500 hover:border-cyan-500 hover:text-cyan-600 bg-transparent',
    // Plain text
    ghost: 'text-slate-500 hover:text-slate-900 hover:bg-slate-100'
  };

  const sizes = {
    sm: 'px-4 py-1.5 text-xs',
    md: 'px-6 py-2.5 text-sm',
    lg: 'px-8 py-4 text-base font-semibold'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

